export const mockDb = {
  // --- AUTH ---
  login: async (email?: string): Promise<User | null> => {
    if (!email) return null;
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('profiles').select('*').eq('email', email).maybeSingle();
        if (error) throw error;
        return data ? mapProfileToUser(data) : null;
    }, null, "Fetch Profile");
  },

  signIn: async (email: string, password: string): Promise<User | null> => {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
    if (data.user) return await mockDb.login(data.user.email!);
    return null;
  },

  registerUser: async (u: any): Promise<User> => {
    const { data: authData, error: authError } = await supabase.auth.signUp({
        email: u.email,
        password: u.password,
    });
    if (authError) throw authError;
    if (!authData.user) throw new Error("Erro ao criar credenciais.");

    const { data, error } = await supabase.from('profiles').insert({
        id: authData.user.id,
        email: u.email,
        name: u.name,
        role: u.role,
        document: u.document,
        phone: u.phone,
        address: u.address,
        status: u.role === 'patient' ? 'active' : 'pending',
        specialty: u.specialty,
        reg: u.reg,
        available_services: u.availableServices || []
    }).select().single();

    if (error) throw error;
    return mapProfileToUser(data);
  },

  // --- CLINICS & SEARCH ---
  getClinics: async (): Promise<Clinic[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('profiles')
            .select('*')
            .in('role', ['clinic', 'professional'])
            .eq('status', 'active');
        if (error) throw error;
        return ensureArray(data).map(p => ({
            id: p.id,
            name: p.name,
            specialty: p.specialty || 'Especialista',
            location: 'Salvador-BA',
            neighborhood: p.address || 'Centro',
            price: p.price || 'A consultar',
            imageUrl: p.avatar_url,
            rating: p.rating || 5.0,
            reviewCount: p.review_count || 0,
            testimonial: p.bio,
            availableServices: ensureArray(p.available_services)
        }));
    }, [], "Get Clinics");
  },

  getFavorites: async (uid: string): Promise<Clinic[]> => {
    return await safeExecute(async () => {
        const { data: p } = await supabase.from('profiles').select('favorites').eq('id', uid).single();
        const favIds = ensureArray(p?.favorites);
        if (favIds.length === 0) return [];
        const { data, error } = await supabase.from('profiles').select('*').in('id', favIds);
        if (error) throw error;
        return ensureArray(data).map(p => ({
            id: p.id, name: p.name, specialty: p.specialty || 'Especialista',
            location: 'Salvador-BA', neighborhood: p.address || 'Centro',
            price: p.price || 'A consultar', imageUrl: p.avatar_url,
            rating: p.rating || 5.0, reviewCount: p.review_count || 0,
            testimonial: p.bio, availableServices: ensureArray(p.available_services)
        }));
    }, [], "Get Favorites");
  },

  toggleFavorite: async (uid: string, cid: string) => {
    const { data: p } = await supabase.from('profiles').select('favorites').eq('id', uid).single();
    let favs = ensureArray(p?.favorites);
    favs = favs.includes(cid) ? favs.filter((id: any) => id !== cid) : [...favs, cid];
    const { data, error } = await supabase.from('profiles').update({ favorites: favs }).eq('id', uid).select().single();
    if (error) throw error;
    return mapProfileToUser(data);
  },

  submitReview: async (cid: string, rating: number, comment: string) => {
    // Lógica simplificada: em produção isso incrementaria ratings e review_count via RPC ou Trigger
    console.log(`[Marclyn Review] Submitting ${rating} stars for clinic ${cid}`);
    return true;
  },

  // --- APPOINTMENTS ---
  getAppointments: async (userId: string, role: UserRole): Promise<Appointment[]> => {
    const col = role === 'patient' ? 'patient_id' : 'clinic_id';
    return await safeExecute(async () => {
        const { data, error } = await supabase
          .from('appointments')
          .select('*, patient:profiles!patient_id(name), clinic:profiles!clinic_id(name)')
          .eq(col, userId)
          .order('date', { ascending: true });
        if (error) throw error;
        return ensureArray(data).map(app => ({
          id: app.id, patientId: app.patient_id, patientName: app.patient?.name || 'Paciente',
          clinicId: app.clinic_id, doctorName: app.doctor_name, date: app.date,
          status: app.status, type: app.type, meetingUrl: app.meeting_url, roomId: app.room_id || app.id
        }));
    }, [], "Get Appointments");
  },

  createAppointment: async (app: Partial<Appointment>) => {
    const { data, error } = await supabase.from('appointments').insert({
      patient_id: app.patientId, clinic_id: app.clinicId, doctor_name: app.doctorName,
      date: app.date, type: app.type, status: 'scheduled', notes: app.notes,
      room_id: Math.random().toString(36).substring(7)
    }).select().single();
    if (error) throw error;
    return data;
  },

  updateAppointmentStatus: async (id: string, status: string) => {
    const { error } = await supabase.from('appointments').update({ status }).eq('id', id);
    if (error) throw error;
  },

  updateAppointmentLink: async (id: string, url: string) => {
    const { error } = await supabase.from('appointments').update({ meeting_url: url }).eq('id', id);
    if (error) throw error;
  },

  getAppointmentById: async (id: string): Promise<Appointment | null> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('appointments')
            .select('*, patient:profiles!patient_id(name), clinic:profiles!clinic_id(name)')
            .eq('id', id).maybeSingle();
        if (error || !data) return null;
        return {
          id: data.id, patientId: data.patient_id, patientName: data.patient?.name,
          clinicId: data.clinic_id, doctorName: data.doctor_name, date: data.date,
          status: data.status, type: data.type, meetingUrl: data.meeting_url, roomId: data.room_id || data.id
        };
    }, null, "Get Appoint By ID");
  },

  // --- RECORDS ---
  getRecords: async (uid: string, role: UserRole): Promise<MedicalRecord[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('medical_records').select('*')
            .or(`patient_id.eq.${uid},professional_id.eq.${uid}`)
            .order('date', { ascending: false });
        if (error) throw error;
        return ensureArray(data).map(r => ({
          id: r.id, patientId: r.patient_id, professionalId: r.professional_id,
          date: r.date, diagnosis: r.diagnosis, prescription: r.prescription,
          doctorName: r.doctor_name, type: r.type as any, title: r.title,
          cid: r.cid, days: r.days, fileUrl: r.file_url
        }));
    }, [], "Get Records");
  },

  createMedicalRecord: async (r: Partial<MedicalRecord>, file?: File) => {
    let fileUrl = '';
    if (file) {
        // Mock de upload: em produção usaria supabase.storage
        fileUrl = URL.createObjectURL(file);
    }
    const { data, error } = await supabase.from('medical_records').insert({
        patient_id: r.patientId, professional_id: r.professionalId,
        date: r.date, diagnosis: r.diagnosis, prescription: r.prescription,
        doctor_name: r.doctorName, type: r.type, cid: r.cid, days: r.days,
        title: r.title, file_url: fileUrl
    }).select().single();
    if (error) throw error;
    return data;
  },

  // --- SLOTS & SCHEDULE ---
  getAvailableSlots: async (cid: string): Promise<TimeSlot[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('time_slots').select('*').eq('clinic_id', cid).eq('is_booked', false).order('date');
        if (error) throw error;
        return ensureArray(data).map(s => ({ id: s.id, clinicId: s.clinic_id, date: s.date, time: s.time, isBooked: s.is_booked }));
    }, [], "Get Available Slots");
  },

  getAllSlotsForClinic: async (cid: string): Promise<TimeSlot[]> => {
    const { data, error } = await supabase.from('time_slots').select('*').eq('clinic_id', cid).order('date');
    if (error) throw error;
    return ensureArray(data).map(s => ({ id: s.id, clinicId: s.clinic_id, date: s.date, time: s.time, isBooked: s.is_booked }));
  },

  createTimeSlot: async (cid: string, date: string, time: string) => {
    const { error } = await supabase.from('time_slots').insert({ clinic_id: cid, date, time, is_booked: false });
    if (error) throw error;
  },

  createTimeSlotsBatch: async (cid: string, slots: {date: string, time: string}[]) => {
    const payload = slots.map(s => ({ clinic_id: cid, date: s.date, time: s.time, is_booked: false }));
    const { data, error } = await supabase.from('time_slots').insert(payload).select();
    if (error) throw error;
    return ensureArray(data).length;
  },

  deleteTimeSlot: async (id: string) => {
    const { error } = await supabase.from('time_slots').delete().eq('id', id);
    if (error) throw error;
  },

  // --- ADMIN & STATS ---
  getAllClinicsForAdmin: async (): Promise<User[]> => {
    const { data, error } = await supabase.from('profiles').select('*').in('role', ['clinic', 'professional']).order('created_at', { ascending: false });
    if (error) throw error;
    return ensureArray(data).map(mapProfileToUser);
  },

  getPendingUsers: async (): Promise<User[]> => {
    const { data, error } = await supabase.from('profiles').select('*').eq('status', 'pending');
    if (error) throw error;
    return ensureArray(data).map(mapProfileToUser);
  },

  updateUserStatus: async (uid: string, status: string) => {
    const { error } = await supabase.from('profiles').update({ status }).eq('id', uid);
    if (error) throw error;
  },

  getStats: async () => {
    return await safeExecute(async () => {
        const { count: users } = await supabase.from('profiles').select('*', { count: 'exact', head: true });
        const { count: pending } = await supabase.from('profiles').select('*', { count: 'exact', head: true }).eq('status', 'pending');
        const { count: apps } = await supabase.from('appointments').select('*', { count: 'exact', head: true });
        return { users: users || 0, clinics: 0, appointments: apps || 0, records: 0, pendingUsers: pending || 0 };
    }, { users: 0, clinics: 0, appointments: 0, records: 0, pendingUsers: 0 }, "Get Stats");
  },

  getClinicFinancials: async (cid: string) => {
    const { data, error } = await supabase.from('appointments').select('*').eq('clinic_id', cid).eq('status', 'done');
    if (error) throw error;
    const total = ensureArray(data).length * 150;
    return { totalRevenue: total, chartData: [{ day: 'HOJE', value: total }] };
  },

  getNotifications: async (uid: string): Promise<Notification[]> => {
    const { data, error } = await supabase.from('notifications').select('*').eq('user_id', uid).order('created_at', { ascending: false });
    if (error) throw error;
    return ensureArray(data).map(n => ({ id: n.id, userId: n.user_id, message: n.message, read: n.read, createdAt: n.created_at, link: n.link, type: n.type as any }));
  },

  markNotificationAsRead: async (id: string) => {
    await supabase.from('notifications').update({ read: true }).eq('id', id);
  },

  updateProfile: async (uid: string, up: Partial<User>, file?: File | null) => {
    let avatarUrl = up.avatarUrl;
    if (file) {
      avatarUrl = await new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(file);
      });
    }
    const { data, error } = await supabase.from('profiles').update({
      name: up.name, phone: up.phone, address: up.address, bio: up.bio, price: up.price,
      operating_hours: up.operatingHours, website: up.website, specialty: up.specialty,
      reg: up.reg, document: up.document, available_services: up.availableServices,
      health_plan: up.healthPlan, emergency_contact: up.emergencyContact, medical_history: up.medicalHistory,
      avatar_url: avatarUrl
    }).eq('id', uid).select().single();
    if (error) throw error;
    return mapProfileToUser(data);
  },

  getAuditLogs: async (): Promise<AuditLog[]> => {
    const { data, error } = await supabase.from('audit_logs').select('*').order('created_at', { ascending: false }).limit(50);
    if (error) return [];
    return ensureArray(data).map(l => ({ id: l.id, action: l.action, userId: l.user_id, details: l.details, timestamp: l.created_at }));
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Search, Calendar, Stethoscope, X, ChevronRight, Video, TestTube, LayoutDashboard, HeartPulse } from 'lucide-react';
import { Clinic, User } from '../types';
import { mockDb } from '../lib/mockSupabase';
import QuickAccessCard from '../components/QuickAccessCard';
import ServiceCard from '../components/ServiceCard';
import AppointmentForm from '../components/forms/AppointmentForm';

interface HomeProps {
  user: User | null;
  onNavigate: (path: string) => void;
  showToast?: (msg: string, type?: 'success' | 'error') => void;
}

const Home: React.FC<HomeProps> = ({ user, onNavigate, showToast }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [allClinics, setAllClinics] = useState<Clinic[]>([]);
  const [loading, setLoading] = useState(true);

  const [suggestions, setSuggestions] = useState<Clinic[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const searchContainerRef = useRef<HTMLDivElement>(null);

  const [showBookingModal, setShowBookingModal] = useState(false);
  const [selectedClinic, setSelectedClinic] = useState<Clinic | null>(null);

  useEffect(() => {
    const loadClinics = async () => {
      setLoading(true);
      try {
        const data = await mockDb.getClinics();
        setAllClinics(Array.isArray(data) ? data : []);
      } catch (err) {
        console.error("Home Load Error:", err);
        setAllClinics([]);
      } finally {
        setLoading(false);
      }
    };
    loadClinics();
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (searchContainerRef.current && !searchContainerRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const normalize = (text: string) => {
    return (text || '')
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "");
  };

  const getMatches = (clinics: Clinic[], term: string) => {
    if (!term || !Array.isArray(clinics)) return [];
    const normalizedTerm = normalize(term);
    const searchTokens = normalizedTerm.split(/\s+/).filter(t => t.length > 0);

    return clinics.filter(clinic => {
      const clinicString = normalize(`${clinic.name || ''} ${clinic.specialty || ''} ${clinic.neighborhood || ''} ${clinic.location || ''}`);
      return searchTokens.every(token => clinicString.includes(token));
    });
  };

  const filteredClinics = Array.isArray(allClinics) && searchTerm 
    ? getMatches(allClinics, searchTerm)
    : allClinics;

  const handleSearchChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setSearchTerm(value);
    if (value.length >= 2) {
      const matches = getMatches(allClinics, value);
      setSuggestions(matches);
      setShowSuggestions(true);
    } else {
      setShowSuggestions(false);
    }
  };

  const handleSelectSuggestion = (clinic: Clinic) => {
    setSearchTerm(clinic.name);
    setShowSuggestions(false);
    onNavigate(`/professional/${clinic.id}`);
  };

  const clearSearch = () => {
    setSearchTerm('');
    setShowSuggestions(false);
  };

  const handleBooking = (clinic: Clinic) => {
    if (!user) {
      if(showToast) showToast('Por favor, faça login ou cadastre-se para agendar.', 'error');
      onNavigate('/login');
      return;
    }
    setSelectedClinic(clinic);
    setShowBookingModal(true);
  };

  const handleBookingSuccess = () => {
    setShowBookingModal(false);
    setSelectedClinic(null);
    onNavigate('/dashboard');
  };

  const services = [
    { id: 'teleconsulta', title: 'Marcar Teleconsulta', icon: <Video size={20} /> },
    { id: 'presencial', title: 'Marcar Consulta', icon: <Stethoscope size={20} />, desc: 'Presencial' },
    { id: 'exames', title: 'Marcar Exames', icon: <TestTube size={20} /> },
    { id: 'agendamentos', title: 'Meus Agendamentos', icon: <Calendar size={20} /> },
  ];

  const getDashboardCardContent = () => {
    if (!user) return { title: 'Acessar Painel do Paciente', desc: 'Ver prontuário, receitas e agendamentos.' };
    if (user.role === 'admin') return { title: 'Painel Administrativo', desc: 'Gestão completa do sistema.' };
    if (user.role === 'clinic') return { title: 'Painel da Clínica', desc: 'Gerencie pacientes e agenda.' };
    if (user.role === 'professional') return { title: 'Painel do Profissional', desc: 'Gerencie sua agenda e atendimentos.' };
    return { title: 'Minha Saúde', desc: 'Ver prontuário, receitas e resultados.' };
  };

  const dashboardInfo = getDashboardCardContent();

  return (
    <div className="bg-[#eef5f6] min-h-screen relative pb-12">
      {showBookingModal && user && (
        <div className="fixed inset-0 z-[60] bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="w-full max-w-lg">
            <AppointmentForm 
              clinics={allClinics}
              patientId={user.id}
              preSelectedClinicId={selectedClinic?.id}
              onSuccess={handleBookingSuccess}
              onCancel={() => {
                setShowBookingModal(false);
                setSelectedClinic(null);
              }}
              showToast={showToast}
            />
          </div>
        </div>
      )}

      <div className="absolute top-0 left-0 w-full h-[340px] bg-[#4d8688] rounded-b-[3rem] z-0 shadow-xl"></div>

      <div className="relative z-30 pt-6 px-4 max-w-2xl mx-auto" ref={searchContainerRef}>
        <div className="relative">
          <input
            type="text"
            placeholder="BUSCAR SERVIÇOS, ESPECIALIDADE, BAIRRO..."
            className="w-full pl-10 pr-10 py-4 rounded-full text-sm font-bold text-white shadow-xl focus:outline-none focus:ring-4 focus:ring-teal-300/50 uppercase placeholder:text-slate-300 transition-all bg-slate-900/60 backdrop-blur-md border border-white/10"
            value={searchTerm}
            onChange={handleSearchChange}
          />
          <Search className="absolute left-4 top-4 text-slate-300" size={20} />
          {searchTerm && (
            <button onClick={clearSearch} className="absolute right-4 top-4 text-slate-300 hover:text-white p-0.5 rounded-full hover:bg-white/10">
              <X size={16} />
            </button>
          )}
        </div>

        {showSuggestions && suggestions.length > 0 && (
          <div className="absolute top-full left-4 right-4 mt-2 bg-white rounded-xl shadow-2xl overflow-hidden border border-slate-100 animate-slideUp">
            <ul className="divide-y divide-slate-50 max-h-64 overflow-y-auto">
              {suggestions.map(suggestion => (
                <li key={suggestion.id} onClick={() => handleSelectSuggestion(suggestion)} className="p-3 hover:bg-teal-50 cursor-pointer flex items-center justify-between group">
                  <div className="flex items-center gap-3">
                    <div className="bg-slate-100 p-2 rounded-lg text-slate-500 group-hover:bg-white group-hover:text-teal-600">
                      <Stethoscope size={16}/>
                    </div>
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-700 text-sm">{suggestion.name}</span>
                      <div className="flex items-center gap-2 text-xs text-slate-400">
                        <span>{suggestion.specialty}</span>
                        <span>•</span>
                        <span>{suggestion.neighborhood}</span>
                      </div>
                    </div>
                  </div>
                  <ChevronRight size={16} className="text-slate-300 group-hover:text-teal-600" />
                </li>
              ))}
            </ul>
          </div>
        )}
      </div>

      <div className="relative z-30 mt-8 px-4 max-w-5xl mx-auto">
        <div className="mb-10">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3 md:gap-4">
             {services.map(s => (
               <QuickAccessCard 
                 key={s.id} 
                 title={s.title} 
                 icon={s.icon} 
                 description={s.desc} 
                 onClick={() => onNavigate(s.id === 'agendamentos' ? (user ? '/dashboard' : '/login') : `/search?type=${s.id}`)} 
               />
             ))}
          </div>
        </div>

        <div className="mb-12">
            <QuickAccessCard 
                title={dashboardInfo.title}
                description={dashboardInfo.desc}
                icon={<LayoutDashboard size={20}/>}
                onClick={() => onNavigate(user ? '/dashboard' : '/login')}
            />
        </div>

        <div>
            <div className="flex items-center justify-between mb-6">
                <h2 className="text-xl font-black text-slate-800 uppercase tracking-tight flex items-center gap-2">
                    <HeartPulse className="text-teal-600" /> Clínicas e Profissionais
                </h2>
                <button onClick={() => onNavigate('/search')} className="text-teal-600 font-bold text-xs uppercase hover:underline">Ver Todos</button>
            </div>

            {loading ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {[1,2,3].map(i => (
                        <div key={i} className="bg-white rounded-[2.5rem] h-[450px] animate-pulse border border-slate-100"></div>
                    ))}
                </div>
            ) : filteredClinics.length > 0 ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {filteredClinics.slice(0, 6).map(clinic => (
                        <ServiceCard 
                          key={clinic.id} 
                          clinic={clinic} 
                          user={user} 
                          onBook={handleBooking} 
                          onNavigate={onNavigate} 
                          showToast={showToast} 
                        />
                    ))}
                </div>
            ) : (
                <div className="bg-white p-12 rounded-[2.5rem] text-center border border-dashed border-slate-200">
                    <p className="text-slate-400 font-bold uppercase text-sm">Nenhum resultado para "{searchTerm}"</p>
                    <button onClick={clearSearch} className="mt-4 text-teal-600 font-black uppercase text-xs">Limpar Busca</button>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

export default Home;

import { supabase } from './supabaseClient';
import { Appointment, Clinic, MedicalRecord, User, UserRole, AuditLog, TimeSlot, Notification } from '../types';

/**
 * MARCLYN DATA ADAPTER - PRODUCTION GRADE v4.0
 * Camada de resiliência ultra-robusta com tratamento de erros e métodos completos.
 */

const MAX_RETRIES = 2;
const TIMEOUT_MS = 10000;

const safeExecute = async <T>(operation: () => Promise<T>, fallback: T, label = "Operation"): Promise<T> => {
    let lastError: any;
    for (let i = 0; i <= MAX_RETRIES; i++) {
        try {
            const timeoutPromise = new Promise<T>((_, reject) => 
                setTimeout(() => reject(new Error(`${label} Timeout`)), TIMEOUT_MS)
            );
            return await Promise.race([operation(), timeoutPromise]);
        } catch (error) {
            lastError = error;
            console.warn(`[Marclyn Data] Tentativa ${i + 1}/${MAX_RETRIES + 1} falhou (${label}):`, error);
            if (i < MAX_RETRIES) await new Promise(r => setTimeout(r, 1000 * (i + 1)));
        }
    }
    console.error(`[Marclyn Data] Erro persistente em ${label}.`, lastError);
    return fallback;
};

const ensureArray = <T>(data: any): T[] => Array.isArray(data) ? data : [];

const mapProfileToUser = (p: any): User => ({
  id: p?.id || '',
  email: p?.email || '',
  name: p?.name || 'Usuário Marclyn',
