const MAX_RETRIES = 2;
const TIMEOUT_MS = 12000;

/**
 * Executa uma operação com timeout e retries, sem nunca disparar erros que quebrem o app.
 */
const safeExecute = async <T>(operation: () => Promise<T>, fallback: T, label = "Op"): Promise<T> => {
    let lastError: any;
    for (let i = 0; i <= MAX_RETRIES; i++) {
        try {
            const timeoutPromise = new Promise<T>((_, reject) => 
                setTimeout(() => reject(new Error(`${label} Timeout`)), TIMEOUT_MS)
            );
            return await Promise.race([operation(), timeoutPromise]);
        } catch (error) {
            lastError = error;
            console.warn(`[Marclyn Data] Tentativa ${i + 1}/${MAX_RETRIES + 1} falhou para ${label}`);
            if (i < MAX_RETRIES) await new Promise(r => setTimeout(r, 1500 * (i + 1)));
        }
    }
    console.error(`[Marclyn Data Critical] ${label} falhou definitivamente. Usando fallback.`, lastError);
    return fallback;
};

