            reviewCount: p.review_count || 0,
            testimonial: p.bio,
            about: p.about,
            availableServices: ensureArray(p.available_services)
        }));
    }, [], "Get Clinics");
  },

  updateProfile: async (uid: string, up: Partial<User>, file?: File | null) => {
    let avatarUrl = up.avatarUrl;
    if (file) {
      avatarUrl = await new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(file);
      });
    }
    const { data, error } = await supabase.from('profiles').update({
      name: up.name, 
      phone: up.phone, 
      address: up.address,
      neighborhood: up.neighborhood,
      city: up.city,
      bio: up.bio, 
      about: up.about,
      price: up.price,
      operating_hours: up.operatingHours, 
      website: up.website, 
      specialty: up.specialty,
      reg: up.reg, 
      document: up.document, 
      available_services: up.availableServices,
      health_plan: up.healthPlan, 
      emergency_contact: up.emergencyContact, 
      medical_history: up.medicalHistory,
      avatar_url: avatarUrl
    }).eq('id', uid).select().single();

    if (error) throw error;
    return mapProfileToUser(data);
  },

  getAppointments: async (userId: string, role: UserRole): Promise<Appointment[]> => {
    const col = role === 'patient' ? 'patient_id' : 'clinic_id';
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('appointments').select('*, patient:profiles!patient_id(name), clinic:profiles!clinic_id(name)')
          .eq(col, userId).order('date', { ascending: true });
        if (error) throw error;
        return ensureArray<any>(data).map(app => ({
          id: app.id, patientId: app.patient_id, patientName: app.patient?.name || 'Paciente', clinicId: app.clinic_id,
          doctorName: app.doctor_name, date: app.date, status: app.status, type: app.type, meetingUrl: app.meeting_url, roomId: app.room_id || app.id
        }));
