import { supabase } from './supabaseClient';
import { Appointment, Clinic, MedicalRecord, User, UserRole, AuditLog, TimeSlot, Notification } from '../types';

/**
 * DATA ADAPTER v5.4 (DEBUGGING & FORCE SYNC)
 */

const MAX_RETRIES = 2;
const TIMEOUT_MS = 12000;

const safeExecute = async <T>(operation: () => Promise<T>, fallback: T, label = "Op"): Promise<T> => {
    let lastError: any;
    for (let i = 0; i <= MAX_RETRIES; i++) {
        try {
            const timeoutPromise = new Promise<T>((_, reject) => 
                setTimeout(() => reject(new Error(`${label} Timeout`)), TIMEOUT_MS)
            );
            return await Promise.race([operation(), timeoutPromise]);
        } catch (error) {
            lastError = error;
            console.error(`[MockDB ${label}] Erro na tentativa ${i + 1}:`, error);
            if (i < MAX_RETRIES) await new Promise(r => setTimeout(r, 1000 * (i + 1)));
        }
    }
    throw lastError || new Error(`Erro persistente em ${label}`);
};

const ensureArray = <T>(data: any): T[] => Array.isArray(data) ? data : [];

const mapProfileToUser = (p: any): User => ({
  id: p?.id || '',
  email: p?.email || '',
  name: p?.name || 'Usuário Marclyn',
  role: (p?.role as UserRole) || 'patient',
  status: p?.status || 'active',
  avatarUrl: p?.avatar_url,
  phone: p?.phone,
  address: p?.address,
  neighborhood: p?.neighborhood,
  city: p?.city || 'Salvador',
  document: p?.document,
  specialty: p?.specialty,
  price: p?.price,
  bio: p?.bio,
  about: p?.about,
  reg: p?.reg,
  operatingHours: p?.operating_hours,
  website: p?.website,
  availableServices: ensureArray(p?.available_services),
  favorites: ensureArray(p?.favorites),
  healthPlan: p?.health_plan,
  medicalHistory: p?.medical_history,
  emergencyContact: p?.emergency_contact,
  yampiUrl: p?.yampi_url
});

export const mockDb = {
  login: async (email?: string): Promise<User | null> => {
    if (!email) return null;
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('profiles').select('*').eq('email', email).maybeSingle();
        if (error) throw error;
        return data ? mapProfileToUser(data) : null;
    }, null, "Fetch Profile");
  },

  signIn: async (email: string, password: string): Promise<User | null> => {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
    if (data.user) return await mockDb.login(data.user.email!);
    return null;
  },

  registerUser: async (u: any): Promise<User> => {
    const { data: authData, error: authError } = await supabase.auth.signUp({
      email: u.email,
      password: u.password,
    });
    if (authError) throw authError;
    if (!authData.user) throw new Error("Auth user creation failed");

    const { data: profData, error: profError } = await supabase.from('profiles').insert({
      id: authData.user.id,
      email: u.email,
      name: u.name,
      role: u.role,
      status: u.role === 'patient' ? 'active' : 'pending',
      document: u.document,
      phone: u.phone,
      address: u.address,
      website: u.website,
      bio: u.bio,
      reg: u.reg,
      specialty: u.specialty,
      available_services: u.availableServices || []
    }).select().single();

    if (profError) throw profError;
    return mapProfileToUser(profData);
  },

  getClinics: async (): Promise<Clinic[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('profiles')
            .select('*')
            .in('role', ['clinic', 'professional'])
            .eq('status', 'active');
        if (error) throw error;
        return ensureArray<any>(data).map(p => ({
            id: p.id,
            name: p.name,
            specialty: p.specialty || 'Especialista',
            location: p.city || 'Salvador-BA',
            neighborhood: p.neighborhood || p.address || 'Centro',
            price: p.price || 'A consultar',
            imageUrl: p.avatar_url,
            rating: p.rating || 5.0,
            reviewCount: p.review_count || 0,
            testimonial: p.bio,
            about: p.about,
            availableServices: ensureArray(p.available_services)
        }));
    }, [], "Get Clinics");
  },

  updateProfile: async (uid: string, up: Partial<User>, file?: File | null) => {
    let avatarUrl = up.avatarUrl;
    if (file) {
      avatarUrl = await new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(file);
      });
    }
    const { data, error } = await supabase.from('profiles').update({
      name: up.name, 
      phone: up.phone, 
      address: up.address,
      neighborhood: up.neighborhood,
      city: up.city,
      bio: up.bio, 
      about: up.about,
      price: up.price,
      operating_hours: up.operatingHours, 
      website: up.website, 
      specialty: up.specialty,
      reg: up.reg, 
      document: up.document, 
      available_services: up.availableServices,
      health_plan: up.healthPlan, 
      emergency_contact: up.emergencyContact, 
      medical_history: up.medicalHistory,
      avatar_url: avatarUrl
    }).eq('id', uid).select().single();

    if (error) throw error;
    return mapProfileToUser(data);
  },

  toggleFavorite: async (uid: string, cid: string): Promise<User | null> => {
    return await safeExecute(async () => {
      const { data: profile } = await supabase.from('profiles').select('favorites').eq('id', uid).single();
      let favs = ensureArray<string>(profile?.favorites);
      if (favs.includes(cid)) {
        favs = favs.filter(id => id !== cid);
      } else {
        favs = [...favs, cid];
      }
      const { data, error } = await supabase.from('profiles').update({ favorites: favs }).eq('id', uid).select().single();
      if (error) throw error;
      return mapProfileToUser(data);
    }, null, "Toggle Favorite");
  },

  getFavorites: async (uid: string): Promise<Clinic[]> => {
    return await safeExecute(async () => {
      const { data: profile } = await supabase.from('profiles').select('favorites').eq('id', uid).single();
      const favIds = ensureArray<string>(profile?.favorites);
      if (favIds.length === 0) return [];

      const { data, error } = await supabase.from('profiles').select('*').in('id', favIds);
      if (error) throw error;
      return ensureArray<any>(data).map(p => ({
        id: p.id,
        name: p.name,
        specialty: p.specialty || 'Especialista',
        location: p.city || 'Salvador-BA',
        neighborhood: p.neighborhood || p.address || 'Centro',
        price: p.price || 'A consultar',
        imageUrl: p.avatar_url,
        rating: p.rating || 5.0,
        reviewCount: p.review_count || 0,
        testimonial: p.bio,
        about: p.about,
        availableServices: ensureArray(p.available_services)
      }));
    }, [], "Get Favorites");
  },

  submitReview: async (cid: string, rating: number, comment: string): Promise<void> => {
    await safeExecute(async () => {
      const { data: clinic } = await supabase.from('profiles').select('rating, review_count').eq('id', cid).single();
      const currentRating = clinic?.rating || 5.0;
      const currentCount = clinic?.review_count || 0;

      const newCount = currentCount + 1;
      const newRating = ((currentRating * currentCount) + rating) / newCount;

      const { error } = await supabase.from('profiles').update({
        rating: newRating,
        review_count: newCount,
      }).eq('id', cid);

      if (error) throw error;
    }, null, "Submit Review");
  },

  getAppointments: async (userId: string, role: UserRole): Promise<Appointment[]> => {
    const col = role === 'patient' ? 'patient_id' : 'clinic_id';
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('appointments').select('*, patient:profiles!patient_id(name), clinic:profiles!clinic_id(name)')
          .eq(col, userId).order('date', { ascending: true });
        if (error) throw error;
        return ensureArray<any>(data).map(app => ({
          id: app.id, patientId: app.patient_id, patientName: app.patient?.name || 'Paciente', clinicId: app.clinic_id,
          doctorName: app.doctor_name, date: app.date, status: app.status, type: app.type, meetingUrl: app.meeting_url, roomId: app.room_id || app.id
        }));
    }, [], "Get Appointments");
  },

  createAppointment: async (app: any): Promise<void> => {
    await safeExecute(async () => {
      const { error } = await supabase.from('appointments').insert({
        patient_id: app.patientId,
        clinic_id: app.clinicId,
        doctor_name: app.doctorName,
        date: app.date,
        status: 'scheduled',
        type: app.type,
        notes: app.notes,
        room_id: app.roomId || Math.random().toString(36).substring(2, 9)
      });
      if (error) throw error;

      const [date, time] = app.date.split(' ');
      await supabase.from('time_slots').update({ is_booked: true })
        .eq('clinic_id', app.clinicId)
        .eq('date', date)
        .eq('time', time);
    }, null, "Create App");
  },

  getRecords: async (uid: string, role: UserRole): Promise<MedicalRecord[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('medical_records').select('*')
            .or(`patient_id.eq.${uid},professional_id.eq.${uid}`)
            .order('date', { ascending: false });
        if (error) throw error;
        return ensureArray<any>(data).map(r => ({
          id: r.id, patientId: r.patient_id, professionalId: r.professional_id, date: r.date, diagnosis: r.diagnosis,
          prescription: r.prescription, doctorName: r.doctor_name, type: r.type as any, title: r.title, cid: r.cid, days: r.days, fileUrl: r.file_url
        }));
    }, [], "Get Records");
  },

  getNotifications: async (uid: string): Promise<Notification[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('notifications').select('*').eq('user_id', uid).order('created_at', { ascending: false });
        if (error) throw error;
        return ensureArray<any>(data).map(n => ({ 
            id: n.id, userId: n.user_id, message: n.message, read: n.read, createdAt: n.created_at, link: n.link, type: n.type as any 
        }));
    }, [], "Get Notifications");
  },

  getAvailableSlots: async (cid: string): Promise<TimeSlot[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('time_slots').select('*').eq('clinic_id', cid).eq('is_booked', false).order('date');
        if (error) throw error;
        return ensureArray<any>(data).map(s => ({ id: s.id, clinicId: s.clinic_id, date: s.date, time: s.time, isBooked: s.is_booked }));
    }, [], "Get Slots");
  },

  getAllSlotsForClinic: async (cid: string): Promise<TimeSlot[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('time_slots').select('*').eq('clinic_id', cid).order('date').order('time');
        if (error) throw error;
        return ensureArray<any>(data).map(s => ({ id: s.id, clinicId: s.clinic_id, date: s.date, time: s.time, isBooked: s.is_booked }));
    }, [], "Get All Slots");
  },

  createTimeSlot: async (cid: string, date: string, time: string): Promise<void> => {
    await safeExecute(async () => {
      const { error } = await supabase.from('time_slots').insert({
        clinic_id: cid,
        date,
        time,
        is_booked: false
      });
      if (error) throw error;
    }, null, "Create Slot");
  },

  createTimeSlotsBatch: async (cid: string, slots: {date: string, time: string}[]): Promise<number> => {
    return await safeExecute(async () => {
      const payload = slots.map(s => ({
        clinic_id: cid,
        date: s.date,
        time: s.time,
        is_booked: false
      }));
      const { data, error } = await supabase.from('time_slots').insert(payload).select();
      if (error) throw error;
      return (data as any[]).length;
    }, 0, "Create Slots Batch");
  },

  deleteTimeSlot: async (id: string): Promise<void> => {
    await safeExecute(async () => {
      const { error } = await supabase.from('time_slots').delete().eq('id', id);
      if (error) throw error;
    }, null, "Delete Slot");
  },

  deleteSlotsByDate: async (cid: string, date: string): Promise<void> => {
    // CRITICAL: Force error propagation and explicit filtering
    await safeExecute(async () => {
      console.log(`[DB] Deletando slots para clinic_id: ${cid}, date: ${date}`);
      const { error, count } = await supabase
        .from('time_slots')
        .delete({ count: 'exact' })
        .eq('clinic_id', cid)
        .eq('date', date);

      if (error) throw error;
      console.log(`[DB] Sucesso. ${count} registros removidos.`);
    }, null, "Delete Slots By Date");
  },

  getAppointmentById: async (id: string): Promise<Appointment | null> => {
    return await safeExecute(async () => {
      const { data, error } = await supabase.from('appointments').select('*').eq('id', id).maybeSingle();
      if (error || !data) return null;
      return {
        id: data.id, patientId: data.patient_id, clinicId: data.clinic_id,
        doctorName: data.doctor_name, date: data.date, status: data.status, type: data.type, 
        meetingUrl: data.meeting_url, roomId: data.room_id || data.id
      };
    }, null, "Get App");
  },

  createMedicalRecord: async (rec: Partial<MedicalRecord>, file?: File) => {
    await safeExecute(async () => {
      const { error } = await supabase.from('medical_records').insert({
        patient_id: rec.patientId, professional_id: rec.professionalId,
        date: rec.date, diagnosis: rec.diagnosis, prescription: rec.prescription,
        doctor_name: rec.doctorName, type: rec.type, title: rec.title, cid: rec.cid, days: rec.days
      });
      if (error) throw error;
    }, null, "Create Rec");
  },

  updateAppointmentStatus: async (id: string, status: string) => {
    await supabase.from('appointments').update({ status }).eq('id', id);
  },

  updateAppointmentLink: async (id: string, url: string) => {
    await supabase.from('appointments').update({ meeting_url: url }).eq('id', id);
  },

  getPendingUsers: async (): Promise<User[]> => {
    const { data, error } = await supabase.from('profiles').select('*').eq('status', 'pending');
    if (error) return [];
    return ensureArray<any>(data).map(mapProfileToUser);
  },

  updateUserStatus: async (uid: string, status: string) => {
    await supabase.from('profiles').update({ status }).eq('id', uid);
  },

  getStats: async () => {
    const { count: u } = await supabase.from('profiles').select('*', { count: 'exact', head: true });
    const { count: a } = await supabase.from('appointments').select('*', { count: 'exact', head: true });
    const { count: p } = await supabase.from('profiles').select('*', { count: 'exact', head: true }).eq('status', 'pending');
    return { users: u || 0, clinics: 0, appointments: a || 0, records: 0, pendingUsers: p || 0 };
  },

  getClinicFinancials: async (cid: string) => {
    return { totalRevenue: 0, chartData: [] };
  },

  getAllClinicsForAdmin: async (): Promise<User[]> => {
    const { data, error } = await supabase.from('profiles').select('*').in('role', ['clinic', 'professional']);
    if (error) return [];
    return ensureArray<any>(data).map(mapProfileToUser);
  },

  getAuditLogs: async (): Promise<AuditLog[]> => {
    return [];
  },

  markNotificationAsRead: async (id: string) => {
    await supabase.from('notifications').update({ read: true }).eq('id', id);
  }
};

import React, { useState, useEffect } from 'react';
import { User, TimeSlot } from '../types';
import { mockDb } from '../lib/mockSupabase';
import { Calendar, Clock, Trash2, Plus, ArrowLeft, Zap, Sparkles, CalendarRange, Check, AlertCircle, Info, RefreshCw } from 'lucide-react';

interface SchedulePageProps {
  user: User;
  onNavigate: (path: string) => void;
  showToast?: (msg: string, type?: 'success' | 'error') => void;
}

const SchedulePage: React.FC<SchedulePageProps> = ({ user, onNavigate, showToast }) => {
  const [slots, setSlots] = useState<TimeSlot[]>([]);
  const [loading, setLoading] = useState(true);

  // Tab State
  const [activeTab, setActiveTab] = useState<'manual' | 'batch'>('batch');

  // Manual Form State
  const [newDate, setNewDate] = useState('');
  const [newTime, setNewTime] = useState('');

  // Batch Form State
  const [batchStartDate, setBatchStartDate] = useState('');
  const [batchEndDate, setBatchEndDate] = useState('');
  const [batchStartTime, setBatchStartTime] = useState('08:00');
  const [batchEndTime, setBatchEndTime] = useState('18:00');
  const [duration, setDuration] = useState('60'); // Minutes
  const [selectedDays, setSelectedDays] = useState<number[]>([1, 2, 3, 4, 5]); // Seg-Sex padrão

  const fetchSlots = async () => {
    setLoading(true);
    try {
      const data = await mockDb.getAllSlotsForClinic(user.id);
      setSlots(Array.isArray(data) ? data : []);
    } catch (e) {
      console.error("Erro ao carregar slots:", e);
      setSlots([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchSlots();
  }, [user.id]);

  const handleAddSlot = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDate || !newTime) return;

    try {
      await mockDb.createTimeSlot(user.id, newDate, newTime);
      if (showToast) showToast('Horário adicionado com sucesso!');
      setNewTime('');
      fetchSlots();
    } catch (e: any) {
      if (showToast) showToast('Erro ao adicionar horário', 'error');
    }
  };

  const handleBatchGenerate = async (e: React.FormEvent) => {
      e.preventDefault();

      if (!batchStartDate || !batchEndDate || !batchStartTime || !batchEndTime) {
          showToast?.("Preencha todas as datas e horários.", "error");
          return;
      }

      const start = new Date(batchStartDate + 'T00:00:00');
      const end = new Date(batchEndDate + 'T00:00:00');

      if (start > end) {
          showToast?.("A data final deve ser posterior à inicial.", "error");
          return;
      }

      const diffTime = Math.abs(end.getTime() - start.getTime());
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1;

      if (diffDays > 31) {
          showToast?.("Limite excedido: Gere no máximo 31 dias por vez.", "error");
          return;
      }

      if (selectedDays.length === 0) {
          showToast?.("Selecione pelo menos um dia da semana.", "error");
          return;
      }

      setLoading(true);
      const slotsToCreate: {date: string, time: string}[] = [];
      let daysProcessed = 0;

      const currentDate = new Date(start);

      while (currentDate <= end && daysProcessed < 40) {
          const dayOfWeek = currentDate.getDay();

          if (selectedDays.includes(dayOfWeek)) {
              const dateISO = currentDate.toISOString().split('T')[0];
              let currentTime = new Date(`${dateISO}T${batchStartTime}:00`);
              const endTimeLimit = new Date(`${dateISO}T${batchEndTime}:00`);
              const stepMinutes = parseInt(duration);

              let slotSafetyCounter = 0;
              while (currentTime < endTimeLimit && slotSafetyCounter < 100) {
                  const timeStr = currentTime.toTimeString().substring(0, 5);
                  slotsToCreate.push({ date: dateISO, time: timeStr });
                  currentTime.setMinutes(currentTime.getMinutes() + stepMinutes);
                  slotSafetyCounter++;
              }
              daysProcessed++;
          }
          currentDate.setDate(currentDate.getDate() + 1);
      }

      if (slotsToCreate.length === 0) {
          showToast?.("Nenhum horário gerado para os dias selecionados.", "error");
          setLoading(false);
          return;
      }

      try {
          const count = await mockDb.createTimeSlotsBatch(user.id, slotsToCreate);
          showToast?.(`${count} horários gerados com sucesso.`);
          await fetchSlots();
      } catch (e) {
          showToast?.("Erro ao salvar lote de horários.", "error");
      } finally {
          setLoading(false);
      }
  };

  const handleDeleteSlot = async (id: string) => {
    try {
      await mockDb.deleteTimeSlot(id);
      setSlots(prev => prev.filter(s => s.id !== id));
      showToast?.('Horário removido.');
    } catch (e) {
      showToast?.('Erro ao remover.', 'error');
    }
  };

  const handleDeleteDay = async (date: string) => {
    const dateBr = date.split('-').reverse().join('/');
    if (!window.confirm(`ATENÇÃO: Deseja remover TODOS os horários do dia ${dateBr}? Isso não afetará consultas já marcadas.`)) return;

    setLoading(true);
    try {
      // Forçamos o envio correto do user.id e da data string
      await mockDb.deleteSlotsByDate(user.id, date);

      showToast?.(`Agenda do dia ${dateBr} removida com sucesso.`);

      // Refresh total para limpar a grade da tela
      await fetchSlots();
    } catch (e: any) {
      console.error("Falha ao deletar dia:", e);
      showToast?.('Erro ao remover dia no banco de dados. Verifique as políticas SQL.', 'error');
      // Tenta dar um refresh de qualquer forma para sincronizar
      await fetchSlots();
    } finally {
      setLoading(false);
    }
  };

  const groupedSlots = slots.reduce((acc, slot) => {
    if (!acc[slot.date]) acc[slot.date] = [];
    acc[slot.date].push(slot);
    return acc;
  }, {} as Record<string, TimeSlot[]>);

  const daysOfWeek = [
      { id: 0, label: 'D' }, { id: 1, label: 'S' }, { id: 2, label: 'T' }, 
      { id: 3, label: 'Q' }, { id: 4, label: 'Q' }, { id: 5, label: 'S' }, 
      { id: 6, label: 'S' },
  ];

  return (
    <div className="p-4 md:p-8 animate-fadeIn max-w-5xl mx-auto">
      <div className="flex items-center gap-3 mb-8">
        <button onClick={() => onNavigate('/dashboard')} className="p-2 hover:bg-slate-100 rounded-full transition-colors md:hidden">
          <ArrowLeft size={20} />
        </button>
        <div>
           <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
             <Calendar className="text-teal-600" /> Gestão de Agenda
           </h2>
           <p className="text-slate-500">Defina sua disponibilidade de forma profissional.</p>
        </div>
      </div>

      <div className="grid md:grid-cols-3 gap-8">
        <div className="md:col-span-1">
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 sticky top-4 overflow-hidden">
            <div className="flex border-b border-slate-100">
                <button 
                  onClick={() => setActiveTab('batch')}
                  className={`flex-1 py-3 text-sm font-bold flex items-center justify-center gap-2 transition-colors ${activeTab === 'batch' ? 'bg-teal-50 text-teal-700 border-b-2 border-teal-500' : 'text-slate-500 hover:bg-slate-50'}`}
                >
                    <Sparkles size={16} /> Automático
                </button>
                <button 
                  onClick={() => setActiveTab('manual')}
                  className={`flex-1 py-3 text-sm font-bold flex items-center justify-center gap-2 transition-colors ${activeTab === 'manual' ? 'bg-white text-slate-800 border-b-2 border-transparent' : 'text-slate-500 hover:bg-slate-50'}`}
                >
                    <Plus size={16} /> Manual
                </button>
            </div>

            <div className="p-6">
                {activeTab === 'batch' && (
                    <form onSubmit={handleBatchGenerate} className="space-y-5">
                        <div className="bg-blue-50 p-3 rounded-lg border border-blue-100 text-blue-800 text-xs mb-2 flex items-start gap-2">
                             <Info size={14} className="mt-0.5 flex-shrink-0" />
                             Gere sua agenda mensal definindo o período e dias.
                        </div>

                        <div className="grid grid-cols-2 gap-3">
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Data Inicial</label>
                                <input 
                                    type="date" required
                                    className="w-full p-2 bg-slate-50 border border-slate-200 rounded text-sm focus:ring-1 focus:ring-teal-500 outline-none"
                                    value={batchStartDate}
                                    onChange={e => setBatchStartDate(e.target.value)}
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Data Final</label>
                                <input 
                                    type="date" required
                                    className="w-full p-2 bg-slate-50 border border-slate-200 rounded text-sm focus:ring-1 focus:ring-teal-500 outline-none"
                                    value={batchEndDate}
                                    onChange={e => setBatchEndDate(e.target.value)}
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Dias de Atendimento</label>
                            <div className="flex justify-between gap-1">
                                {daysOfWeek.map((day) => (
                                    <button
                                        type="button"
                                        key={day.id}
                                        onClick={() => {
                                            setSelectedDays(prev => 
                                                prev.includes(day.id) ? prev.filter(d => d !== day.id) : [...prev, day.id]
                                            );
                                        }}
                                        className={`w-8 h-8 rounded-full text-xs font-bold flex items-center justify-center transition-all ${selectedDays.includes(day.id) ? 'bg-teal-600 text-white shadow-md' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'}`}
                                    >
                                        {day.label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-3">
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Início</label>
                                <input 
                                    type="time" required
                                    className="w-full p-2 bg-slate-50 border border-slate-200 rounded text-sm focus:ring-1 focus:ring-teal-500 outline-none"
                                    value={batchStartTime}
                                    onChange={e => setBatchStartTime(e.target.value)}
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Término</label>
                                <input 
                                    type="time" required
                                    className="w-full p-2 bg-slate-50 border border-slate-200 rounded text-sm focus:ring-1 focus:ring-teal-500 outline-none"
                                    value={batchEndTime}
                                    onChange={e => setBatchEndTime(e.target.value)}
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Duração</label>
                            <select 
                                value={duration}
                                onChange={e => setDuration(e.target.value)}
                                className="w-full p-2 bg-slate-50 border border-slate-200 rounded text-sm focus:ring-1 focus:ring-teal-500 outline-none"
                            >
                                <option value="15">15 min</option>
                                <option value="30">30 min</option>
                                <option value="60">1 hora</option>
                            </select>
                        </div>

                        <button 
                            type="submit"
                            disabled={loading}
                            className="w-full bg-teal-600 text-white font-bold py-3 rounded-xl hover:bg-teal-700 transition-all flex items-center justify-center gap-2 disabled:opacity-70"
                        >
                            {loading ? <RefreshCw className="animate-spin" size={18} /> : <Sparkles size={18} />} 
                            {loading ? 'Processando...' : 'Gerar Agenda'}
                        </button>
                    </form>
                )}

                {activeTab === 'manual' && (
                    <form onSubmit={handleAddSlot} className="space-y-4">
                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Data</label>
                            <input 
                                type="date" required
                                className="w-full p-2 bg-slate-50 border border-slate-200 rounded focus:ring-2 focus:ring-teal-500 outline-none"
                                value={newDate}
                                onChange={e => setNewDate(e.target.value)}
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Hora</label>
                            <input 
                                type="time" required
                                className="w-full p-2 bg-slate-50 border border-slate-200 rounded focus:ring-2 focus:ring-teal-500 outline-none"
                                value={newTime}
                                onChange={e => setNewTime(e.target.value)}
                            />
                        </div>
                        <button 
                            type="submit"
                            className="w-full bg-slate-900 text-white font-bold py-3 rounded-xl hover:bg-slate-800 transition-colors flex items-center justify-center gap-2"
                        >
                            <Plus size={18} /> Adicionar
                        </button>
                    </form>
                )}
            </div>
          </div>
        </div>

        <div className="md:col-span-2 space-y-4">
          <div className="flex items-center justify-between mb-2">
               <h3 className="font-bold text-slate-800 flex items-center gap-2">
                   <CalendarRange size={20} className="text-slate-400"/> Grade de Atendimento
               </h3>
               <div className="text-xs text-slate-400 font-bold uppercase tracking-wider">
                   {slots.length} Horários
               </div>
          </div>

          {loading && slots.length === 0 ? (
            <div className="text-center py-20 bg-white rounded-xl border border-slate-100 flex flex-col items-center">
                <RefreshCw className="animate-spin text-teal-500 mb-4" size={32} />
                <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Sincronizando...</p>
            </div>
          ) : Object.keys(groupedSlots).length === 0 ? (
            <div className="bg-slate-50 border border-dashed border-slate-300 rounded-xl p-8 text-center text-slate-500 flex flex-col items-center justify-center">
               <Calendar size={48} className="mx-auto mb-3 opacity-20" />
               <p className="font-bold text-slate-800">Sua agenda está vazia</p>
            </div>
          ) : (
            <div className="space-y-6">
                {Object.keys(groupedSlots).sort().map(date => (
                  <div key={date} className="bg-white rounded-xl border border-slate-200 overflow-hidden shadow-sm hover:shadow-md transition-shadow">
                    <div className="bg-slate-50 px-4 py-3 border-b border-slate-100 flex justify-between items-center">
                      <h4 className="font-black text-slate-700 flex items-center gap-2 uppercase text-[10px] tracking-widest">
                        <Calendar size={14} className="text-teal-600" />
                        {date.split('-').reverse().join('/')}
                      </h4>
                      <div className="flex items-center gap-3">
                        <span className="text-[10px] font-black bg-white border border-slate-200 px-2 py-0.5 rounded text-slate-500 uppercase">
                          {groupedSlots[date].length} Slots
                        </span>
                        <button 
                          onClick={() => handleDeleteDay(date)}
                          className="flex items-center gap-1.5 px-3 py-1 bg-red-50 text-red-600 border border-red-100 rounded-lg font-black text-[10px] uppercase tracking-widest hover:bg-red-100 transition-colors"
                        >
                          <Trash2 size={12} /> Remover Dia
                        </button>
                      </div>
                    </div>
                    <div className="p-4 grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-3">
                      {groupedSlots[date].sort((a,b) => a.time.localeCompare(b.time)).map(slot => (
                        <div 
                          key={slot.id} 
                          className={`relative group border rounded-lg p-2 text-center transition-all ${slot.isBooked ? 'bg-red-50 border-red-100' : 'bg-white border-slate-100 hover:border-teal-300'}`}
                        >
                          <div className={`font-mono font-bold text-sm ${slot.isBooked ? 'text-red-400 line-through' : 'text-slate-700'}`}>
                            {slot.time}
                          </div>
                          {!slot.isBooked && (
                            <button 
                              onClick={() => handleDeleteSlot(slot.id)}
                              className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 opacity-0 group-hover:opacity-100 transition-all shadow-md"
                            >
                              <Trash2 size={10} />
                            </button>
                          )}
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

