/**
 * MARCLYN PRODUCTION SHIELD v6.0
 * ARCHITECTURE: CONCURRENCY LOCK (MUTEX) + REQUEST SINGLETON
 */

const MAX_RETRIES = 1; // Produção: Apenas 1 tentativa extra
const TIMEOUT_MS = 15000;

// Mapa global para impedir requisições duplicadas em voo
const activeRequests = new Map<string, Promise<any>>();

const safeExecute = async <T>(operation: () => Promise<T>, fallback: T, label = "Op"): Promise<T> => {
    // 1. Singleton Check: Impede chamadas idênticas simultâneas (evita loops de useEffect)
    const requestKey = label; 
    if (activeRequests.has(requestKey)) {
        return activeRequests.get(requestKey);
    }

    const execute = async (): Promise<T> => {
        let lastError: any;
        for (let i = 0; i <= MAX_RETRIES; i++) {
            try {
                const controller = new AbortController();
                const timeoutId = setTimeout(() => controller.abort(), TIMEOUT_MS);

                const result = await operation();
                clearTimeout(timeoutId);
                return result;
            } catch (error: any) {
                lastError = error;

                // SUPRESSÃO DE ABORTERROR: Não logar nem retentar se for apenas um cancelamento de navegação
                if (error.name === 'AbortError' || error.message?.includes('aborted')) {
                    return fallback;
                }

                if (i < MAX_RETRIES) {
                    await new Promise(r => setTimeout(r, 500 * (i + 1)));
                    continue;
                }
            }
        }

        // Log único de erro real
        if (lastError && lastError.name !== 'AbortError') {
            console.error(`[Shield v6.0] ${label} falhou definitivamente:`, lastError.message || lastError);
        }

        throw lastError;
    };

    const requestPromise = execute();
    activeRequests.set(requestKey, requestPromise);

    try {
        return await requestPromise;
    } finally {
        // Libera a trava após a conclusão (sucesso ou falha)
        activeRequests.delete(requestKey);
    }
};

const ensureArray = <T>(data: any): T[] => Array.isArray(data) ? data : [];

