        doctor_name: rec.doctorName, type: rec.type, title: rec.title, cid: rec.cid, days: rec.days
    });
    if (error) throw error;
  },

  updateAppointmentStatus: async (id: string, status: string) => {
    await supabase.from('appointments').update({ status }).eq('id', id);
  },

  updateAppointmentLink: async (id: string, url: string) => {
    await supabase.from('appointments').update({ meeting_url: url }).eq('id', id);
  },

  getPendingUsers: async (): Promise<User[]> => {
    const { data, error } = await supabase.from('profiles').select('*').eq('status', 'pending');
    if (error) return [];
    return ensureArray<any>(data).map(mapProfileToUser);
  },

  updateUserStatus: async (uid: string, status: string) => {
    await supabase.from('profiles').update({ status }).eq('id', uid);
  },

  getStats: async () => {
    const { count: u } = await supabase.from('profiles').select('*', { count: 'exact', head: true });
    const { count: a } = await supabase.from('appointments').select('*', { count: 'exact', head: true });
    const { count: p } = await supabase.from('profiles').select('*', { count: 'exact', head: true }).eq('status', 'pending');
    return { users: u || 0, clinics: 0, appointments: a || 0, records: 0, pendingUsers: p || 0 };
  },

  getClinicFinancials: async (cid: string) => {
    return { totalRevenue: 0, chartData: [] };
  },

  getAllClinicsForAdmin: async (): Promise<User[]> => {
    const { data, error } = await supabase.from('profiles').select('*').in('role', ['clinic', 'professional']);
    if (error) return [];
    return ensureArray<any>(data).map(mapProfileToUser);
  },

  getAuditLogs: async (): Promise<AuditLog[]> => {
    return [];
  },

  markNotificationAsRead: async (id: string) => {
    await supabase.from('notifications').update({ read: true }).eq('id', id);
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Layout from './components/Layout';
import Home from './pages/Home';
import Login from './pages/Login';
import RegisterPatient from './pages/RegisterPatient';
import RegisterPartner from './pages/RegisterPartner';
import PatientDashboard from './pages/PatientDashboard';
import ClinicDashboard from './pages/ClinicDashboard';
import AdminDashboard from './pages/AdminDashboard';
import AdminApprovals from './pages/AdminApprovals';
import AdminSubscriptions from './pages/AdminSubscriptions';
import AdminLogs from './pages/AdminLogs';
import AdminSystemSettings from './pages/AdminSystemSettings';
import ProfilePage from './pages/ProfilePage';
import DocumentsPage from './pages/DocumentsPage';
import SettingsPage from './pages/SettingsPage';
import ConsultationPage from './pages/ConsultationPage';
import SchedulePage from './pages/SchedulePage';
import SearchPage from './pages/SearchPage';
import TeleconsultationRoom from './pages/TeleconsultationRoom';
import ProfessionalPublicProfile from './pages/ProfessionalPublicProfile';
import { mockDb } from './lib/mockSupabase';
import { supabase } from './lib/supabaseClient';
import { User } from './types';
import { CheckCircle, AlertTriangle, X, RefreshCw } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [currentPath, setCurrentPath] = useState(() => window.location.hash.replace('#', '').split('?')[0] || '/');

  // TRAVAS GLOBAIS DE PRODUÇÃO
  const isSyncingRef = useRef(false);
  const authListenerStartedRef = useRef(false);

  const showToast = useCallback((message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3500);
  }, []);

  const syncProfile = useCallback(async (email: string) => {
    if (isSyncingRef.current) return;
    isSyncingRef.current = true;

    try {
      const profile = await mockDb.login(email);
      if (profile) {
        setUser(profile);
      } else {
        // Fallback resiliente: evita logout fantasma se o banco falhar momentaneamente
        setUser(prev => prev || { id: 'temp', email, name: 'Usuário Marclyn', role: 'patient', status: 'active' });
      }
    } catch (e) {
      console.error("[AuthSync] Falha ao sincronizar perfil:", e);
    } finally {
      isSyncingRef.current = false;
      setAuthLoading(false);
    }
  }, []);

  useEffect(() => {
    const handleHash = () => setCurrentPath(window.location.hash.replace('#', '').split('?')[0] || '/');
    window.addEventListener('hashchange', handleHash);
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  // SINGLETON AUTH LISTENER (Anti-Loop & Anti-Logout)
  useEffect(() => {
    if (authListenerStartedRef.current) return;
    authListenerStartedRef.current = true;

    let subscription: any = null;

    const initAuth = async () => {
      // 1. Estado Inicial
      const { data: { session } } = await supabase.auth.getSession();
      if (session?.user?.email) {
        await syncProfile(session.user.email);
      } else {
        setAuthLoading(false);
      }

      // 2. Único Listener Global
      const { data } = supabase.auth.onAuthStateChange(async (event, session) => {
        if (event === 'SIGNED_IN' || event === 'TOKEN_REFRESHED') {
          if (session?.user?.email) {
            await syncProfile(session.user.email);
          }
        } else if (event === 'SIGNED_OUT') {
          setUser(null);
          setAuthLoading(false);
          window.location.hash = '/';
        }
      });
      subscription = data.subscription;
    };

    initAuth();

    return () => {
      if (subscription) subscription.unsubscribe();
      authListenerStartedRef.current = false;
    };
  }, [syncProfile]);

  const navigate = (path: string) => {
    window.location.hash = path;
  };

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    navigate('/dashboard');
    showToast(`Bem-vindo, ${loggedInUser.name.split(' ')[0]}!`);
  };

  const handleLogout = async () => {
    try {
      await supabase.auth.signOut();
    } catch (e) {
      setUser(null);
      navigate('/');
    }
  };

  const commonProps = { onNavigate: navigate, showToast };

  const renderContent = () => {
    if (currentPath.startsWith('/teleconsulta/')) {
        if (!user) return <Login onLogin={handleLogin} {...commonProps} />;
        return <TeleconsultationRoom user={user} {...commonProps} />;
    }
    if (currentPath.startsWith('/professional/')) {
        return <ProfessionalPublicProfile user={user} {...commonProps} />;
    }

    switch (currentPath) {
      case '/': return <Home user={user} {...commonProps} />;
      case '/search': return <SearchPage user={user} {...commonProps} />;
      case '/login': return <Login onLogin={handleLogin} {...commonProps} />;
      case '/register-patient': return <RegisterPatient onLogin={handleLogin} {...commonProps} />;
      case '/register-partner': return <RegisterPartner {...commonProps} />;
      case '/dashboard':
        if (!user) return <Login onLogin={handleLogin} {...commonProps} />;
        if (user.role === 'admin') return <AdminDashboard user={user} onNavigate={navigate} />;
        if (user.role === 'clinic' || user.role === 'professional') return <ClinicDashboard user={user} onNavigate={navigate} />;
        return <PatientDashboard user={user} showToast={showToast} onNavigate={navigate} />;
      case '/admin/approvals':
         if (!user || user.role !== 'admin') return <Home user={user} {...commonProps} />;
         return <AdminApprovals onBack={() => navigate('/dashboard')} showToast={showToast} />;
      case '/admin/subscriptions':
         if (!user || user.role !== 'admin') return <Home user={user} {...commonProps} />;
         return <AdminSubscriptions onNavigate={navigate} showToast={showToast} />;
      case '/admin/logs':
         if (!user || user.role !== 'admin') return <Home user={user} {...commonProps} />;
         return <AdminLogs onNavigate={navigate} />;
      case '/admin/settings':
         if (!user || user.role !== 'admin') return <Home user={user} {...commonProps} />;
         return <AdminSystemSettings onNavigate={navigate} showToast={showToast} />;
      case '/profile':
        if (!user) return <Login onLogin={handleLogin} {...commonProps} />;
        return <ProfilePage user={user} {...commonProps} />;
      case '/documents':
         if (!user) return <Login onLogin={handleLogin} {...commonProps} />;
         return <DocumentsPage user={user} onNavigate={navigate} />;
      case '/consultation':
         if (!user || (user.role !== 'clinic' && user.role !== 'professional')) return <Home user={user} {...commonProps} />;
         return <ConsultationPage user={user} {...commonProps} />;
      case '/schedule':
         if (!user || (user.role !== 'clinic' && user.role !== 'professional')) return <Home user={user} {...commonProps} />;
         return <SchedulePage user={user} {...commonProps} />;
      case '/settings': return <SettingsPage onNavigate={navigate} />;
      default: return <Home user={user} {...commonProps} />;
    }
  };

  if (authLoading) {
    return (
        <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white">
            <div className="w-16 h-16 border-4 border-teal-500/20 border-t-teal-500 rounded-full animate-spin mb-4"></div>
            <p className="text-teal-400 font-black uppercase text-[10px] tracking-widest animate-pulse">Proteção Marclyn Cloud</p>
        </div>
    );
  }

  return (
    <Layout user={user} onLogout={handleLogout} onNavigate={navigate}>
      {renderContent()}

      {toast && (
        <div className={`fixed top-6 right-6 z-[110] p-4 rounded-xl shadow-2xl flex items-center gap-3 animate-slideIn ${toast.type === 'success' ? 'bg-slate-900 text-white' : 'bg-red-600 text-white'}`}>
          <div className={`${toast.type === 'success' ? 'text-teal-400' : 'text-white'}`}>
            {toast.type === 'success' ? <CheckCircle size={24} /> : <AlertTriangle size={24} />}
          </div>
          <div className="flex-1">
            <p className="font-bold text-sm uppercase tracking-tight">{toast.type === 'success' ? 'Sucesso' : 'Aviso'}</p>
            <p className="text-xs opacity-90 leading-tight font-medium">{toast.message}</p>
          </div>
          <button onClick={() => setToast(null)} className="ml-2 hover:opacity-75 p-1"><X size={16} /></button>
        </div>
      )}
    </Layout>
  );
};

export default App;

