/**
 * MARCLYN PRODUCTION SHIELD v6.1
 * ADDED: CANCEL APPOINTMENT LOGIC & SLOT RELEASE
 */

const MAX_RETRIES = 1;
const TIMEOUT_MS = 15000;

const activeRequests = new Map<string, Promise<any>>();

const safeExecute = async <T>(operation: () => Promise<T>, fallback: T, label = "Op"): Promise<T> => {
    const requestKey = label; 
    if (activeRequests.has(requestKey)) {
        return activeRequests.get(requestKey);
    }

    const execute = async (): Promise<T> => {
        let lastError: any;
        for (let i = 0; i <= MAX_RETRIES; i++) {
            try {
                const controller = new AbortController();
                const timeoutId = setTimeout(() => controller.abort(), TIMEOUT_MS);

                const result = await operation();
                clearTimeout(timeoutId);
                return result;
            } catch (error: any) {
                lastError = error;
                if (error.name === 'AbortError' || error.message?.includes('aborted')) {
                    return fallback;
                }
                if (i < MAX_RETRIES) {
                    await new Promise(r => setTimeout(r, 500 * (i + 1)));
                    continue;
                }
            }
        }
        if (lastError && lastError.name !== 'AbortError') {
            console.error(`[Shield v6.1] ${label} falhou:`, lastError.message || lastError);
        }
        throw lastError;
    };

    const requestPromise = execute();
    activeRequests.set(requestKey, requestPromise);
    try {
        return await requestPromise;
    } finally {
        activeRequests.delete(requestKey);
    }
};

const ensureArray = <T>(data: any): T[] => Array.isArray(data) ? data : [];

const mapProfileToUser = (p: any): User => ({
  id: p?.id || '',
  email: p?.email || '',
  name: p?.name || 'Usuário Marclyn',
  role: (p?.role as UserRole) || 'patient',
  status: p?.status || 'active',
  avatarUrl: p?.avatar_url,
  phone: p?.phone,
  address: p?.address,
  neighborhood: p?.neighborhood,
  city: p?.city || 'Salvador',
  document: p?.document,
  specialty: p?.specialty,
  price: p?.price,
  bio: p?.bio,
  about: p?.about,
  reg: p?.reg,
  operatingHours: p?.operating_hours,
  website: p?.website,
  availableServices: ensureArray(p?.available_services),
  favorites: ensureArray(p?.favorites),
  healthPlan: p?.health_plan,
  medicalHistory: p?.medical_history,
  emergencyContact: p?.emergency_contact,
  yampiUrl: p?.yampi_url
});

export const mockDb = {
  login: async (email?: string): Promise<User | null> => {
    if (!email) return null;
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('profiles').select('*').eq('email', email).maybeSingle();
        if (error) throw error;
        return data ? mapProfileToUser(data) : null;
    }, null, "FetchProfile");
  },

  signIn: async (email: string, password: string): Promise<User | null> => {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
    if (data.user) return await mockDb.login(data.user.email!);
    return null;
  },

  registerUser: async (u: any): Promise<User> => {
    const { data: authData, error: authError } = await supabase.auth.signUp({
      email: u.email,
      password: u.password,
    });
    if (authError) throw authError;
    if (!authData.user) throw new Error("Auth failed");

    const { data: profData, error: profError } = await supabase.from('profiles').insert({
      id: authData.user.id,
      email: u.email,
      name: u.name,
      role: u.role,
      status: u.role === 'patient' ? 'active' : 'pending',
      document: u.document,
      phone: u.phone,
      address: u.address,
      website: u.website,
      bio: u.bio,
      reg: u.reg,
      specialty: u.specialty,
      available_services: u.availableServices || []
    }).select().single();

    if (profError) throw profError;
    return mapProfileToUser(profData);
  },

  getClinics: async (): Promise<Clinic[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('profiles')
            .select('*')
            .in('role', ['clinic', 'professional'])
            .eq('status', 'active');
        if (error) throw error;
        return ensureArray<any>(data).map(p => ({
            id: p.id,
            name: p.name,
            specialty: p.specialty || 'Especialista',
            location: p.city || 'Salvador-BA',
            neighborhood: p.neighborhood || p.address || 'Centro',
            price: p.price || 'A consultar',
            imageUrl: p.avatar_url,
            rating: p.rating || 5.0,
            reviewCount: p.review_count || 0,
            testimonial: p.bio,
            about: p.about,
            availableServices: ensureArray(p.available_services)
        }));
    }, [], "GetClinics");
  },

  updateProfile: async (uid: string, up: Partial<User>, file?: File | null) => {
    let avatarUrl = up.avatarUrl;
    if (file) {
      avatarUrl = await new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(file);
      });
    }
    const { data, error } = await supabase.from('profiles').update({
      name: up.name, phone: up.phone, address: up.address, neighborhood: up.neighborhood, city: up.city,
      bio: up.bio, about: up.about, price: up.price, website: up.website, specialty: up.specialty,
      reg: up.reg, document: up.document, available_services: up.availableServices,
      health_plan: up.healthPlan, emergency_contact: up.emergencyContact, 
      medical_history: up.medicalHistory, avatar_url: avatarUrl
    }).eq('id', uid).select().single();
    if (error) throw error;
    return mapProfileToUser(data);
  },

  toggleFavorite: async (uid: string, cid: string): Promise<User | null> => {
    const { data: profile } = await supabase.from('profiles').select('favorites').eq('id', uid).single();
    let favs = ensureArray<string>(profile?.favorites);
    favs = favs.includes(cid) ? favs.filter(id => id !== cid) : [...favs, cid];
    const { data, error } = await supabase.from('profiles').update({ favorites: favs }).eq('id', uid).select().single();
    if (error) throw error;
    return mapProfileToUser(data);
  },

  getFavorites: async (uid: string): Promise<Clinic[]> => {
    return await safeExecute(async () => {
      const { data: profile } = await supabase.from('profiles').select('favorites').eq('id', uid).single();
      const favIds = ensureArray<string>(profile?.favorites);
      if (favIds.length === 0) return [];
      const { data, error } = await supabase.from('profiles').select('*').in('id', favIds);
      if (error) throw error;
      return ensureArray<any>(data).map(p => ({
        id: p.id, name: p.name, specialty: p.specialty, location: p.city,
        neighborhood: p.neighborhood, price: p.price, imageUrl: p.avatar_url,
        rating: p.rating, reviewCount: p.review_count, testimonial: p.bio,
        about: p.about, availableServices: p.available_services
      }));
    }, [], "GetFavorites");
  },

  submitReview: async (cid: string, rating: number, comment: string): Promise<void> => {
    const { data: clinic } = await supabase.from('profiles').select('rating, review_count').eq('id', cid).single();
    const newCount = (clinic?.review_count || 0) + 1;
    const newRating = (((clinic?.rating || 5) * (clinic?.review_count || 0)) + rating) / newCount;
    await supabase.from('profiles').update({ rating: newRating, review_count: newCount }).eq('id', cid);
  },

  getAppointments: async (userId: string, role: UserRole): Promise<Appointment[]> => {
    const col = role === 'patient' ? 'patient_id' : 'clinic_id';
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('appointments').select('*, patient:profiles!patient_id(name), clinic:profiles!clinic_id(name)')
          .eq(col, userId).order('date', { ascending: true });
        if (error) throw error;
        return ensureArray<any>(data).map(app => ({
          id: app.id, patientId: app.patient_id, patientName: app.patient?.name || 'Paciente', clinicId: app.clinic_id,
          doctorName: app.doctor_name, date: app.date, status: app.status, type: app.type, meetingUrl: app.meeting_url, roomId: app.room_id || app.id
        }));
    }, [], "GetAppointments");
  },

  createAppointment: async (app: any): Promise<void> => {
    const { error } = await supabase.from('appointments').insert({
      patient_id: app.patientId, clinic_id: app.clinicId, doctor_name: app.doctorName,
      date: app.date, status: 'scheduled', type: app.type, notes: app.notes, room_id: app.roomId
    });
    if (error) throw error;
    const [date, time] = app.date.split(' ');
    await supabase.from('time_slots').update({ is_booked: true }).eq('clinic_id', app.clinicId).eq('date', date).eq('time', time);
  },

  cancelAppointment: async (appId: string): Promise<void> => {
      // 1. Busca detalhes do agendamento para liberar o horário
      const { data: app, error: fetchError } = await supabase.from('appointments').select('clinic_id, date').eq('id', appId).single();
      if (fetchError || !app) throw new Error("Agendamento não encontrado");

      // 2. Atualiza status para cancelado
      const { error: updateError } = await supabase.from('appointments').update({ status: 'canceled' }).eq('id', appId);
      if (updateError) throw updateError;

      // 3. Tenta liberar o slot de tempo original
      try {
          const [date, time] = app.date.split(' ');
          await supabase.from('time_slots')
            .update({ is_booked: false })
            .eq('clinic_id', app.clinic_id)
            .eq('date', date)
            .eq('time', time);
      } catch (e) {
          console.warn("Slot de tempo não pôde ser liberado automaticamente.");
      }
  },

  getRecords: async (uid: string, role: UserRole): Promise<MedicalRecord[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('medical_records').select('*')
            .or(`patient_id.eq.${uid},professional_id.eq.${uid}`)
            .order('date', { ascending: false });
        if (error) throw error;
        return ensureArray<any>(data).map(r => ({
          id: r.id, patientId: r.patient_id, professionalId: r.professional_id, date: r.date, diagnosis: r.diagnosis,
          prescription: r.prescription, doctorName: r.doctor_name, type: r.type as any, title: r.title, cid: r.cid, days: r.days, fileUrl: r.file_url
        }));
    }, [], "GetRecords");
  },

  getNotifications: async (uid: string): Promise<Notification[]> => {
    try {
        const { data, error } = await supabase.from('notifications').select('*').eq('user_id', uid).order('created_at', { ascending: false }).limit(15);
        if (error) return [];
        return ensureArray<any>(data).map(n => ({ 
            id: n.id, userId: n.user_id, message: n.message, read: n.read, createdAt: n.created_at, link: n.link, type: n.type as any 
        }));
    } catch { return []; }
  },

  getAvailableSlots: async (cid: string): Promise<TimeSlot[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('time_slots').select('*').eq('clinic_id', cid).eq('is_booked', false).order('date');
        if (error) throw error;
        return ensureArray<any>(data).map(s => ({ id: s.id, clinicId: s.clinic_id, date: s.date, time: s.time, isBooked: s.is_booked }));
    }, [], "GetSlots");
  },

  getAllSlotsForClinic: async (cid: string): Promise<TimeSlot[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('time_slots').select('*').eq('clinic_id', cid).order('date').order('time');
        if (error) throw error;
        return ensureArray<any>(data).map(s => ({ id: s.id, clinicId: s.clinic_id, date: s.date, time: s.time, isBooked: s.is_booked }));
    }, [], "GetAllSlots");
  },

  createTimeSlot: async (cid: string, date: string, time: string): Promise<void> => {
    await supabase.from('time_slots').insert({ clinic_id: cid, date, time, is_booked: false });
  },

  createTimeSlotsBatch: async (cid: string, slots: {date: string, time: string}[]): Promise<number> => {
    const payload = slots.map(s => ({ clinic_id: cid, date: s.date, time: s.time, is_booked: false }));
    const { data, error } = await supabase.from('time_slots').insert(payload).select();
    if (error) throw error;
    return (data as any[]).length;
  },

  deleteTimeSlot: async (id: string): Promise<void> => {
    await supabase.from('time_slots').delete().eq('id', id);
  },

  deleteSlotsByDate: async (cid: string, date: string): Promise<number> => {
    const { error, data } = await supabase
        .from('time_slots')
        .delete()
        .eq('clinic_id', cid)
        .eq('date', date)
        .select();
    if (error) throw error;
    return (data as any[])?.length || 0;
  },

  getAppointmentById: async (id: string): Promise<Appointment | null> => {
    const { data, error } = await supabase.from('appointments').select('*').eq('id', id).maybeSingle();
    if (error || !data) return null;
    return {
        id: data.id, patientId: data.patient_id, clinicId: data.clinic_id,
        doctorName: data.doctor_name, date: data.date, status: data.status, type: data.type, 
        meetingUrl: data.meeting_url, roomId: data.room_id || data.id
    };
  },

  createMedicalRecord: async (rec: Partial<MedicalRecord>, file?: File) => {
    const { error } = await supabase.from('medical_records').insert({
        patient_id: rec.patientId, professional_id: rec.professionalId,
        date: rec.date, diagnosis: rec.diagnosis, prescription: rec.prescription,
        doctor_name: rec.doctorName, type: rec.type, title: rec.title, cid: rec.cid, days: rec.days
    });
    if (error) throw error;
  },

  updateAppointmentStatus: async (id: string, status: string) => {
    await supabase.from('appointments').update({ status }).eq('id', id);
  },

  updateAppointmentLink: async (id: string, url: string) => {
    await supabase.from('appointments').update({ meeting_url: url }).eq('id', id);
  },

  getPendingUsers: async (): Promise<User[]> => {
    const { data, error } = await supabase.from('profiles').select('*').eq('status', 'pending');
    if (error) return [];
    return ensureArray<any>(data).map(mapProfileToUser);
  },

  updateUserStatus: async (uid: string, status: string) => {
    await supabase.from('profiles').update({ status }).eq('id', uid);
  },

  getStats: async () => {
    const { count: u } = await supabase.from('profiles').select('*', { count: 'exact', head: true });
    const { count: a } = await supabase.from('appointments').select('*', { count: 'exact', head: true });
    const { count: p } = await supabase.from('profiles').select('*', { count: 'exact', head: true }).eq('status', 'pending');
    return { users: u || 0, clinics: 0, appointments: a || 0, records: 0, pendingUsers: p || 0 };
  },

  getClinicFinancials: async (cid: string) => {
    return { totalRevenue: 0, chartData: [] };
  },

  getAllClinicsForAdmin: async (): Promise<User[]> => {
    const { data, error } = await supabase.from('profiles').select('*').in('role', ['clinic', 'professional']);
    if (error) return [];
    return ensureArray<any>(data).map(mapProfileToUser);
  },

  getAuditLogs: async (): Promise<AuditLog[]> => {
    return [];
  },

  markNotificationAsRead: async (id: string) => {
    await supabase.from('notifications').update({ read: true }).eq('id', id);
  }
};

import React, { useState, useEffect } from 'react';
import { User, Appointment, Clinic } from '../types';
import { mockDb } from '../lib/mockSupabase';
import QuickAccessCard from '../components/QuickAccessCard';
import ServiceCard from '../components/ServiceCard';
import AppointmentForm from '../components/forms/AppointmentForm';
import { Calendar, Clock, Plus, Filter, CheckCircle, XCircle, Clock as ClockIcon, History, Star, MessageSquare, Send, X, Video, Stethoscope, TestTube, ClipboardCheck, FileText, FileHeart, FileBadge, Settings, Link, Copy, Heart, Trash2 } from 'lucide-react';

interface PatientDashboardProps {
  user: User;
  showToast?: (msg: string, type?: 'success' | 'error') => void;
  onNavigate?: (path: string) => void;
}

const PatientDashboard: React.FC<PatientDashboardProps> = ({ user, showToast, onNavigate }) => {
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [clinics, setClinics] = useState<Clinic[]>([]);
  const [favoriteClinics, setFavoriteClinics] = useState<Clinic[]>([]);
  const [loading, setLoading] = useState(true);

  // Booking Modal
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [selectedClinicForBooking, setSelectedClinicForBooking] = useState<Clinic | null>(null);

  // Filters State
  const [viewPeriod, setViewPeriod] = useState<'upcoming' | 'history'>('upcoming');
  const [statusFilter, setStatusFilter] = useState<'all' | 'scheduled' | 'confirmed' | 'done' | 'canceled'>('all');

  // Rating Modal State
  const [ratingModalOpen, setRatingModalOpen] = useState(false);
  const [selectedAppointment, setSelectedAppointment] = useState<Appointment | null>(null);
  const [ratingValue, setRatingValue] = useState(0);
  const [ratingComment, setRatingComment] = useState('');

  const refreshData = async () => {
    setLoading(true);
    try {
        const [apps, clin, favs] = await Promise.all([
            mockDb.getAppointments(user.id, user.role),
            mockDb.getClinics(),
            mockDb.getFavorites(user.id)
        ]);

        const sortedApps = apps.sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
        setAppointments(sortedApps);
        setClinics(clin);
        setFavoriteClinics(favs);
    } catch (e) {
        console.error(e);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => {
    refreshData();
  }, [user]);

  const openRatingModal = (app: Appointment) => {
    setSelectedAppointment(app);
    setRatingValue(0);
    setRatingComment('');
    setRatingModalOpen(true);
  };

  const submitRating = async () => {
    if (!selectedAppointment || ratingValue === 0) {
      if(showToast) showToast("Selecione uma nota de 1 a 5 estrelas.", "error");
      return;
    }

    try {
      await mockDb.submitReview(selectedAppointment.clinicId, ratingValue, ratingComment);
      if(showToast) showToast("Avaliação enviada com sucesso!");
      setRatingModalOpen(false);
    } catch (e) {
      if(showToast) showToast("Erro ao enviar avaliação.", "error");
    }
  };

  const handleCancelAppointment = async (appId: string) => {
    if (!window.confirm("Deseja realmente cancelar este agendamento? O horário ficará disponível para outros pacientes.")) return;

    try {
      await mockDb.cancelAppointment(appId);
      if (showToast) showToast("Consulta cancelada com sucesso.");
      refreshData();
    } catch (e) {
      if (showToast) showToast("Erro ao cancelar consulta.", "error");
    }
  };

  const handleCopyLink = (link: string) => {
    navigator.clipboard.writeText(link).then(() => {
        if (showToast) showToast("Link copiado para a área de transferência!");
    });
  };

  const handleBookFavorite = (clinic: Clinic) => {
    setSelectedClinicForBooking(clinic);
    setShowBookingModal(true);
  };

  const handleBookingSuccess = () => {
    setShowBookingModal(false);
    setSelectedClinicForBooking(null);
    refreshData(); 
  };

  const handleServiceClick = (serviceId: string) => {
    if(!onNavigate) return;
    switch(serviceId) {
      case 'teleconsulta': onNavigate('/search?type=teleconsulta'); break;
      case 'presencial': onNavigate('/search?type=presencial'); break;
      case 'exames': onNavigate('/search?type=exame'); break;
      case 'resultados': onNavigate('/documents?filter=exam_result'); break;
      case 'perfil': onNavigate('/profile'); break;
    }
  };

  const allServices = [
    { id: 'teleconsulta', title: 'Marcar Teleconsulta', icon: <Video size={20} /> },
    { id: 'presencial', title: 'Marcar Consulta', icon: <Stethoscope size={20} />, desc: 'Presencial' },
    { id: 'exames', title: 'Marcar Exames', icon: <TestTube size={20} /> },
    { id: 'resultados', title: 'Resultados de Exames', icon: <ClipboardCheck size={20} />, desc: 'Ver Laudos' },
    { id: 'perfil', title: 'Minha Conta', icon: <Settings size={20} /> },
  ];

  const filteredAppointments = appointments.filter(app => {
    const appDate = new Date(app.date.replace(' ', 'T'));
    const now = new Date();
    const isUpcoming = appDate >= now || app.date.startsWith(now.toISOString().split('T')[0]);
    if (viewPeriod === 'upcoming' && !isUpcoming) return false;
    if (viewPeriod === 'history' && isUpcoming && app.status !== 'done' && app.status !== 'canceled') return false;
    if (statusFilter !== 'all' && app.status !== statusFilter) return false;
    return true;
  });

  const displayList = viewPeriod === 'history' ? [...filteredAppointments].reverse() : filteredAppointments;
  const getClinic = (id: string) => clinics.find(c => c.id === id);
  const getClinicName = (id: string) => getClinic(id)?.name || 'Clínica/Profissional';

  const getStatusColor = (status: string) => {
    switch(status) {
      case 'confirmed': return 'bg-green-100 text-green-800 border-green-200';
      case 'scheduled': return 'bg-blue-100 text-blue-800 border-blue-200';
      case 'done': return 'bg-slate-100 text-slate-600 border-slate-200';
      case 'canceled': return 'bg-red-100 text-red-800 border-red-200';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusLabel = (status: string) => {
     switch(status) {
      case 'confirmed': return 'Confirmado';
      case 'scheduled': return 'Agendado';
      case 'done': return 'Realizado';
      case 'canceled': return 'Cancelado';
      default: return status;
    }
  };

  const isTeleconsultActive = (app: Appointment) => {
      if (app.type !== 'teleconsulta') return false;
      if (app.status === 'canceled' || app.status === 'done') return false;
      const appDateOnly = app.date.split(' ')[0];
      const todayOnly = new Date().toISOString().split('T')[0];
      return appDateOnly === todayOnly;
  };

  return (
    <div className="p-4 md:p-8 relative animate-fadeIn max-w-6xl mx-auto">

      {showBookingModal && selectedClinicForBooking && (
        <div className="fixed inset-0 z-[70] bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="w-full max-w-lg">
            <AppointmentForm 
              clinics={clinics}
              patientId={user.id}
              preSelectedClinicId={selectedClinicForBooking.id}
              onSuccess={handleBookingSuccess}
              onCancel={() => {
                setShowBookingModal(false);
                setSelectedClinicForBooking(null);
              }}
              showToast={showToast}
            />
          </div>
        </div>
      )}

      {ratingModalOpen && selectedAppointment && (
        <div className="fixed inset-0 z-[60] bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl p-6 border border-slate-100 animate-slideUp">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-xl font-bold text-slate-800">Avaliar Atendimento</h3>
              <button onClick={() => setRatingModalOpen(false)} className="text-slate-400 hover:text-slate-600">
                <X size={24} />
              </button>
            </div>
            <div className="text-center mb-6">
              <div className="w-16 h-16 bg-teal-50 rounded-full flex items-center justify-center mx-auto mb-3 text-teal-600 font-bold text-2xl">
                 {getClinicName(selectedAppointment.clinicId).charAt(0)}
              </div>
              <p className="font-bold text-slate-800 text-lg">{getClinicName(selectedAppointment.clinicId)}</p>
              <p className="text-slate-500 text-sm">{selectedAppointment.doctorName}</p>
            </div>
            <div className="flex justify-center gap-2 mb-6">
              {[1, 2, 3, 4, 5].map((star) => (
                <button key={star} onClick={() => setRatingValue(star)} className={`transition-all transform hover:scale-110 ${ratingValue >= star ? 'text-yellow-400 fill-yellow-400' : 'text-slate-300'}`}>
                  <Star size={32} fill={ratingValue >= star ? "currentColor" : "none"} />
                </button>
              ))}
            </div>
            <div className="mb-6">
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Seu Depoimento (Opcional)</label>
              <textarea value={ratingComment} onChange={(e) => setRatingComment(e.target.value)} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none resize-none text-sm" rows={3} placeholder="Conte como foi sua experiência..." />
            </div>
            <button onClick={submitRating} className="w-full bg-slate-900 text-white font-bold py-3 rounded-xl hover:bg-slate-800 transition-all flex items-center justify-center gap-2 shadow-lg">
              <Send size={18} /> Enviar Avaliação
            </button>
          </div>
        </div>
      )}

      <div className="mb-8">
        <h2 className="text-2xl font-bold text-slate-900">Painel do Cliente</h2>
        <p className="text-slate-500 mt-1">Bem-vindo(a), {user.name.split(' ')[0]}. O que você precisa hoje?</p>
      </div>

      <div className="mb-10">
        <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4">Serviços Disponíveis</h3>
        <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
          {allServices.map(service => (
            <QuickAccessCard key={service.id} title={service.title} icon={service.icon} description={service.desc} onClick={() => handleServiceClick(service.id)} />
          ))}
        </div>
      </div>

      {favoriteClinics.length > 0 && (
          <div className="mb-10 animate-slideIn">
            <h3 className="text-sm font-bold text-teal-600 uppercase tracking-wider mb-4 flex items-center gap-2">
                <Heart size={16} className="fill-teal-600" /> Minhas Clínicas Favoritas
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {favoriteClinics.map(clinic => (
