const ClinicDashboard: React.FC<ClinicDashboardProps> = ({ user, onNavigate, showToast }) => {
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [financials, setFinancials] = useState({ totalRevenue: 0, chartData: [] as any[] });
  const [loading, setLoading] = useState(true);

  const loadData = async () => {
      setLoading(true);
      try {
        const apps = await mockDb.getAppointments(user.id, user.role);
        const finData = await mockDb.getClinicFinancials(user.id);
        setAppointments(apps);
        setFinancials(finData);
      } catch (e) {
        console.error("Dashboard Load Error:", e);
      } finally {
        setLoading(false);
      }
  };

  useEffect(() => {
    loadData();
  }, [user]);

  const handleConsultation = () => {
    if (onNavigate) onNavigate('/consultation');
  };

  const handleCancelAppointment = async (appId: string) => {
      if (!window.confirm("Confirmar cancelamento de consulta? O paciente será notificado e o horário liberado.")) return;

      try {
          await mockDb.cancelAppointment(appId);
          if (showToast) showToast("Consulta cancelada e horário liberado.");
          loadData();
      } catch (e: any) {
          console.error("Erro no cancelamento:", e);
          if (showToast) showToast(e.message || "Erro ao cancelar consulta. Verifique sua conexão.", "error");
      }
  };

  const isToday = (dateStr: string) => {
      if (!dateStr) return false;
      const today = new Date().toISOString().split('T')[0];
      return dateStr.startsWith(today);
  };

  const canShowTeleconsultButton = (app: Appointment) => {
    if (app.type !== 'teleconsulta') return false;
