/**
 * MARCLYN PRODUCTION SHIELD v6.4
 * EMERGENCY FIX: REMOVED MUTEX LOCK ON CANCEL ACTIONS TO PREVENT UI STICKINESS
 */

const MAX_RETRIES = 1;
const TIMEOUT_MS = 15000;

const activeRequests = new Map<string, Promise<any>>();

const safeExecute = async <T>(operation: () => Promise<T>, fallback: T, label = "Op"): Promise<T> => {
    // Para operações de leitura (GET), mantemos o cache de concorrência
    const isReadOp = label.startsWith("Get") || label.startsWith("Fetch");
    const requestKey = label; 

    if (isReadOp && activeRequests.has(requestKey)) {
        return activeRequests.get(requestKey);
    }

    const execute = async (): Promise<T> => {
        let lastError: any;
        for (let i = 0; i <= MAX_RETRIES; i++) {
            try {
                const controller = new AbortController();
                const timeoutId = setTimeout(() => controller.abort(), TIMEOUT_MS);

                const result = await operation();
                clearTimeout(timeoutId);
                return result;
            } catch (error: any) {
                lastError = error;
                if (error.name === 'AbortError' || error.message?.includes('aborted')) {
                    return fallback;
                }
                if (i < MAX_RETRIES) {
                    await new Promise(r => setTimeout(r, 500 * (i + 1)));
                    continue;
                }
            }
        }
        console.error(`[Shield v6.4] Erro em ${label}:`, lastError.message || lastError);
        throw lastError;
    };

    if (isReadOp) {
        const requestPromise = execute();
        activeRequests.set(requestKey, requestPromise);
        try { return await requestPromise; } finally { activeRequests.delete(requestKey); }
    } else {
        // Operações de escrita (Cancel/Delete) rodam SEM trava de mapa para não travar a UI
        return await execute();
    }
};

