  cancelAppointment: async (appId: string): Promise<void> => {
    console.log(`[DB] Iniciando cancelamento do ID: ${appId}`);
    return await safeExecute(async () => {
        // 1. Busca detalhes do agendamento
        const { data: app, error: fetchError } = await supabase.from('appointments').select('clinic_id, date').eq('id', appId).maybeSingle();

        if (fetchError) {
            console.error("[DB] Erro ao buscar agendamento:", fetchError);
            throw new Error(`Erro ao buscar dados: ${fetchError.message}`);
        }

        if (!app) {
            console.warn("[DB] Nenhum agendamento encontrado para o ID fornecido.");
            throw new Error("Agendamento não encontrado.");
        }

        // 2. Atualiza para cancelado
        const { error: updateError } = await supabase.from('appointments').update({ status: 'canceled' }).eq('id', appId);
        if (updateError) {
            console.error("[DB] Erro ao atualizar status:", updateError);
            throw updateError;
        }

        // 3. Libera o horário se possível
        if (app.date && app.date.includes(' ')) {
            const [date, time] = app.date.split(' ');
            console.log(`[DB] Liberando slot: ${date} ${time}`);
            await supabase.from('time_slots').update({ is_booked: false })
              .eq('clinic_id', app.clinic_id).eq('date', date).eq('time', time);
