  email: p?.email || '',
  name: p?.name || 'Usuário Marclyn',
  role: (p?.role as UserRole) || 'patient',
  status: p?.status || 'active',
  avatarUrl: p?.avatar_url,
  phone: p?.phone,
  address: p?.address,
  neighborhood: p?.neighborhood,
  city: p?.city || 'Salvador',
  document: p?.document,
  specialty: p?.specialty,
  price: p?.price,
  bio: p?.bio,
  about: p?.about,
  reg: p?.reg,
  operatingHours: p?.operating_hours,
  website: p?.website,
  availableServices: ensureArray(p?.available_services),
