    return {
        id: data.id, patientId: data.patient_id, clinicId: data.clinic_id,
        doctorName: data.doctor_name, date: data.date, status: data.status, type: data.type, 
        meetingUrl: data.meeting_url, roomId: app.room_id || app.id
    };
  },

  createMedicalRecord: async (rec: Partial<MedicalRecord>, file?: File) => {
    const { error } = await supabase.from('medical_records').insert({
        patient_id: rec.patientId, professional_id: rec.professionalId,
        date: rec.date, diagnosis: rec.diagnosis, prescription: rec.prescription,
        doctor_name: rec.doctorName, type: rec.type, title: rec.title, cid: rec.cid, days: rec.days
    });
    if (error) throw error;
  },

  updateAppointmentStatus: async (id: string, status: string) => {
    await supabase.from('appointments').update({ status }).eq('id', id);
  },

  updateAppointmentLink: async (id: string, url: string) => {
    await supabase.from('appointments').update({ meeting_url: url }).eq('id', id);
  },

  getPendingUsers: async (): Promise<User[]> => {
    const { data, error } = await supabase.from('profiles').select('*').eq('status', 'pending');
    if (error) return [];
    return ensureArray<any>(data).map(mapProfileToUser);
  },

  updateUserStatus: async (uid: string, status: string) => {
    await supabase.from('profiles').update({ status }).eq('id', uid);
  },

  getStats: async () => {
    const { count: u } = await supabase.from('profiles').select('*', { count: 'exact', head: true });
    const { count: a } = await supabase.from('appointments').select('*', { count: 'exact', head: true });
    const { count: p } = await supabase.from('profiles').select('*', { count: 'exact', head: true }).eq('status', 'pending');
    return { users: u || 0, clinics: 0, appointments: a || 0, records: 0, pendingUsers: p || 0 };
  },

  getClinicFinancials: async (cid: string) => {
    return { totalRevenue: 0, chartData: [] };
  },

  getAllClinicsForAdmin: async (): Promise<User[]> => {
    const { data, error } = await supabase.from('profiles').select('*').in('role', ['clinic', 'professional']);
    if (error) return [];
    return ensureArray<any>(data).map(mapProfileToUser);
  },

  getAuditLogs: async (): Promise<AuditLog[]> => {
    return [];
  },

  markNotificationAsRead: async (id: string) => {
    await supabase.from('notifications').update({ read: true }).eq('id', id);
  }
};

import React, { useState, useEffect } from 'react';
import { User, Appointment, Clinic } from '../types';
import { mockDb } from '../lib/mockSupabase';
import QuickAccessCard from '../components/QuickAccessCard';
import ServiceCard from '../components/ServiceCard';
import AppointmentForm from '../components/forms/AppointmentForm';
import { Calendar, Clock, Plus, Filter, CheckCircle, XCircle, Clock as ClockIcon, History, Star, Send, X, Video, Stethoscope, TestTube, ClipboardCheck, FileText, Settings, Link, Copy, Heart, Trash2 } from 'lucide-react';

interface PatientDashboardProps {
  user: User;
  showToast?: (msg: string, type?: 'success' | 'error') => void;
  onNavigate?: (path: string) => void;
}

const PatientDashboard: React.FC<PatientDashboardProps> = ({ user, showToast, onNavigate }) => {
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [clinics, setClinics] = useState<Clinic[]>([]);
  const [favoriteClinics, setFavoriteClinics] = useState<Clinic[]>([]);
  const [loading, setLoading] = useState(true);

  // Booking Modal
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [selectedClinicForBooking, setSelectedClinicForBooking] = useState<Clinic | null>(null);

  // Filters State
  const [viewPeriod, setViewPeriod] = useState<'upcoming' | 'history'>('upcoming');
  const [statusFilter, setStatusFilter] = useState<'all' | 'scheduled' | 'confirmed' | 'done' | 'canceled'>('all');

  // Rating Modal State
  const [ratingModalOpen, setRatingModalOpen] = useState(false);
  const [selectedAppointment, setSelectedAppointment] = useState<Appointment | null>(null);
  const [ratingValue, setRatingValue] = useState(0);
  const [ratingComment, setRatingComment] = useState('');

  const refreshData = async () => {
    setLoading(true);
    try {
        const [apps, clin, favs] = await Promise.all([
            mockDb.getAppointments(user.id, user.role),
            mockDb.getClinics(),
            mockDb.getFavorites(user.id)
        ]);

        const sortedApps = apps.sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
        setAppointments(sortedApps);
        setClinics(clin);
        setFavoriteClinics(favs);
    } catch (e) {
        console.error(e);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => {
    refreshData();
  }, [user]);

  const openRatingModal = (app: Appointment) => {
    setSelectedAppointment(app);
    setRatingValue(0);
    setRatingComment('');
    setRatingModalOpen(true);
  };

  const submitRating = async () => {
    if (!selectedAppointment || ratingValue === 0) {
      if(showToast) showToast("Selecione uma nota de 1 a 5 estrelas.", "error");
      return;
    }

    try {
      await mockDb.submitReview(selectedAppointment.clinicId, ratingValue, ratingComment);
      if(showToast) showToast("Avaliação enviada com sucesso!");
      setRatingModalOpen(false);
    } catch (e) {
      if(showToast) showToast("Erro ao enviar avaliação.", "error");
    }
  };

  const handleCancelAppointment = async (appId: string) => {
    console.log(`[PACIENTE] Tentativa de cancelar ID: ${appId}`);

    if (!window.confirm("Deseja realmente cancelar este agendamento? O horário ficará disponível para outros pacientes.")) return;

    // UI OTIMISTA: Atualiza o status na tela imediatamente
    const originalApps = [...appointments];
    setAppointments(prev => prev.map(a => a.id === appId ? { ...a, status: 'canceled' as any } : a));

    try {
      if (showToast) showToast("Processando cancelamento...", "success");
      await mockDb.cancelAppointment(appId);

      console.log("[PACIENTE] Sucesso no banco.");
      if (showToast) showToast("Consulta cancelada com sucesso.");

      // Sincroniza com o banco real após um pequeno delay
      setTimeout(refreshData, 500);
    } catch (e: any) {
      console.error("[PACIENTE] Falha ao cancelar no banco:", e);
      // ROLLBACK: Se falhar no banco, volta os dados originais
      setAppointments(originalApps);
      if (showToast) showToast(`Erro ao cancelar: ${e.message || "Tente novamente."}`, "error");
    }
  };

  const handleCopyLink = (link: string) => {
    navigator.clipboard.writeText(link).then(() => {
        if (showToast) showToast("Link copiado para a área de transferência!");
    });
  };

  const handleBookFavorite = (clinic: Clinic) => {
    setSelectedClinicForBooking(clinic);
    setShowBookingModal(true);
  };

  const handleBookingSuccess = () => {
    setShowBookingModal(false);
    setSelectedClinicForBooking(null);
    refreshData(); 
  };

