      case 'teleconsulta': onNavigate('/search?type=teleconsulta'); break;
      case 'presencial': onNavigate('/search?type=presencial'); break;
      case 'exames': onNavigate('/search?type=exame'); break;
      case 'resultados': onNavigate('/documents?filter=exam_result'); break;
