    if (viewPeriod === 'upcoming' && !isUpcoming) return false;
    if (viewPeriod === 'history' && isUpcoming && app.status !== 'done' && app.status !== 'canceled') return false;
    if (statusFilter !== 'all' && app.status !== statusFilter) return false;
    return true;
