    <div className="p-4 md:p-8 relative animate-fadeIn max-w-6xl mx-auto">

      {showBookingModal && selectedClinicForBooking && (
        <div className="fixed inset-0 z-[70] bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="w-full max-w-lg">
            <AppointmentForm 
              clinics={clinics}
              patientId={user.id}
              preSelectedClinicId={selectedClinicForBooking.id}
              onSuccess={handleBookingSuccess}
              onCancel={() => {
                setShowBookingModal(false);
                setSelectedClinicForBooking(null);
              }}
              showToast={showToast}
            />
          </div>
        </div>
      )}

      {ratingModalOpen && selectedAppointment && (
        <div className="fixed inset-0 z-[60] bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl p-6 border border-slate-100 animate-slideUp">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-xl font-bold text-slate-800">Avaliar Atendimento</h3>
              <button onClick={() => setRatingModalOpen(false)} className="text-slate-400 hover:text-slate-600">
                <X size={24} />
              </button>
            </div>
            <div className="text-center mb-6">
              <div className="w-16 h-16 bg-teal-50 rounded-full flex items-center justify-center mx-auto mb-3 text-teal-600 font-bold text-2xl">
                 {getClinicName(selectedAppointment.clinicId).charAt(0)}
              </div>
              <p className="font-bold text-slate-800 text-lg">{getClinicName(selectedAppointment.clinicId)}</p>
              <p className="text-slate-500 text-sm">{selectedAppointment.doctorName}</p>
            </div>
            <div className="flex justify-center gap-2 mb-6">
              {[1, 2, 3, 4, 5].map((star) => (
                <button key={star} onClick={() => setRatingValue(star)} className={`transition-all transform hover:scale-110 ${ratingValue >= star ? 'text-yellow-400 fill-yellow-400' : 'text-slate-300'}`}>
                  <Star size={32} fill={ratingValue >= star ? "currentColor" : "none"} />
                </button>
              ))}
            </div>
            <div className="mb-6">
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Seu Depoimento (Opcional)</label>
              <textarea value={ratingComment} onChange={(e) => setRatingComment(e.target.value)} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none resize-none text-sm" rows={3} placeholder="Conte como foi sua experiência..." />
            </div>
            <button onClick={submitRating} className="w-full bg-slate-900 text-white font-bold py-3 rounded-xl hover:bg-slate-800 transition-all flex items-center justify-center gap-2 shadow-lg">
              <Send size={18} /> Enviar Avaliação
