                       <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shadow-sm relative ${app.status === 'done' || app.status === 'canceled' ? 'bg-slate-100 text-slate-400' : 'bg-teal-50 text-teal-600'}`}>
