                            <>
                                <button onClick={() => onNavigate(`/teleconsulta/${app.roomId || app.id}`)} className="bg-red-600 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 hover:bg-red-700 shadow-lg animate-pulse transition-all">
                                <Video size={16} /> Entrar na Sala
