                                <button onClick={() => handleCopyLink(app.meetingUrl!)} className="bg-white border border-slate-200 text-slate-600 p-2 rounded-lg hover:bg-slate-50 hover:text-slate-900 transition-colors"><Copy size={20} /></button>
                            </>
                        ) : (
                            <button disabled className="bg-slate-100 text-slate-400 border border-slate-200 px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 cursor-not-allowed">
                                <Link size={16} /> Aguardando Médico...
