                    )}
                    {app.status === 'done' && <button onClick={() => openRatingModal(app)} className="flex items-center gap-2 text-teal-600 hover:text-white hover:bg-teal-600 border border-teal-600 px-4 py-2 rounded-lg transition-colors font-bold text-sm"><Star size={16} /> Avaliar</button>}

                    {canCancel && (
                        <button 
                            type="button"
                            onClick={() => handleCancelAppointment(app.id)}
