              </div>
            );
          })
        ) : (
          <div className="text-center py-16 bg-white rounded-xl border border-dashed border-slate-300">
            <div className="bg-slate-50 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4"><Calendar className="text-slate-300" size={32} /></div>
            <p className="text-slate-500 font-medium">Nenhum agendamento encontrado.</p>
          </div>
        )}
      </div>
    </div>
  );
