  status: p?.status || 'active',
  avatarUrl: p?.avatar_url,
  phone: p?.phone,
  address: p?.address,
  neighborhood: p?.neighborhood,
  city: p?.city || 'Salvador',
  document: p?.document,
  specialty: p?.specialty,
  price: p?.price,
  bio: p?.bio,
  about: p?.about,
  reg: p?.reg,
  operatingHours: p?.operating_hours,
  website: p?.website,
  availableServices: ensureArray(p?.available_services),
  favorites: ensureArray(p?.favorites),
  healthPlan: p?.health_plan,
  medicalHistory: p?.medical_history,
  emergencyContact: p?.emergency_contact,
  yampiUrl: p?.yampi_url
});

export const mockDb = {
  login: async (email?: string): Promise<User | null> => {
    if (!email) return null;
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('profiles').select('*').eq('email', email).maybeSingle();
        if (error) throw error;
        return data ? mapProfileToUser(data) : null;
    }, null, "FetchProfile");
  },

  signIn: async (email: string, password: string): Promise<User | null> => {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
    if (data.user) return await mockDb.login(data.user.email!);
    return null;
  },

  registerUser: async (u: any): Promise<User> => {
    const { data: authData, error: authError } = await supabase.auth.signUp({ email: u.email, password: u.password });
    if (authError) throw authError;
    if (!authData.user) throw new Error("Auth failed");
    const { data: profData, error: profError } = await supabase.from('profiles').insert({
      id: authData.user.id, email: u.email, name: u.name, role: u.role, status: u.role === 'patient' ? 'active' : 'pending',
      document: u.document, phone: u.phone, address: u.address, website: u.website, bio: u.bio, reg: u.reg, specialty: u.specialty,
      available_services: u.availableServices || []
    }).select().single();
    if (profError) throw profError;
    return mapProfileToUser(profData);
  },

  getClinics: async (): Promise<Clinic[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('profiles').select('*').in('role', ['clinic', 'professional']).eq('status', 'active');
        if (error) throw error;
        return ensureArray<any>(data).map(p => ({
            id: p.id, name: p.name, specialty: p.specialty || 'Especialista', location: p.city || 'Salvador-BA',
            neighborhood: p.neighborhood || p.address || 'Centro', price: p.price || 'A consultar', imageUrl: p.avatar_url,
            rating: p.rating || 5.0, reviewCount: p.review_count || 0, testimonial: p.bio, about: p.about,
            availableServices: ensureArray(p.available_services)
        }));
    }, [], "GetClinics");
  },

  updateProfile: async (uid: string, up: Partial<User>, file?: File | null) => {
    let avatarUrl = up.avatarUrl;
    if (file) {
      avatarUrl = await new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(file);
      });
    }
    const { data, error } = await supabase.from('profiles').update({
      name: up.name, phone: up.phone, address: up.address, neighborhood: up.neighborhood, city: up.city,
      bio: up.bio, about: up.about, price: up.price, website: up.website, specialty: up.specialty,
      reg: up.reg, document: up.document, available_services: up.availableServices,
      health_plan: up.healthPlan, emergency_contact: up.emergencyContact, 
      medical_history: up.medicalHistory, avatar_url: avatarUrl
    }).eq('id', uid).select().single();
    if (error) throw error;
    return mapProfileToUser(data);
  },

  toggleFavorite: async (uid: string, cid: string): Promise<User | null> => {
    const { data: profile } = await supabase.from('profiles').select('favorites').eq('id', uid).single();
    let favs = ensureArray<string>(profile?.favorites);
    favs = favs.includes(cid) ? favs.filter(id => id !== cid) : [...favs, cid];
    const { data, error } = await supabase.from('profiles').update({ favorites: favs }).eq('id', uid).select().single();
    if (error) throw error;
    return mapProfileToUser(data);
  },

  getFavorites: async (uid: string): Promise<Clinic[]> => {
    return await safeExecute(async () => {
      const { data: profile } = await supabase.from('profiles').select('favorites').eq('id', uid).single();
      const favIds = ensureArray<string>(profile?.favorites);
      if (favIds.length === 0) return [];
      const { data, error } = await supabase.from('profiles').select('*').in('id', favIds);
      if (error) throw error;
      return ensureArray<any>(data).map(p => ({
        id: p.id, name: p.name, specialty: p.specialty, location: p.city,
        neighborhood: p.neighborhood, price: p.price, imageUrl: p.avatar_url,
        rating: p.rating, reviewCount: p.review_count, testimonial: p.bio,
        about: p.about, availableServices: p.available_services
      }));
    }, [], "GetFavorites");
  },

  submitReview: async (cid: string, rating: number, comment: string): Promise<void> => {
    const { data: clinic } = await supabase.from('profiles').select('rating, review_count').eq('id', cid).single();
    const newCount = (clinic?.review_count || 0) + 1;
    const newRating = (((clinic?.rating || 5) * (clinic?.review_count || 0)) + rating) / newCount;
    await supabase.from('profiles').update({ rating: newRating, review_count: newCount }).eq('id', cid);
  },

  getAppointments: async (userId: string, role: UserRole): Promise<Appointment[]> => {
    const col = role === 'patient' ? 'patient_id' : 'clinic_id';
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('appointments').select('*, patient:profiles!patient_id(name), clinic:profiles!clinic_id(name)')
          .eq(col, userId).order('date', { ascending: true });
        if (error) throw error;
        return ensureArray<any>(data).map(app => ({
          id: app.id, patientId: app.patient_id, patientName: app.patient?.name || 'Paciente', clinicId: app.clinic_id,
          doctorName: app.doctor_name, date: app.date, status: app.status, type: app.type, meetingUrl: app.meeting_url, roomId: app.room_id || app.id
        }));
    }, [], "GetAppointments");
  },

  createAppointment: async (app: any): Promise<void> => {
    return await safeExecute(async () => {
      const { error } = await supabase.from('appointments').insert({
        patient_id: app.patientId, clinic_id: app.clinicId, doctor_name: app.doctorName,
        date: app.date, status: 'scheduled', type: app.type, notes: app.notes, room_id: app.roomId
      });
      if (error) throw error;
      if (app.date && app.date.includes(' ')) {
        const [date, time] = app.date.split(' ');
        await supabase.from('time_slots').update({ is_booked: true }).eq('clinic_id', app.clinicId).eq('date', date).eq('time', time);
      }
    }, undefined, "ActionCreateAppointment");
  },

  cancelAppointment: async (appId: string): Promise<void> => {
    console.log(`[DB] INICIANDO CANCELAMENTO DIRETO: ${appId}`);

    // 1. TENTA buscar os detalhes primeiro (opcional, mas bom para liberar o slot)
    const { data: app } = await supabase.from('appointments').select('clinic_id, date').eq('id', appId).maybeSingle();

    // 2. ATUALIZAÇÃO NO SUPABASE (Obrigatória)
    const { error: updateError } = await supabase
        .from('appointments')
        .update({ status: 'canceled' })
        .eq('id', appId);

    if (updateError) {
        console.error("[DB] ERRO AO CANCELAR NO SUPABASE:", updateError);
        throw updateError;
    }

    // 3. LIBERAÇÃO DO TIME_SLOT (Para que outros pacientes possam agendar)
    if (app && app.date && app.date.includes(' ')) {
        const [date, time] = app.date.split(' ');
        console.log(`[DB] LIBERANDO SLOT: ${date} ${time}`);
        await supabase.from('time_slots')
            .update({ is_booked: false })
            .eq('clinic_id', app.clinic_id)
            .eq('date', date)
            .eq('time', time);
    }

    console.log("[DB] CANCELAMENTO FINALIZADO COM SUCESSO NO BANCO.");
  },

  getRecords: async (uid: string, role: UserRole): Promise<MedicalRecord[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('medical_records').select('*')
            .or(`patient_id.eq.${uid},professional_id.eq.${uid}`)
            .order('date', { ascending: false });
        if (error) throw error;
        return ensureArray<any>(data).map(r => ({
          id: r.id, patientId: r.patient_id, professionalId: r.professional_id, date: r.date, diagnosis: r.diagnosis,
          prescription: r.prescription, doctorName: r.doctor_name, type: r.type as any, title: r.title, cid: r.cid, days: r.days, fileUrl: r.file_url
        }));
    }, [], "GetRecords");
  },

  getNotifications: async (uid: string): Promise<Notification[]> => {
    try {
        const { data, error } = await supabase.from('notifications').select('*').eq('user_id', uid).order('created_at', { ascending: false }).limit(15);
        if (error) return [];
        return ensureArray<any>(data).map(n => ({ 
            id: n.id, userId: n.user_id, message: n.message, read: n.read, createdAt: n.created_at, link: n.link, type: n.type as any 
        }));
    } catch { return []; }
  },

  getAvailableSlots: async (cid: string): Promise<TimeSlot[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('time_slots').select('*').eq('clinic_id', cid).eq('is_booked', false).order('date');
        if (error) throw error;
        return ensureArray<any>(data).map(s => ({ id: s.id, clinicId: s.clinic_id, date: s.date, time: s.time, isBooked: s.is_booked }));
    }, [], "GetSlots");
  },

  getAllSlotsForClinic: async (cid: string): Promise<TimeSlot[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('time_slots').select('*').eq('clinic_id', cid).order('date').order('time');
        if (error) throw error;
        return ensureArray<any>(data).map(s => ({ id: s.id, clinicId: s.clinic_id, date: s.date, time: s.time, isBooked: s.is_booked }));
    }, [], "GetAllSlots");
  },

  createTimeSlot: async (cid: string, date: string, time: string): Promise<void> => {
    return await safeExecute(async () => {
        await supabase.from('time_slots').insert({ clinic_id: cid, date, time, is_booked: false });
    }, undefined, "ActionCreateTimeSlot");
  },

  createTimeSlotsBatch: async (cid: string, slots: {date: string, time: string}[]): Promise<number> => {
    return await safeExecute(async () => {
        const payload = slots.map(s => ({ clinic_id: cid, date: s.date, time: s.time, is_booked: false }));
        const { data, error } = await supabase.from('time_slots').insert(payload).select();
        if (error) throw error;
        return (data as any[]).length;
    }, 0, "ActionCreateSlotsBatch");
  },

  deleteTimeSlot: async (id: string): Promise<void> => {
    return await safeExecute(async () => {
        await supabase.from('time_slots').delete().eq('id', id);
    }, undefined, "ActionDeleteTimeSlot");
  },

  deleteSlotsByDate: async (cid: string, date: string): Promise<number> => {
    console.log(`[DB] EXCLUINDO SLOTS: Clinic=${cid}, Date=${date}`);
    const { error } = await supabase
        .from('time_slots')
        .delete()
        .eq('clinic_id', cid)
        .eq('date', date);
    if (error) throw error;
    return 1;
  },

  getAppointmentById: async (id: string): Promise<Appointment | null> => {
    const { data, error } = await supabase.from('appointments').select('*').eq('id', id).maybeSingle();
    if (error || !data) return null;
    // Fix: Reference 'data' instead of 'app' for roomId mapping
    return {
        id: data.id, patientId: data.patient_id, clinicId: data.clinic_id,
        doctorName: data.doctor_name, date: data.date, status: data.status, type: data.type, 
        meetingUrl: data.meeting_url, roomId: data.room_id || data.id
    };
  },

  createMedicalRecord: async (rec: Partial<MedicalRecord>, file?: File) => {
    const { error } = await supabase.from('medical_records').insert({
        patient_id: rec.patientId, professional_id: rec.professionalId,
        date: rec.date, diagnosis: rec.diagnosis, prescription: rec.prescription,
        doctor_name: rec.doctorName, type: rec.type, title: rec.title, cid: rec.cid, days: rec.days
    });
    if (error) throw error;
  },

  updateAppointmentStatus: async (id: string, status: string) => {
    await supabase.from('appointments').update({ status }).eq('id', id);
  },

  updateAppointmentLink: async (id: string, url: string) => {
    await supabase.from('appointments').update({ meeting_url: url }).eq('id', id);
  },

  getPendingUsers: async (): Promise<User[]> => {
    const { data, error } = await supabase.from('profiles').select('*').eq('status', 'pending');
    if (error) return [];
    return ensureArray<any>(data).map(mapProfileToUser);
  },

  updateUserStatus: async (uid: string, status: string) => {
    await supabase.from('profiles').update({ status }).eq('id', uid);
  },

  getStats: async () => {
    const { count: u } = await supabase.from('profiles').select('*', { count: 'exact', head: true });
    const { count: a } = await supabase.from('appointments').select('*', { count: 'exact', head: true });
    const { count: p } = await supabase.from('profiles').select('*', { count: 'exact', head: true }).eq('status', 'pending');
    return { users: u || 0, clinics: 0, appointments: a || 0, records: 0, pendingUsers: p || 0 };
  },

  getClinicFinancials: async (cid: string) => {
    return { totalRevenue: 0, chartData: [] };
  },

  getAllClinicsForAdmin: async (): Promise<User[]> => {
    const { data, error } = await supabase.from('profiles').select('*').in('role', ['clinic', 'professional']);
    if (error) return [];
    return ensureArray<any>(data).map(mapProfileToUser);
  },

  getAuditLogs: async (): Promise<AuditLog[]> => {
    return [];
  },

  markNotificationAsRead: async (id: string) => {
    await supabase.from('notifications').update({ read: true }).eq('id', id);
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { User, Appointment } from '../types';
import { mockDb } from '../lib/mockSupabase';
import { Users, Calendar, DollarSign, Activity, Stethoscope, Clock, Video, Trash2, RefreshCw } from 'lucide-react';

interface ClinicDashboardProps {
  user: User;
  onNavigate?: (path: string) => void;
  showToast?: (msg: string, type?: 'success' | 'error') => void;
}

const MetricCard = ({ title, value, icon, color, subtext }: any) => (
  <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex flex-col justify-between h-full">
    <div className="flex justify-between items-start mb-2">
      <div>
        <p className="text-slate-500 text-xs font-bold uppercase tracking-wide">{title}</p>
        <h3 className="text-2xl font-bold text-slate-800 mt-1">{value}</h3>
      </div>
      <div className={`p-3 rounded-xl ${color} text-white shadow-lg shadow-opacity-20`}>
        {icon}
      </div>
    </div>
    {subtext && <p className="text-xs text-slate-400 font-medium">{subtext}</p>}
  </div>
);

const ClinicDashboard: React.FC<ClinicDashboardProps> = ({ user, onNavigate, showToast }) => {
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [financials, setFinancials] = useState({ totalRevenue: 0, chartData: [] as any[] });
  const [loading, setLoading] = useState(true);

  // Memoized loadData para evitar re-criações desnecessárias
  const loadData = useCallback(async () => {
      setLoading(true);
      try {
        console.log("[UI] Recarregando agendamentos...");
        const apps = await mockDb.getAppointments(user.id, user.role);
        const finData = await mockDb.getClinicFinancials(user.id);
        setAppointments(apps);
        setFinancials(finData);
      } catch (e) {
        console.error("[UI] Erro ao carregar dashboard:", e);
      } finally {
        setLoading(false);
      }
  }, [user.id, user.role]);

  // FIX: Depender apenas do ID para evitar loops de re-render do App.tsx
  useEffect(() => {
    loadData();
  }, [user.id, loadData]);

  const handleConsultation = () => {
    if (onNavigate) onNavigate('/consultation');
  };

  const handleCancelAppointment = async (appId: string) => {
      console.log(`[UI] Tentativa de cancelar: ${appId}`);

      const confirmed = window.confirm("Deseja realmente CANCELAR esta consulta? O horário será liberado imediatamente.");
      if (!confirmed) return;

      // 1. ATUALIZAÇÃO OTIMISTA (Imediata)
      const originalApps = [...appointments];
      setAppointments(prev => prev.map(a => a.id === appId ? {...a, status: 'canceled' as any} : a));

      try {
          if (showToast) showToast("Cancelando consulta...", "success");

          // 2. EXECUÇÃO NO BANCO
          await mockDb.cancelAppointment(appId);

          console.log("[UI] Sucesso no cancelamento!");
          if (showToast) showToast("Consulta cancelada com sucesso.");

          // 3. SINCRONIA FINAL
          loadData();
      } catch (e: any) {
          console.error("[UI] Erro crítico no cancelamento:", e);
          // ROLLBACK
          setAppointments(originalApps);
          const errorMsg = e.message || "Erro de permissão ou conexão.";
          if (showToast) showToast(`Erro ao cancelar: ${errorMsg}`, "error");
      }
  };

  const isToday = (dateStr: string) => {
      if (!dateStr) return false;
      const today = new Date().toISOString().split('T')[0];
      return dateStr.startsWith(today);
  };

  const canShowTeleconsultButton = (app: Appointment) => {
    if (app.type !== 'teleconsulta') return false;
    if (!isToday(app.date)) return false;
    if (app.status === 'done' || app.status === 'canceled') return false;
    if (app.clinicId !== user.id) return false;
    return true;
  };

  const formatMoney = (val: number) => {
      return val.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  };

  const getDashboardTitle = () => {
     return user.role === 'professional' ? 'Painel do Profissional' : 'Painel da Clínica';
  };

  return (
    <div className="p-4 space-y-6 animate-fadeIn max-w-7xl mx-auto">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-2 gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">{getDashboardTitle()}</h2>
          <p className="text-slate-500 text-sm">Bem-vindo, {user.name}. Gerencie sua operação.</p>
        </div>
        <div className="flex gap-2">
           <button 
            onClick={loadData}
            className="p-2 text-slate-400 hover:text-teal-600 transition-colors"
            title="Recarregar dados"
          >
            <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
          </button>
           <button 
            onClick={() => onNavigate && onNavigate('/schedule')}
            className="bg-white text-slate-700 border border-slate-200 px-4 py-2 rounded-lg font-bold text-sm hover:bg-slate-50 transition-colors flex items-center gap-2 shadow-sm"
          >
            <Clock size={16} className="text-teal-600"/> Gerenciar Agenda
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <MetricCard 
          title="Pacientes Hoje" 
          value={appointments.filter(a => (a.status === 'confirmed' || a.status === 'scheduled') && isToday(a.date)).length} 
          icon={<Users size={20} />} 
          color="bg-blue-500"
          subtext="Confirmados para hoje" 
        />
        <MetricCard 
          title="Total Agendamentos" 
          value={appointments.length} 
          icon={<Calendar size={20} />} 
          color="bg-teal-500" 
        />
        <MetricCard 
          title="Faturamento Real" 
          value={loading ? '...' : formatMoney(financials.totalRevenue)} 
          icon={<DollarSign size={20} />} 
          color="bg-emerald-500"
          subtext="Consultas finalizadas"
        />
        <MetricCard 
          title="Taxa de Ocupação" 
          value="85%" 
          icon={<Activity size={20} />} 
          color="bg-purple-500" 
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-slate-100 p-6 overflow-hidden">
            <div className="flex justify-between items-center mb-4">
              <h3 className="font-bold text-slate-800">Fila de Atendimento</h3>
              <button 
                  onClick={handleConsultation}
                  className="bg-slate-900 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 hover:bg-slate-800 transition-colors shadow-lg active:scale-95"
              >
                  <Stethoscope size={16} /> Ir para Atendimento
              </button>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-sm text-left">
                  <thead className="text-[10px] text-slate-400 uppercase bg-slate-50 font-black tracking-widest">
                  <tr>
                      <th className="px-4 py-3 rounded-l-lg">Paciente</th>
                      <th className="px-4 py-3">Médico</th>
                      <th className="px-4 py-3">Horário</th>
                      <th className="px-4 py-3">Status</th>
                      <th className="px-4 py-3 rounded-r-lg text-right">Ações</th>
                  </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                  {appointments.length > 0 ? appointments.slice(0, 10).map(app => {
                      const isActive = app.status !== 'canceled' && app.status !== 'done';
                      return (
                          <tr key={app.id} className={`hover:bg-slate-50 transition-colors group ${!isActive ? 'opacity-50' : ''}`}>
                              <td className="px-4 py-4 font-bold text-slate-900">{app.patientName || "Paciente s/ nome"}</td>
                              <td className="px-4 py-4 text-slate-500">{app.doctorName || "---"}</td>
                              <td className="px-4 py-4">
                                  <div className="flex flex-col">
                                      <span className="font-medium text-slate-700">{app.date || "Sem data"}</span>
                                      {app.type === 'teleconsulta' && <span className="text-[9px] font-black text-teal-600 uppercase">Online</span>}
                                  </div>
                              </td>
                              <td className="px-4 py-4">
                                  <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase border ${app.status === 'confirmed' ? 'bg-green-50 text-green-700 border-green-100' : app.status === 'scheduled' ? 'bg-blue-50 text-blue-700 border-blue-100' : app.status === 'canceled' ? 'bg-red-50 text-red-700 border-red-100' : 'bg-slate-50 text-slate-500 border-slate-100'}`}>
                                    {app.status}
                                  </span>
                              </td>
                              <td className="px-4 py-4 text-right">
                                  <div className="flex items-center justify-end gap-2">
                                      {canShowTeleconsultButton(app) && (
                                          <button 
                                              onClick={() => onNavigate && onNavigate(`/teleconsulta/${app.roomId || app.id}`)}
                                              className="text-xs bg-red-600 text-white px-3 py-1.5 rounded-lg font-bold hover:bg-red-700 flex items-center gap-1.5 animate-pulse shadow-md"
                                          >
                                              <Video size={12} /> Entrar
                                          </button>
                                      )}
                                      {isActive && (
                                          <button 
                                              type="button"
                                              onClick={(e) => {
                                                  e.preventDefault();
                                                  e.stopPropagation();
                                                  handleCancelAppointment(app.id);
                                              }}
                                              className="p-3 bg-red-50 text-red-500 hover:bg-red-500 hover:text-white rounded-xl transition-all active:scale-95 flex items-center gap-2 border border-red-100"
                                              title="Cancelar Agendamento"
                                          >
                                              <Trash2 size={18} />
                                              <span className="text-xs font-black uppercase tracking-tight">Cancelar</span>
                                          </button>
                                      )}
                                  </div>
                              </td>
                          </tr>
                      )
                  }) : (
                      <tr>
                      <td colSpan={5} className="text-center py-12 text-slate-400 font-medium">Nenhum agendamento ativo.</td>
                      </tr>
                  )}
                  </tbody>
              </table>
            </div>
          </div>

          <div className="bg-white rounded-xl shadow-sm border border-slate-100 p-6 flex flex-col">
              <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
