import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, Appointment, Clinic } from '../types';
import { mockDb } from '../lib/mockSupabase';
import QuickAccessCard from '../components/QuickAccessCard';
import ServiceCard from '../components/ServiceCard';
import AppointmentForm from '../components/forms/AppointmentForm';
import { Calendar, Clock, Plus, Filter, Clock as ClockIcon, History, Star, Send, X, Video, Stethoscope, TestTube, ClipboardCheck, Settings, Copy, Heart, Trash2 } from 'lucide-react';

interface PatientDashboardProps {
  user: User;
  showToast?: (msg: string, type?: 'success' | 'error') => void;
  onNavigate?: (path: string) => void;
}

const PatientDashboard: React.FC<PatientDashboardProps> = ({ user, showToast, onNavigate }) => {
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [clinics, setClinics] = useState<Clinic[]>([]);
  const [favoriteClinics, setFavoriteClinics] = useState<Clinic[]>([]);
  const [loading, setLoading] = useState(true);

  // TRAVAS DE SEGURANÇA
  const isCancelling = useRef(false);
  const userId = user?.id;

  const refreshData = useCallback(async () => {
    if (!userId) return;
    setLoading(true);
    try {
        const [apps, clin, favs] = await Promise.all([
            mockDb.getAppointments(user.id, user.role),
            mockDb.getClinics(),
            mockDb.getFavorites(user.id)
        ]);
        setAppointments(apps.sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime()));
        setClinics(clin);
        setFavoriteClinics(favs);
    } catch (e) {
        console.error(e);
    } finally {
        setLoading(false);
    }
  }, [userId, user.role]);

  useEffect(() => {
    refreshData();
  }, [userId]); // BLINDAGEM: Apenas ID

  const handleCancelAppointment = async (appId: string) => {
    if (isCancelling.current) return;

    if (!window.confirm("Deseja realmente cancelar este agendamento?")) return;

    console.log(`[UI] Tentativa de cancelar: ${appId}`);
    isCancelling.current = true;

    // OPTIMISTIC UI
    const originalApps = [...appointments];
    setAppointments(prev => prev.map(a => a.id === appId ? { ...a, status: 'canceled' as any } : a));

    try {
      if (showToast) showToast("Cancelando...", "success");
      await mockDb.cancelAppointment(appId);
      if (showToast) showToast("Consulta cancelada.");

      const apps = await mockDb.getAppointments(user.id, user.role);
      setAppointments(apps);
    } catch (e: any) {
      setAppointments(originalApps);
      if (showToast) showToast("Falha ao cancelar.", "error");
    } finally {
      isCancelling.current = false;
    }
  };

  const getStatusLabel = (status: string) => {
     switch(status) {
      case 'confirmed': return 'Confirmado';
      case 'scheduled': return 'Agendado';
      case 'done': return 'Realizado';
      case 'canceled': return 'Cancelado';
      default: return status;
    }
  };

  return (
