import { supabase } from './supabaseClient';
import { Appointment, Clinic, MedicalRecord, User, UserRole, AuditLog, TimeSlot, Notification, ProfileImage } from '../types';

/**
 * MARCLYN PRODUCTION SHIELD v7.0
 * GALLERY & CONSISTENCY ENGINE
 */

const MAX_RETRIES = 1;
const TIMEOUT_MS = 15000;

const activeRequests = new Map<string, Promise<any>>();

const safeExecute = async <T>(operation: () => Promise<T>, fallback: T, label = "Op"): Promise<T> => {
    const isReadOp = label.startsWith("Get") || label.startsWith("Fetch");
    const requestKey = label; 

    if (isReadOp && activeRequests.has(requestKey)) {
        return activeRequests.get(requestKey);
    }

    const execute = async (): Promise<T> => {
        let lastError: any;
        for (let i = 0; i <= MAX_RETRIES; i++) {
            try {
                const controller = new AbortController();
                const timeoutId = setTimeout(() => controller.abort(), TIMEOUT_MS);

                const result = await operation();
                clearTimeout(timeoutId);
                return result;
            } catch (error: any) {
                lastError = error;
                if (error.name === 'AbortError' || error.message?.includes('aborted')) {
                    return fallback;
                }
                if (i < MAX_RETRIES) {
                    await new Promise(r => setTimeout(r, 500 * (i + 1)));
                    continue;
                }
            }
        }
        console.error(`[Shield v7.0] Erro em ${label}:`, lastError.message || lastError);
        throw lastError;
    };

    if (isReadOp) {
        const requestPromise = execute();
        activeRequests.set(requestKey, requestPromise);
        try { return await requestPromise; } finally { activeRequests.delete(requestKey); }
    } else {
        return await execute();
    }
};

const ensureArray = <T>(data: any): T[] => Array.isArray(data) ? data : [];

const mapProfileToUser = (p: any, gallery: any[] = []): User => ({
  id: p?.id || '',
  email: p?.email || '',
  name: p?.name || 'Usuário Marclyn',
  role: (p?.role as UserRole) || 'patient',
  status: p?.status || 'active',
  avatarUrl: p?.avatar_url,
  phone: p?.phone,
  address: p?.address,
  neighborhood: p?.neighborhood,
  city: p?.city || 'Salvador',
  document: p?.document,
  specialty: p?.specialty,
  price: p?.price,
  bio: p?.bio,
  about: p?.about,
  reg: p?.reg,
  operatingHours: p?.operating_hours,
  website: p?.website,
  availableServices: ensureArray(p?.available_services),
  favorites: ensureArray(p?.favorites),
  healthPlan: p?.health_plan,
  medicalHistory: p?.medical_history,
  emergencyContact: p?.emergency_contact,
  yampiUrl: p?.yampi_url,
  gallery: gallery.map(img => ({
    id: img.id,
    profileId: img.profile_id,
    imageUrl: img.image_url,
    position: img.position
  }))
});

export const mockDb = {
  login: async (email?: string): Promise<User | null> => {
    if (!email) return null;
    return await safeExecute(async () => {
        const { data: p, error } = await supabase.from('profiles').select('*').eq('email', email).maybeSingle();
        if (error) throw error;
        if (!p) return null;
        const { data: g } = await supabase.from('profile_images').select('*').eq('profile_id', p.id).order('position');
        return mapProfileToUser(p, g || []);
    }, null, "FetchProfile");
  },

  signIn: async (email: string, password: string): Promise<User | null> => {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
    if (data.user) return await mockDb.login(data.user.email!);
    return null;
  },

  getClinics: async (): Promise<Clinic[]> => {
    return await safeExecute(async () => {
        const { data: profiles, error } = await supabase.from('profiles').select('*').in('role', ['clinic', 'professional']).eq('status', 'active');
        if (error) throw error;
        const ids = profiles.map(p => p.id);
        const { data: images } = await supabase.from('profile_images').select('*').in('profile_id', ids).order('position');

        return ensureArray<any>(profiles).map(p => {
            const gallery = (images || []).filter(img => img.profile_id === p.id).map(img => ({
                id: img.id,
                profileId: img.profile_id,
                imageUrl: img.image_url,
                position: img.position
            }));

            return {
                id: p.id, name: p.name, specialty: p.specialty || 'Especialista', location: p.city || 'Salvador-BA',
                neighborhood: p.neighborhood || p.address || 'Centro', price: p.price || 'A consultar', imageUrl: p.avatar_url,
                rating: p.rating || 5.0, reviewCount: p.review_count || 0, testimonial: p.bio, about: p.about,
                availableServices: ensureArray(p.available_services),
                gallery
            };
        });
    }, [], "GetClinics");
  },

  updateProfile: async (uid: string, up: Partial<User>, file?: File | null) => {
    let avatarUrl = up.avatarUrl;
    if (file) {
      avatarUrl = await new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(file);
      });
    }
    const { data, error } = await supabase.from('profiles').update({
      name: up.name, phone: up.phone, address: up.address, neighborhood: up.neighborhood, city: up.city,
      bio: up.bio, about: up.about, price: up.price, website: up.website, specialty: up.specialty,
      reg: up.reg, document: up.document, available_services: up.availableServices,
      health_plan: up.healthPlan, emergency_contact: up.emergencyContact, 
      medical_history: up.medicalHistory, avatar_url: avatarUrl
    }).eq('id', uid).select().single();
    if (error) throw error;
    return mapProfileToUser(data);
  },

  updateGalleryImage: async (uid: string, position: number, base64Data: string): Promise<void> => {
      // Remover se já existe na posição
      await supabase.from('profile_images').delete().eq('profile_id', uid).eq('position', position);
      // Inserir novo
      const { error } = await supabase.from('profile_images').insert({
          profile_id: uid,
          position: position,
          image_url: base64Data
      });
      if (error) throw error;
  },

  deleteGalleryImage: async (uid: string, position: number): Promise<void> => {
      await supabase.from('profile_images').delete().eq('profile_id', uid).eq('position', position);
  },

  toggleFavorite: async (uid: string, cid: string): Promise<User | null> => {
    const { data: profile } = await supabase.from('profiles').select('favorites').eq('id', uid).single();
    let favs = ensureArray<string>(profile?.favorites);
    favs = favs.includes(cid) ? favs.filter(id => id !== cid) : [...favs, cid];
    const { data, error } = await supabase.from('profiles').update({ favorites: favs }).eq('id', uid).select().single();
    if (error) throw error;
    return mapProfileToUser(data);
  },

  getFavorites: async (uid: string): Promise<Clinic[]> => {
    return await safeExecute(async () => {
      const { data: profile } = await supabase.from('profiles').select('favorites').eq('id', uid).single();
      const favIds = ensureArray<string>(profile?.favorites);
      if (favIds.length === 0) return [];
      const { data, error } = await supabase.from('profiles').select('*').in('id', favIds);
      if (error) throw error;
      return ensureArray<any>(data).map(p => ({
        id: p.id, name: p.name, specialty: p.specialty, location: p.city,
        neighborhood: p.neighborhood, price: p.price, imageUrl: p.avatar_url,
        rating: p.rating, reviewCount: p.review_count, testimonial: p.bio,
        about: p.about, availableServices: p.available_services
      }));
    }, [], "GetFavorites");
  },

  submitReview: async (cid: string, rating: number, comment: string): Promise<void> => {
    const { data: clinic } = await supabase.from('profiles').select('rating, review_count').eq('id', cid).single();
    const newCount = (clinic?.review_count || 0) + 1;
    const newRating = (((clinic?.rating || 5) * (clinic?.review_count || 0)) + rating) / newCount;
    await supabase.from('profiles').update({ rating: newRating, review_count: newCount }).eq('id', cid);
  },

  getAppointments: async (userId: string, role: UserRole): Promise<Appointment[]> => {
    const col = role === 'patient' ? 'patient_id' : 'clinic_id';
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('appointments').select('*, patient:profiles!patient_id(name), clinic:profiles!clinic_id(name)')
          .eq(col, userId).order('date', { ascending: true });
        if (error) throw error;
        return ensureArray<any>(data).map(app => ({
          id: app.id, patientId: app.patient_id, patientName: app.patient?.name || 'Paciente', clinicId: app.clinic_id,
          doctorName: app.doctor_name, date: app.date, status: app.status, type: app.type, meetingUrl: app.meeting_url, roomId: app.room_id || app.id
        }));
    }, [], "GetAppointments");
  },

  createAppointment: async (app: any): Promise<void> => {
    return await safeExecute(async () => {
      const { error } = await supabase.from('appointments').insert({
        patient_id: app.patientId, clinic_id: app.clinicId, doctor_name: app.doctorName,
        date: app.date, status: 'scheduled', type: app.type, notes: app.notes, room_id: app.roomId
      });
      if (error) throw error;
      if (app.date && app.date.includes(' ')) {
        const [date, time] = app.date.split(' ');
        await supabase.from('time_slots').update({ is_booked: true }).eq('clinic_id', app.clinicId).eq('date', date).eq('time', time);
      }
    }, undefined, "ActionCreateAppointment");
  },

  cancelAppointment: async (appId: string): Promise<void> => {
    const { error: updateError } = await supabase.from('appointments').update({ status: 'canceled' }).eq('id', appId);
    if (updateError) throw updateError;
    const { data: app } = await supabase.from('appointments').select('clinic_id, date').eq('id', appId).maybeSingle();
    if (app && app.date && app.date.includes(' ')) {
        const [date, time] = app.date.split(' ');
        await supabase.from('time_slots').update({ is_booked: false }).eq('clinic_id', app.clinic_id).eq('date', date).eq('time', time);
    }
  },

  getRecords: async (uid: string, role: UserRole): Promise<MedicalRecord[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('medical_records').select('*').or(`patient_id.eq.${uid},professional_id.eq.${uid}`).order('date', { ascending: false });
        if (error) throw error;
        return ensureArray<any>(data).map(r => ({
          id: r.id, patientId: r.patient_id, professionalId: r.professional_id, date: r.date, diagnosis: r.diagnosis,
          prescription: r.prescription, doctorName: r.doctor_name, type: r.type as any, title: r.title, cid: r.cid, days: r.days, fileUrl: r.file_url
        }));
    }, [], "GetRecords");
  },

  getNotifications: async (uid: string): Promise<Notification[]> => {
    try {
        const { data, error } = await supabase.from('notifications').select('*').eq('user_id', uid).order('created_at', { ascending: false }).limit(15);
        if (error) return [];
        return ensureArray<any>(data).map(n => ({ 
            id: n.id, userId: n.user_id, message: n.message, read: n.read, createdAt: n.created_at, link: n.link, type: n.type as any 
        }));
    } catch { return []; }
  },

  getAvailableSlots: async (cid: string): Promise<TimeSlot[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('time_slots').select('*').eq('clinic_id', cid).eq('is_booked', false).order('date');
        if (error) throw error;
        return ensureArray<any>(data).map(s => ({ id: s.id, clinicId: s.clinic_id, date: s.date, time: s.time, isBooked: s.is_booked }));
    }, [], "GetSlots");
  },

  getAllSlotsForClinic: async (cid: string): Promise<TimeSlot[]> => {
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('time_slots').select('*').eq('clinic_id', cid).order('date').order('time');
        if (error) throw error;
        return ensureArray<any>(data).map(s => ({ id: s.id, clinicId: s.clinic_id, date: s.date, time: s.time, isBooked: s.is_booked }));
    }, [], "GetAllSlots");
  },

  createTimeSlot: async (cid: string, date: string, time: string): Promise<void> => {
    return await safeExecute(async () => {
        await supabase.from('time_slots').insert({ clinic_id: cid, date, time, is_booked: false });
    }, undefined, "ActionCreateTimeSlot");
  },

  createTimeSlotsBatch: async (cid: string, slots: {date: string, time: string}[]): Promise<number> => {
    return await safeExecute(async () => {
        const payload = slots.map(s => ({ clinic_id: cid, date: s.date, time: s.time, is_booked: false }));
        const { data, error } = await supabase.from('time_slots').insert(payload).select();
        if (error) throw error;
        return (data as any[]).length;
    }, 0, "ActionCreateSlotsBatch");
  },

  deleteTimeSlot: async (id: string): Promise<void> => {
    return await safeExecute(async () => {
        await supabase.from('time_slots').delete().eq('id', id);
    }, undefined, "ActionDeleteTimeSlot");
  },

  deleteSlotsByDate: async (cid: string, date: string): Promise<number> => {
    const { error } = await supabase.from('time_slots').delete().eq('clinic_id', cid).eq('date', date);
    if (error) throw error;
    return 1;
  },

  getAppointmentById: async (id: string): Promise<Appointment | null> => {
    const { data, error } = await supabase.from('appointments').select('*').eq('id', id).maybeSingle();
    if (error || !data) return null;
    return {
        id: data.id, patientId: data.patient_id, clinicId: data.clinic_id,
        doctorName: data.doctor_name, date: data.date, status: data.status, type: data.type, 
        meetingUrl: data.meeting_url, roomId: data.room_id || data.id
    };
  },

  createMedicalRecord: async (rec: Partial<MedicalRecord>, file?: File) => {
    const { error } = await supabase.from('medical_records').insert({
        patient_id: rec.patientId, professional_id: rec.professionalId,
        date: rec.date, diagnosis: rec.diagnosis, prescription: rec.prescription,
        doctor_name: rec.doctorName, type: rec.type, title: rec.title, cid: rec.cid, days: rec.days
    });
    if (error) throw error;
  },

  updateAppointmentStatus: async (id: string, status: string) => {
    await supabase.from('appointments').update({ status }).eq('id', id);
  },

  updateAppointmentLink: async (id: string, url: string) => {
    await supabase.from('appointments').update({ meeting_url: url }).eq('id', id);
  },

  getPendingUsers: async (): Promise<User[]> => {
    const { data, error } = await supabase.from('profiles').select('*').eq('status', 'pending');
    if (error) return [];
    return ensureArray<any>(data).map(p => mapProfileToUser(p));
  },

  updateUserStatus: async (uid: string, status: string) => {
    await supabase.from('profiles').update({ status }).eq('id', uid);
  },

  getStats: async () => {
    const { count: u } = await supabase.from('profiles').select('*', { count: 'exact', head: true });
    const { count: a } = await supabase.from('appointments').select('*', { count: 'exact', head: true });
    const { count: p } = await supabase.from('profiles').select('*', { count: 'exact', head: true }).eq('status', 'pending');
    return { users: u || 0, clinics: 0, appointments: a || 0, records: 0, pendingUsers: p || 0 };
  },

  getClinicFinancials: async (cid: string) => {
    return { totalRevenue: 0, chartData: [] };
  },

  getAllClinicsForAdmin: async (): Promise<User[]> => {
    const { data, error } = await supabase.from('profiles').select('*').in('role', ['clinic', 'professional']);
    if (error) return [];
    return ensureArray<any>(data).map(p => mapProfileToUser(p));
  },

  getAuditLogs: async (): Promise<AuditLog[]> => {
    return [];
  },

  markNotificationAsRead: async (id: string) => {
    await supabase.from('notifications').update({ read: true }).eq('id', id);
  },

  registerUser: async (u: any): Promise<User> => {
    const { data: authData, error: authError } = await supabase.auth.signUp({ email: u.email, password: u.password });
    if (authError) throw authError;
    if (!authData.user) throw new Error("Auth failed");
    const { data: profData, error: profError } = await supabase.from('profiles').insert({
      id: authData.user.id, email: u.email, name: u.name, role: u.role, status: u.role === 'patient' ? 'active' : 'pending',
      document: u.document, phone: u.phone, address: u.address, website: u.website, bio: u.bio, reg: u.reg, specialty: u.specialty,
      available_services: u.availableServices || []
    }).select().single();
    if (profError) throw profError;
    return mapProfileToUser(profData);
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { User, UserRole, Clinic, ProfileImage } from '../../types';
import { Camera, Save, Lock, AlertTriangle, Building, Stethoscope, HeartPulse, Clock, Globe, DollarSign, Video, TestTube, MapPin, Star, Eye, Plus, Trash2, Image as ImageIcon } from 'lucide-react';
import { mockDb } from '../../lib/mockSupabase';
import ServiceCard from '../ServiceCard';

interface ProfileSettingsFormProps {
  user: User;
  onUpdate: (updatedUser: User) => void;
  showToast?: (msg: string, type?: 'success' | 'error') => void;
}

const roleLabels: Record<UserRole, string> = {
  patient: 'Paciente',
  clinic: 'Clínica',
  professional: 'Profissional',
  admin: 'Administrador'
};

const ProfileSettingsForm: React.FC<ProfileSettingsFormProps> = ({ user, onUpdate, showToast }) => {
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const galleryInputRefs = [useRef<HTMLInputElement>(null), useRef<HTMLInputElement>(null), useRef<HTMLInputElement>(null)];

  const [formData, setFormData] = useState<Partial<User>>({
    name: user.name,
    email: user.email,
    phone: user.phone || '',
    address: user.address || '',
    neighborhood: user.neighborhood || '',
    city: user.city || 'Salvador',
    avatarUrl: user.avatarUrl,
    bio: user.bio || '',
    about: user.about || '',
    price: user.price || '',
    operatingHours: user.operatingHours || '',
    website: user.website || '',
    specialty: user.specialty || '',
    reg: user.reg || '', 
    document: user.document || '', 
    availableServices: user.availableServices || [],
    healthPlan: user.healthPlan || '',
    emergencyContact: user.emergencyContact || '',
    medicalHistory: user.medicalHistory || '',
    yampiUrl: user.yampiUrl || '',
    gallery: user.gallery || []
  });

  const [avatarFile, setAvatarFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | undefined>(user.avatarUrl);

  const previewClinic: Clinic = {
    id: 'preview',
    name: formData.name || 'Nome do Profissional',
    specialty: formData.specialty || 'Sua Especialidade',
    location: formData.city || 'Salvador-BA',
    neighborhood: formData.neighborhood || 'Bairro',
    price: formData.price || 'A consultar',
    imageUrl: previewUrl,
    gallery: formData.gallery,
    rating: 5.0,
    reviewCount: 0,
    testimonial: formData.bio || 'Sua biografia curta aparecerá aqui para os pacientes no card de busca.',
    availableServices: formData.availableServices
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setAvatarFile(file);
      setPreviewUrl(URL.createObjectURL(file));
    }
  };

  const handleGalleryUpload = async (position: number, e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const file = e.target.files[0];
          const reader = new FileReader();
          reader.onloadend = async () => {
              const base64 = reader.result as string;
              try {
                  await mockDb.updateGalleryImage(user.id, position, base64);
                  // Atualiza estado local para preview imediato
                  const newGallery = [...(formData.gallery || [])].filter(img => img.position !== position);
                  newGallery.push({ id: `temp-${Date.now()}`, profileId: user.id, imageUrl: base64, position });
                  setFormData(prev => ({ ...prev, gallery: newGallery }));
                  if (showToast) showToast(`Foto ${position} atualizada!`);
              } catch (e) {
                  if (showToast) showToast("Erro ao subir foto.", "error");
              }
          };
          reader.readAsDataURL(file);
      }
  };

  const removeGalleryImage = async (position: number) => {
      try {
          await mockDb.deleteGalleryImage(user.id, position);
          setFormData(prev => ({ 
              ...prev, 
              gallery: (prev.gallery || []).filter(img => img.position !== position) 
          }));
          if (showToast) showToast(`Foto ${position} removida.`);
      } catch (e) {
          if (showToast) showToast("Erro ao remover foto.", "error");
      }
  };

  const handleChange = (field: keyof User, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const toggleService = (service: string) => {
    const current = formData.availableServices || [];
    const updated = current.includes(service) 
      ? current.filter(s => s !== service) 
      : [...current, service];
    handleChange('availableServices', updated);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      const updatedUser = await mockDb.updateProfile(user.id, formData, avatarFile);
      if (updatedUser) {
        onUpdate(updatedUser);
        if (showToast) showToast('Perfil atualizado com sucesso!');
      }
    } catch (error) {
      if (showToast) showToast('Erro ao salvar alterações.', 'error');
    } finally {
      setLoading(false);
    }
  };

  const isPro = user.role === 'clinic' || user.role === 'professional';

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">

      <form onSubmit={handleSubmit} className="lg:col-span-2 bg-white rounded-[2.5rem] shadow-sm border border-slate-200 overflow-hidden animate-fadeIn">
        <div className="bg-slate-900 p-8 flex flex-col md:flex-row items-center gap-6">
          <div className="relative group cursor-pointer" onClick={() => fileInputRef.current?.click()}>
            <div className="w-24 h-24 rounded-full border-4 border-white/20 overflow-hidden shadow-xl bg-slate-800">
               <img 
                 src={previewUrl || `https://ui-avatars.com/api/?name=${user.name}&background=0D9488&color=fff`} 
                 alt="Avatar" 
                 className="w-full h-full object-cover"
               />
            </div>
            <div className="absolute bottom-0 right-0 bg-teal-500 text-white p-2 rounded-full shadow-lg group-hover:bg-teal-600 transition-colors">
              <Camera size={16} />
            </div>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
          </div>
          <div className="text-center md:text-left text-white">
            <h3 className="text-xl font-bold">{formData.name || user.name}</h3>
            <p className="text-slate-400 text-sm uppercase tracking-wider">{roleLabels[user.role]}</p>
            <div className="mt-2 text-xs bg-white/10 px-3 py-1 rounded-full border border-white/5 inline-block">
              {user.status === 'active' ? '● Conta Verificada' : '● Aguardando Aprovação'}
            </div>
          </div>
        </div>

        <div className="p-8 space-y-8">

          {isPro && (
             <section className="space-y-4">
               <h4 className="font-black text-slate-800 text-xs uppercase border-b border-slate-100 pb-2 tracking-widest flex items-center gap-2">
                  <ImageIcon size={14} className="text-teal-600" /> Galeria de Fotos Extras (Máx 3)
               </h4>
               <p className="text-xs text-slate-500 font-medium">Estas fotos aparecem no seu perfil público para pacientes. Use fotos do consultório ou certificados.</p>
               <div className="grid grid-cols-3 gap-4 mt-4">
                  {[1, 2, 3].map((pos) => {
                      const img = formData.gallery?.find(g => g.position === pos);
                      return (
                          <div key={pos} className="aspect-square relative rounded-2xl bg-slate-50 border-2 border-dashed border-slate-200 flex flex-col items-center justify-center overflow-hidden group hover:border-teal-500 transition-all">
                              {img ? (
                                  <>
                                      <img src={img.imageUrl} alt={`Extra ${pos}`} className="w-full h-full object-cover" />
                                      <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                                          <button 
                                              type="button"
                                              onClick={() => galleryInputRefs[pos-1].current?.click()}
                                              className="p-2 bg-white text-slate-700 rounded-full hover:bg-teal-500 hover:text-white transition-all"
                                          >
                                              <Camera size={16} />
                                          </button>
                                          <button 
                                              type="button"
                                              onClick={() => removeGalleryImage(pos)}
                                              className="p-2 bg-red-500 text-white rounded-full hover:bg-red-600 transition-all"
                                          >
                                              <Trash2 size={16} />
                                          </button>
                                      </div>
                                  </>
                              ) : (
                                  <button 
                                      type="button"
                                      onClick={() => galleryInputRefs[pos-1].current?.click()}
                                      className="flex flex-col items-center text-slate-400 hover:text-teal-600 transition-colors"
                                  >
                                      <Plus size={24} />
                                      <span className="text-[10px] font-black uppercase mt-1">Foto {pos}</span>
                                  </button>
                              )}
                              <input 
                                  type="file" 
                                  ref={galleryInputRefs[pos-1]} 
                                  className="hidden" 
                                  accept="image/*"
                                  onChange={(e) => handleGalleryUpload(pos, e)}
                              />
                          </div>
                      );
                  })}
               </div>
             </section>
          )}

          <section className="space-y-4">
            <h4 className="font-black text-slate-800 text-xs uppercase border-b border-slate-100 pb-2 tracking-widest flex items-center gap-2">
               <Building size={14} className="text-teal-600" /> Informações Básicas
            </h4>
            <div className="grid md:grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 tracking-wider">Nome Comercial / Completo</label>
                <input 
                  type="text" required value={formData.name} 
                  onChange={e => handleChange('name', e.target.value)}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-teal-500 outline-none transition-all font-bold text-slate-700"
                />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 tracking-wider">Documento (CPF/CNPJ)</label>
                <input 
                  type="text" value={formData.document} 
                  onChange={e => handleChange('document', e.target.value)}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-teal-500 outline-none transition-all font-bold text-slate-700"
                />
              </div>
            </div>
          </section>

          {isPro && (
            <section className="space-y-4">
              <h4 className="font-black text-slate-800 text-xs uppercase border-b border-slate-100 pb-2 tracking-widest flex items-center gap-2">
                 <Stethoscope size={14} className="text-teal-600" /> Presença Profissional
              </h4>
              <div className="grid md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 tracking-wider">Especialidade Principal</label>
