import { supabase } from './supabaseClient';
import { Appointment, Clinic, MedicalRecord, User, UserRole, UserStatus, AuditLog, TimeSlot, Notification, ProfileImage } from '../types';

/**
 * UTILITY HELPERS
 */

// Fix: Implement safeExecute to handle async database operations with logging
async function safeExecute<T>(fn: () => Promise<T>, fallback: T, context: string): Promise<T> {
  try {
    return await fn();
  } catch (error) {
    console.error(`[mockDb:${context}] Error:`, error);
    return fallback;
  }
}

// Fix: Implement ensureArray to safely handle potential null/single values from API
function ensureArray<T>(data: any): T[] {
  if (!data) return [];
  return Array.isArray(data) ? data : [data];
}

// Fix: Implement mapProfileToUser to transform database records to frontend types
function mapProfileToUser(p: any, gallery: any[] = []): User {
  if (!p) return {} as User;
  return {
    id: p.id,
    name: p.name || '',
    email: p.email || '',
    role: p.role as UserRole,
    status: p.status as UserStatus,
    avatarUrl: p.avatar_url,
    favorites: ensureArray<string>(p.favorites),
    gallery: gallery.map(img => ({
      id: img.id,
      profileId: img.profile_id,
      imageUrl: img.image_url,
      position: img.position
    })),
    document: p.document,
    specialty: p.specialty,
    reg: p.reg,
    phone: p.phone,
    address: p.address,
    neighborhood: p.neighborhood,
    city: p.city,
    healthPlan: p.health_plan,
    emergencyContact: p.emergency_contact,
    medical_history: p.medical_history,
    bio: p.bio,
    about: p.about,
    price: p.price,
    operatingHours: p.operating_hours,
    website: p.website,
    availableServices: ensureArray<string>(p.available_services),
    yampiUrl: p.yampi_url
  };
}

/**
