  submitReview: async (cid: string, rating: number, comment: string): Promise<void> => {
    const { data: clinic } = await supabase.from('profiles').select('rating, review_count').eq('id', cid).single();
    const newCount = (clinic?.review_count || 0) + 1;
    const newRating = (((clinic?.rating || 5) * (clinic?.review_count || 0)) + rating) / newCount;
    await supabase.from('profiles').update({ rating: newRating, review_count: newCount }).eq('id', cid);
  },

  getAppointments: async (userId: string, role: UserRole): Promise<Appointment[]> => {
    const col = role === 'patient' ? 'patient_id' : 'clinic_id';
    return await safeExecute(async () => {
        const { data, error } = await supabase.from('appointments').select('*, patient:profiles!patient_id(name), clinic:profiles!clinic_id(name)')
          .eq(col, userId).order('date', { ascending: true });
        if (error) throw error;
        return ensureArray<any>(data).map(app => ({
          id: app.id, patientId: app.patient_id, patientName: app.patient?.name || 'Paciente', clinicId: app.clinic_id,
          doctorName: app.doctor_name, date: app.date, status: app.status, type: app.type, meetingUrl: app.meeting_url, roomId: app.room_id || app.id
        }));
    }, [], "GetAppointments");
  },

  createAppointment: async (app: any): Promise<void> => {
    return await safeExecute(async () => {
      const { error } = await supabase.from('appointments').insert({
        patient_id: app.patientId, clinic_id: app.clinicId, doctor_name: app.doctorName,
        date: app.date, status: 'scheduled', type: app.type, notes: app.notes, room_id: app.roomId
      });
      if (error) throw error;
      if (app.date && app.date.includes(' ')) {
        const [date, time] = app.date.split(' ');
        await supabase.from('time_slots').update({ is_booked: true }).eq('clinic_id', app.clinicId).eq('date', date).eq('time', time);
