  },

  /**
   * ESCUTA EM TEMPO REAL (CDC)
   * Sem polling. O Supabase avisa o browser quando o banco muda.
   */
  subscribeToNotifications: (uid: string, callback: (payload: any) => void) => {
    return supabase
      .channel(`notifications_user_${uid}`)
      .on(
        'postgres_changes', 
        { 
          event: 'INSERT', 
          schema: 'public', 
          table: 'notifications', 
          filter: `user_id=eq.${uid}` 
        }, 
        (payload) => callback(payload)
      )
      .subscribe();
  },

  login: async (email?: string): Promise<User | null> => {
