                                    'bg-slate-50 text-slate-500 border-slate-100'
                                  }`}>
                                    {app.status}
                                  </span>
                              </td>
                              <td className="py-5 text-right">
                                  <div className="flex items-center justify-end gap-2">
                                      {canShowTeleconsult(app) && (
                                          <button 
                                              onClick={() => onNavigate?.(`/teleconsulta/${app.roomId || app.id}`)}
