      bio: up.bio, about: up.about, price: up.price, website: up.website, specialty: up.specialty,
      reg: up.reg, document: up.document, available_services: up.availableServices,
      health_plan: up.healthPlan, emergency_contact: up.emergencyContact, 
      medical_history: up.medicalHistory, avatar_url: avatarUrl
    }).eq('id', uid).select().single();
    if (error) throw error;
