 * Garante que apenas uma execução ocorra por vez e limpa memória ao desmontar.
 */
export function useSafeAsync<T>(asyncFn: () => Promise<T>, immediate = true) {
  const [data, setData] = useState<T | null>(null);
  const [loading, setLoading] = useState(immediate);
  const [error, setError] = useState<Error | null>(null);

  const isMounted = useRef(true);
  const isExecuting = useRef(false);

  const execute = useCallback(async () => {
    if (isExecuting.current) return;

    isExecuting.current = true;
    if (isMounted.current) setLoading(true);
    if (isMounted.current) setError(null);

    try {
      const result = await asyncFn();
      if (isMounted.current) {
        setData(result);
        setError(null);
      }
      return result;
    } catch (err: any) {
      if (isMounted.current) setError(err);
      throw err;
    } finally {
      if (isMounted.current) {
        setLoading(false);
        isExecuting.current = false;
      }
    }
  }, [asyncFn]);

  useEffect(() => {
    isMounted.current = true;
    if (immediate) {
      execute().catch(() => {});
    }
    return () => {
      isMounted.current = false;
    };
  }, [execute, immediate]);

  return { data, loading, error, execute, setData };
}

import { supabase } from './supabaseClient';
import { Appointment, Clinic, MedicalRecord, RecordType, User, UserRole, UserStatus, AuditLog, TimeSlot, Notification, ProfileImage } from '../types';

/**
 * MARCLYN REQUEST MANAGER (Deduplication Engine)
 * Impede chamadas idênticas simultâneas ao Supabase.
 */
const inflightRequests = new Map<string, Promise<any>>();

async function dedupe<T>(key: string, fn: () => Promise<T>): Promise<T> {
  if (inflightRequests.has(key)) return inflightRequests.get(key);
  const promise = fn().finally(() => inflightRequests.delete(key));
  inflightRequests.set(key, promise);
  return promise;
}

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

async function safeExecute<T>(fn: () => Promise<T>, fallback: T, context: string): Promise<T> {
  try {
    return await fn();
  } catch (error) {
    console.error(`[mockDb:${context}]`, error);
    return fallback;
  }
}

function ensureArray<T>(data: any): T[] {
  if (!data) return [];
  return Array.isArray(data) ? data : [data];
}

function mapProfileToUser(p: any, gallery: any[] = []): User {
  if (!p) return {} as User;
  return {
    id: p.id,
    name: p.name || '',
    email: p.email || '',
    role: p.role as UserRole,
    status: p.status as UserStatus,
    avatarUrl: p.avatar_url,
    favorites: ensureArray<string>(p.favorites),
    gallery: gallery.map(img => ({
      id: img.id,
      profileId: img.profile_id,
      imageUrl: img.image_url,
      position: img.position
    })),
    document: p.document,
    specialty: p.specialty,
    reg: p.reg,
    phone: p.phone,
    address: p.address,
    neighborhood: p.neighborhood,
    city: p.city,
    healthPlan: p.health_plan,
    emergencyContact: p.emergency_contact,
    medicalHistory: p.medical_history,
    bio: p.bio,
    about: p.about,
    price: p.price,
    operatingHours: p.operating_hours,
    website: p.website,
    availableServices: ensureArray<string>(p.available_services),
    yampiUrl: p.yampi_url
  };
}

export const mockDb = {
  getNotifications: async (uid: string): Promise<Notification[]> => {
    return dedupe(`notifs_${uid}`, () => safeExecute(async () => {
        const { data, error } = await supabase.from('notifications').select('*').eq('user_id', uid).order('created_at', { ascending: false }).limit(20);
        if (error) throw error;
        return ensureArray<any>(data).map(n => ({ 
            id: n.id, userId: n.user_id, message: n.message, read: n.read, createdAt: n.created_at, 
            link: n.appointment_id ? `/dashboard` : undefined, type: n.type as any 
        }));
    }, [], "FetchNotifications"));
  },

  markNotificationAsRead: async (id: string) => {
    await supabase.from('notifications').update({ read: true }).eq('id', id);
  },

  subscribeToNotifications: (uid: string, callback: (payload: any) => void) => {
    return supabase.channel(`notifications_user_${uid}`).on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'notifications', filter: `user_id=eq.${uid}` }, (p) => callback(p)).subscribe();
  },

  login: async (email?: string): Promise<User | null> => {
    if (!email) return null;
    return dedupe(`login_${email}`, () => safeExecute(async () => {
        const { data: p, error } = await supabase.from('profiles').select('*').eq('email', email).maybeSingle();
        if (error) throw error;
        if (!p) return null;
        const { data: g } = await supabase.from('profile_images').select('*').eq('profile_id', p.id).order('position');
        return mapProfileToUser(p, g || []);
    }, null, "FetchProfile"));
  },

  signIn: async (email: string, password: string): Promise<User | null> => {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
    if (data.user) return await mockDb.login(data.user.email!);
    return null;
  },

  getClinics: async (): Promise<Clinic[]> => {
    return dedupe('all_clinics', () => safeExecute(async () => {
        const { data: profiles, error } = await supabase.from('profiles').select('*').in('role', ['clinic', 'professional']).eq('status', 'active');
        if (error) throw error;
        const ids = profiles.map(p => p.id);
        const { data: images } = await supabase.from('profile_images').select('*').in('profile_id', ids).order('position');
        return ensureArray<any>(profiles).map(p => {
            const gallery = (images || []).filter(img => img.profile_id === p.id).map(img => ({
                id: img.id, profileId: img.profile_id, imageUrl: img.image_url, position: img.position
            }));
            return {
                id: p.id, name: p.name, specialty: p.specialty || 'Especialista', location: p.city || 'Salvador-BA',
                neighborhood: p.neighborhood || 'Centro', price: p.price || 'A consultar', imageUrl: p.avatar_url,
                rating: p.rating || 5.0, reviewCount: p.review_count || 0, testimonial: p.bio, about: p.about,
                phone: p.phone, availableServices: ensureArray(p.available_services), gallery
            };
        });
    }, [], "GetClinics"));
  },

  getAppointments: async (userId: string, role: UserRole): Promise<Appointment[]> => {
    return dedupe(`apps_${userId}`, () => safeExecute(async () => {
        const col = role === 'patient' ? 'patient_id' : 'clinic_id';
        const { data, error } = await supabase.from('appointments').select('*, patient:profiles!patient_id(name), clinic:profiles!clinic_id(name)').eq(col, userId).order('date', { ascending: true });
        if (error) throw error;
        return ensureArray<any>(data).map(app => ({
          id: app.id, patientId: app.patient_id, patientName: app.patient?.name || 'Paciente', clinicId: app.clinic_id,
          doctorName: app.doctor_name, date: app.date, status: app.status, type: app.type, meetingUrl: app.meeting_url, roomId: app.room_id || app.id
        }));
    }, [], "GetAppointments"));
  },

  cancelAppointment: async (appId: string): Promise<void> => {
    await safeExecute(async () => {
        const { error: updateError } = await supabase.from('appointments').update({ status: 'canceled' }).eq('id', appId);
        if (updateError) throw updateError;
        const { data: app } = await supabase.from('appointments').select('clinic_id, date').eq('id', appId).maybeSingle();
        if (app?.date?.includes(' ')) {
            const [date, time] = app.date.split(' ');
            await supabase.from('time_slots').update({ is_booked: false }).eq('clinic_id', app.clinic_id).eq('date', date).eq('time', time);
        }
    }, undefined, "CancelAppointment");
  },

  getClinicFinancials: async (cid: string) => {
    return dedupe(`fin_${cid}`, () => safeExecute(async () => {
        const { data } = await supabase.from('appointments').select('status').eq('clinic_id', cid).eq('status', 'done');
        const count = (data || []).length;
        return {
            totalRevenue: count * 150,
            chartData: [{ day: 'Seg', value: 400 }, { day: 'Ter', value: 700 }, { day: 'Qua', value: 500 }, { day: 'Qui', value: 900 }, { day: 'Sex', value: 1200 }]
        };
    }, { totalRevenue: 0, chartData: [] }, "GetFinancials"));
  },

  getRecords: async (userId: string, role: UserRole): Promise<MedicalRecord[]> => {
    return dedupe(`records_${userId}`, () => safeExecute(async () => {
        const col = role === 'patient' ? 'patient_id' : 'professional_id';
        const { data, error } = await supabase.from('medical_records').select('*').eq(col, userId).order('date', { ascending: false });
        if (error) throw error;
        return ensureArray<any>(data).map(rec => ({
          id: rec.id, patientId: rec.patient_id, professionalId: rec.professional_id, date: rec.date, diagnosis: rec.diagnosis,
          prescription: rec.prescription, doctorName: rec.doctor_name, type: rec.type as RecordType, fileUrl: rec.file_url,
          cid: rec.cid, days: rec.days, title: rec.title
        }));
    }, [], "GetRecords"));
  },

  createAppointment: async (app: any): Promise<void> => {
    const { error } = await supabase.from('appointments').insert({
        patient_id: app.patientId, clinic_id: app.clinicId, doctor_name: app.doctorName,
        date: app.date, status: 'scheduled', type: app.type, notes: app.notes, room_id: app.roomId
    });
    if (error) throw error;
    if (app.date?.includes(' ')) {
        const [date, time] = app.date.split(' ');
        await supabase.from('time_slots').update({ is_booked: true }).eq('clinic_id', app.clinicId).eq('date', date).eq('time', time);
    }
  },

  getAvailableSlots: async (cid: string): Promise<TimeSlot[]> => {
    return dedupe(`slots_avail_${cid}`, () => safeExecute(async () => {
        const { data } = await supabase.from('time_slots').select('*').eq('clinic_id', cid).eq('is_booked', false).order('date');
        return ensureArray<any>(data).map(s => ({ id: s.id, clinicId: s.clinic_id, date: s.date, time: s.time, isBooked: s.is_booked }));
    }, [], "GetAvailableSlots"));
  },

  getAllSlotsForClinic: async (cid: string): Promise<TimeSlot[]> => {
    return dedupe(`all_slots_${cid}`, () => safeExecute(async () => {
        const { data } = await supabase.from('time_slots').select('*').eq('clinic_id', cid).order('date').order('time');
        return ensureArray<any>(data).map(s => ({ id: s.id, clinicId: s.clinic_id, date: s.date, time: s.time, isBooked: s.is_booked }));
    }, [], "GetAllSlots"));
  },

  createTimeSlot: async (cid: string, date: string, time: string): Promise<void> => {
    await supabase.from('time_slots').insert({ clinic_id: cid, date, time, is_booked: false });
  },

  createTimeSlotsBatch: async (cid: string, slots: {date: string, time: string}[]): Promise<number> => {
    const payload = slots.map(s => ({ clinic_id: cid, date: s.date, time: s.time, is_booked: false }));
    const { data } = await supabase.from('time_slots').insert(payload).select();
    return (data as any[] || []).length;
  },

  deleteTimeSlot: async (id: string): Promise<void> => {
    await supabase.from('time_slots').delete().eq('id', id);
  },

  deleteSlotsByDate: async (cid: string, date: string): Promise<number> => {
    const { error } = await supabase.from('time_slots').delete().eq('clinic_id', cid).eq('date', date);
    if (error) throw error;
    return 1;
  },

  getAppointmentById: async (id: string): Promise<Appointment | null> => {
    const { data } = await supabase.from('appointments').select('*').eq('id', id).maybeSingle();
