    return {
        id: data.id, patientId: data.patient_id, clinicId: data.clinic_id, doctorName: data.doctor_name, 
        date: data.date, status: data.status, type: data.type, meetingUrl: data.meeting_url, roomId: data.room_id || data.id
    };
  },

  createMedicalRecord: async (rec: Partial<MedicalRecord>) => {
    await supabase.from('medical_records').insert({
        patient_id: rec.patientId, professional_id: rec.professionalId, date: rec.date, 
        diagnosis: rec.diagnosis, prescription: rec.prescription, doctor_name: rec.doctorName, 
        type: rec.type, title: rec.title, cid: rec.cid, days: rec.days
    });
  },

  updateAppointmentStatus: async (id: string, status: string) => {
