  },

  updateAppointmentLink: async (id: string, url: string) => {
    await supabase.from('appointments').update({ meeting_url: url }).eq('id', id);
  },

  getPendingUsers: async (): Promise<User[]> => {
    return dedupe('pending_users', () => safeExecute(async () => {
        const { data } = await supabase.from('profiles').select('*').eq('status', 'pending');
        return ensureArray<any>(data).map(p => mapProfileToUser(p));
    }, [], "GetPendingUsers"));
  },

  updateUserStatus: async (uid: string, status: string) => {
    await supabase.from('profiles').update({ status }).eq('id', uid);
  },

  getStats: async () => {
    return dedupe('stats', () => safeExecute(async () => {
        const { count: u } = await supabase.from('profiles').select('*', { count: 'exact', head: true });
        const { count: a } = await supabase.from('appointments').select('*', { count: 'exact', head: true });
        const { count: p } = await supabase.from('profiles').select('*', { count: 'exact', head: true }).eq('status', 'pending');
        return { users: u || 0, clinics: 0, appointments: a || 0, records: 0, pendingUsers: p || 0 };
    }, { users: 0, clinics: 0, appointments: 0, records: 0, pendingUsers: 0 }, "GetStats"));
  },

  getAllClinicsForAdmin: async (): Promise<User[]> => {
    return dedupe('admin_all_clinics', () => safeExecute(async () => {
        const { data } = await supabase.from('profiles').select('*').in('role', ['clinic', 'professional']);
        return ensureArray<any>(data).map(p => mapProfileToUser(p));
    }, [], "GetAllClinicsAdmin"));
  },

  getAuditLogs: async (): Promise<AuditLog[]> => [],

  registerUser: async (u: any): Promise<User> => {
    const { data: authData, error: authError } = await supabase.auth.signUp({ email: u.email, password: u.password });
    if (authError) throw authError;
    if (!authData.user) throw new Error("Auth failed");
    const { data: profData, error: profError } = await supabase.from('profiles').insert({
      id: authData.user.id, email: u.email, name: u.name, role: u.role, status: u.role === 'patient' ? 'active' : 'pending',
      document: u.document, phone: u.phone, address: u.address, website: u.website, bio: u.bio, reg: u.reg, specialty: u.specialty,
      available_services: u.available_services || []
    }).select().single();
    if (profError) throw profError;
    return mapProfileToUser(profData);
  },

  getFavorites: async (uid: string): Promise<Clinic[]> => {
    return dedupe(`favs_${uid}`, () => safeExecute(async () => {
        const { data: profile } = await supabase.from('profiles').select('favorites').eq('id', uid).single();
        const favIds = ensureArray<string>(profile?.favorites);
        if (favIds.length === 0) return [];
        const { data } = await supabase.from('profiles').select('*').in('id', favIds);
        return ensureArray<any>(data).map(p => ({
            id: p.id, name: p.name, specialty: p.specialty, location: p.city, neighborhood: p.neighborhood, 
            price: p.price, imageUrl: p.avatar_url, rating: p.rating, reviewCount: p.review_count, testimonial: p.bio, 
            about: p.about, availableServices: p.available_services
        }));
    }, [], "GetFavorites"));
  },

  submitReview: async (cid: string, rating: number, comment: string): Promise<void> => {
    const { data: clinic } = await supabase.from('profiles').select('rating, review_count').eq('id', cid).single();
    const newCount = (clinic?.review_count || 0) + 1;
    const newRating = (((clinic?.rating || 5) * (clinic?.review_count || 0)) + rating) / newCount;
    await supabase.from('profiles').update({ rating: newRating, review_count: newCount }).eq('id', cid);
  },

  toggleFavorite: async (uid: string, cid: string): Promise<User | null> => {
    const { data: profile } = await supabase.from('profiles').select('favorites').eq('id', uid).single();
    let favs = ensureArray<string>(profile?.favorites);
    favs = favs.includes(cid) ? favs.filter(id => id !== cid) : [...favs, cid];
    const { data, error } = await supabase.from('profiles').update({ favorites: favs }).eq('id', uid).select().single();
    if (error) throw error;
    return mapProfileToUser(data);
  }
};

import React, { useState, useMemo } from 'react';
import { User, Appointment, Clinic } from '../types';
import { mockDb } from '../lib/mockSupabase';
import { useSafeAsync } from '../hooks/useSafeAsync';
import QuickAccessCard from '../components/QuickAccessCard';
import ServiceCard from '../components/ServiceCard';
import AppointmentForm from '../components/forms/AppointmentForm';
import { Calendar, Clock, Plus, Filter, CheckCircle, Star, Send, X, Video, Stethoscope, TestTube, ClipboardCheck, Settings, Link, Copy, Heart, Trash2, History } from 'lucide-react';

const PatientDashboard: React.FC<{ user: User; showToast?: (msg: string, type?: any) => void; onNavigate?: (path: string) => void; }> = ({ user, showToast, onNavigate }) => {
  const [viewPeriod, setViewPeriod] = useState<'upcoming' | 'history'>('upcoming');
  const [statusFilter, setStatusFilter] = useState('all');
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [selectedClinic, setSelectedClinic] = useState<Clinic | null>(null);

  // ENGINE: Carregamento Paralelo Único
  const fetchAllData = React.useCallback(async () => {
    const [apps, clin, favs] = await Promise.all([
      mockDb.getAppointments(user.id, user.role),
      mockDb.getClinics(),
      mockDb.getFavorites(user.id)
    ]);
    return { appointments: apps, clinics: clin, favorites: favs };
  }, [user.id, user.role]);

  const { data, loading, execute: refresh } = useSafeAsync(fetchAllData);

  const appointments = data?.appointments || [];
  const clinics = data?.clinics || [];
  const favorites = data?.favorites || [];

  // LOGIC: Filtros Memoizados (Zero Lag)
  const filteredList = useMemo(() => {
    return appointments.filter(app => {
      const isUpcoming = new Date(app.date.replace(' ', 'T')) >= new Date() || app.date.startsWith(new Date().toISOString().split('T')[0]);
      if (viewPeriod === 'upcoming' && !isUpcoming) return false;
      if (viewPeriod === 'history' && isUpcoming && app.status !== 'done' && app.status !== 'canceled') return false;
      if (statusFilter !== 'all' && app.status !== statusFilter) return false;
      return true;
    }).sort((a,b) => viewPeriod === 'upcoming' ? new Date(a.date).getTime() - new Date(b.date).getTime() : new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [appointments, viewPeriod, statusFilter]);

  const handleCancel = async (id: string) => {
    if (!window.confirm("Cancelar agendamento?")) return;
    try {
      if (showToast) showToast("Cancelando...", "success");
      await mockDb.cancelAppointment(id);
      refresh();
      if (showToast) showToast("Cancelado com sucesso.");
    } catch (e) {
      if (showToast) showToast("Erro ao cancelar.", "error");
    }
  };

  const services = [
    { id: 'teleconsulta', title: 'Teleconsulta', icon: <Video size={20} />, path: '/search?type=teleconsulta' },
    { id: 'presencial', title: 'Consulta', icon: <Stethoscope size={20} />, path: '/search?type=presencial' },
    { id: 'exames', title: 'Exames', icon: <TestTube size={20} />, path: '/search?type=exame' },
    { id: 'resultados', title: 'Resultados', icon: <ClipboardCheck size={20} />, path: '/documents' },
    { id: 'perfil', title: 'Minha Conta', icon: <Settings size={20} />, path: '/profile' },
  ];

  return (
    <div className="p-4 md:p-8 max-w-6xl mx-auto animate-fadeIn">
      {showBookingModal && selectedClinic && (
        <div className="fixed inset-0 z-[70] bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4">
          <AppointmentForm clinics={clinics} patientId={user.id} preSelectedClinicId={selectedClinic.id} onSuccess={() => { setShowBookingModal(false); refresh(); }} onCancel={() => setShowBookingModal(false)} showToast={showToast} />
        </div>
      )}

      <div className="mb-10">
        <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tighter">Olá, {user.name.split(' ')[0]}</h2>
        <p className="text-slate-500 text-sm font-medium">Sua saúde em dia. O que faremos hoje?</p>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-5 gap-3 mb-10">
        {services.map(s => (
          <QuickAccessCard key={s.id} title={s.title} icon={s.icon} onClick={() => onNavigate?.(s.path)} />
        ))}
      </div>

      {favorites.length > 0 && (
        <div className="mb-12">
          <h3 className="text-[10px] font-black text-teal-600 uppercase tracking-widest mb-4 flex items-center gap-2">
            <Heart size={14} className="fill-teal-600" /> Clínicas Favoritas
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {favorites.map(c => <ServiceCard key={c.id} clinic={c} user={user} onBook={(cl) => { setSelectedClinic(cl); setShowBookingModal(true); }} onNavigate={onNavigate!} showToast={showToast} />)}
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row justify-between items-center gap-4 mb-6 border-t border-slate-100 pt-8">
        <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">Meus Agendamentos</h3>
        <div className="flex bg-slate-100 p-1 rounded-xl">
          <button onClick={() => setViewPeriod('upcoming')} className={`px-4 py-2 rounded-lg text-xs font-black uppercase tracking-widest transition-all ${viewPeriod === 'upcoming' ? 'bg-white text-teal-600 shadow-sm' : 'text-slate-500'}`}>Próximos</button>
          <button onClick={() => setViewPeriod('history')} className={`px-4 py-2 rounded-lg text-xs font-black uppercase tracking-widest transition-all ${viewPeriod === 'history' ? 'bg-white text-teal-600 shadow-sm' : 'text-slate-500'}`}>Histórico</button>
        </div>
      </div>

      <div className="space-y-4">
        {loading ? (
          <div className="py-20 text-center text-slate-400 font-black uppercase text-xs animate-pulse">Sincronizando agenda...</div>
        ) : filteredList.length > 0 ? (
          filteredList.map(app => (
            <div key={app.id} className={`bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex flex-col md:flex-row justify-between items-center gap-6 hover:shadow-md transition-all ${app.status === 'canceled' ? 'opacity-40 grayscale' : ''}`}>
              <div className="flex items-center gap-4 w-full">
                <div className="w-14 h-14 bg-teal-50 rounded-2xl flex items-center justify-center text-teal-600 shadow-inner">
                  {app.type === 'teleconsulta' ? <Video size={24}/> : <Calendar size={24}/>}
                </div>
                <div>
                  <h4 className="font-black text-slate-800 uppercase tracking-tight">{app.doctorName || 'Profissional'}</h4>
                  <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{app.date.split(' ').reverse().join(' às ')}</p>
                </div>
              </div>
              <div className="flex items-center gap-3 w-full md:w-auto justify-end">
                <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase border ${app.status === 'confirmed' ? 'bg-green-50 text-green-700 border-green-100' : 'bg-blue-50 text-blue-700 border-blue-100'}`}>{app.status}</span>
                {app.status !== 'canceled' && app.status !== 'done' && (
                  <button onClick={() => handleCancel(app.id)} className="p-2 text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={18}/></button>
                )}
              </div>
            </div>
          ))
        ) : (
          <div className="py-20 text-center bg-white rounded-3xl border border-dashed border-slate-200 text-slate-400 font-bold uppercase text-xs">Nenhum registro encontrado.</div>
        )}
      </div>
    </div>
  );
};

