  const { data: apps, loading, execute: refresh } = useSafeAsync(fetchQueue);

  const handleFinish = async () => {
    if (!selectedApp || !notes.trim()) return showToast?.("Preencha as notas do atendimento.", "error");

    setFinishing(true);
    try {
      await mockDb.createMedicalRecord({
        patientId: selectedApp.patientId, professionalId: user.id, date: new Date().toISOString().split('T')[0],
