FOR UPDATE USING (auth.uid() = id)
WITH CHECK (auth.uid() = id);

-- INSERT/DELETE: Bloqueado para o Frontend (Gerenciado pelo Trigger via SECURITY DEFINER)

-- 4. Função Automatizada de Perfil
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
