    return dedupe(`notifs_${uid}`, () => safeExecute(async () => {
        const { data, error } = await supabase.from('notifications').select('*').eq('user_id', uid).order('created_at', { ascending: false }).limit(20);
        if (error) throw error;
        return ensureArray<any>(data).map(n => ({ 
            id: n.id, userId: n.user_id, message: n.message, read: n.read, createdAt: n.created_at, 
            link: n.appointment_id ? `/dashboard` : undefined, type: n.type as any 
        }));
