      password: u.password,
      options: {
        data: {
          name: u.name,
          role: u.role,
          document: u.document,
          phone: u.phone,
          specialty: u.specialty,
          reg: u.reg
        }
      }
    });

    if (authError) throw authError;
    if (!authData.user) throw new Error("Falha ao criar usuário.");

    // NÃO inserimos manualmente em profiles. O Trigger handle_new_user fará isso.
    // Retornamos um objeto mockado ou aguardamos a propagação
    let profile = null;
    let attempts = 0;
    while (!profile && attempts < 10) {
        await sleep(500);
        profile = await mockDb.login(u.email);
        attempts++;
    }

    if (!profile) throw new Error("Perfil não sincronizado. Verifique se o Trigger foi executado.");
