  },

  deleteGalleryImage: async (uid: string, position: number): Promise<void> => {
    await supabase.from('profile_images').delete().eq('profile_id', uid).eq('position', position);
  },

  updateProfile: async (uid: string, updates: Partial<User>, avatarFile?: File | null): Promise<User | null> => {
    let avatarUrl = updates.avatarUrl;
    if (avatarFile) avatarUrl = URL.createObjectURL(avatarFile);

    const { data, error } = await supabase.from('profiles').update({
      name: updates.name, 
      email: updates.email, 
      phone: updates.phone, 
      address: updates.address,
      neighborhood: updates.neighborhood, 
      city: updates.city, 
      avatar_url: avatarUrl,
      bio: updates.bio, 
      about: updates.about, 
      price: updates.price,
      operating_hours: updates.operatingHours, 
      website: updates.website,
      specialty: updates.specialty, 
      reg: updates.reg, 
      document: updates.document,
      available_services: updates.availableServices, 
      health_plan: updates.healthPlan,
      emergency_contact: updates.emergencyContact, 
      medical_history: updates.medicalHistory,
      yampi_url: updates.yampiUrl, 
      favorites: updates.favorites
    }).eq('id', uid).select().single();

    if (error) throw error;
    const { data: g } = await supabase.from('profile_images').select('*').eq('profile_id', uid).order('position');
    return mapProfileToUser(data, g || []);
  }
};

