    // Cadastro no módulo de autenticação do Supabase
    const { data: authData, error: authError } = await supabase.auth.signUp({ 
      email: u.email, 
      password: u.password,
      options: {
        data: {
          name: u.name,
          role: u.role,
          document: u.document,
          phone: u.phone,
          specialty: u.specialty,
          reg: u.reg
        }
      }
    });

    if (authError) {
        // Tratamento específico para o erro de banco na criação do usuário
        if (authError.message.includes('Database error')) {
            throw new Error("Erro no servidor ao salvar seu perfil. Por favor, tente novamente em instantes.");
        }
        throw authError;
    }

    if (!authData.user) throw new Error("Falha ao criar usuário de autenticação.");

    // Aguarda a propagação do Trigger para criar o perfil na tabela public.profiles
