    dbCache.clear();

    // 1. Criar usuário no Auth
    const { data: authData, error: authError } = await supabase.auth.signUp({ 
      email: u.email, 
      password: u.password,
      options: {
        data: {
          name: u.name,
          role: u.role,
          document: u.document,
          phone: u.phone,
          specialty: u.specialty,
          reg: u.reg
        }
      }
    });

    if (authError) throw authError;
    const userId = authData.user?.id;
    if (!userId) throw new Error("Erro crítico na criação da conta.");

    // 2. Polling agressivo (0.5s)
    let profile = null;
    for (let i = 0; i < 10; i++) {
        await sleep(500);
        profile = await mockDb.login(u.email);
        if (profile) return profile;
    }

    // 3. AUTO-REPARO (Se o gatilho falhar, o frontend cria o perfil)
    console.warn("[REPAIR] Perfil não encontrado, tentando criação manual...");
    const { error: repairError } = await supabase.from('profiles').insert({
        id: userId,
        email: u.email,
        name: u.name,
        role: u.role,
        status: u.role === 'patient' ? 'active' : 'pending',
        document: u.document,
        phone: u.phone,
        specialty: u.specialty,
        reg: u.reg
    });

    if (repairError) throw new Error("Erro ao salvar perfil. Por favor, tente login.");

    // Tenta carregar uma última vez
    profile = await mockDb.login(u.email);
    if (!profile) throw new Error("Conta criada, mas o perfil está em sincronização. Tente fazer login.");

    return profile;
