    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
    if (data.user) return await mockDb.login(data.user.email!);
    return null;
  },

  // CADASTRO RESILIENTE (Retorna null se o perfil demorar, mas a conta for criada)
  registerUser: async (u: any): Promise<User | null> => {
    dbCache.clear();

    // 1. Criar usuário no Auth
    const { data: authData, error: authError } = await supabase.auth.signUp({ 
      email: u.email, 
      password: u.password,
      options: {
        data: {
          name: u.name,
          role: u.role,
          document: u.document,
          phone: u.phone,
          specialty: u.specialty,
          reg: u.reg
        }
      }
    });

    if (authError) throw authError;
    const userId = authData.user?.id;
    if (!userId) throw new Error("Erro crítico na criação da conta.");

    // 2. Polling para encontrar o perfil criado pelo Trigger
    let profile = null;
    for (let i = 0; i < 8; i++) {
        await sleep(600);
        profile = await mockDb.login(u.email);
        if (profile) return profile;
    }

    // 3. AUTO-REPARO SILENCIOSO
    console.warn("[REPAIR] Perfil não encontrado no tempo limite, tentando criação emergencial...");
    try {
        await supabase.from('profiles').insert({
            id: userId,
            email: u.email,
            name: u.name,
            role: u.role,
            status: u.role === 'patient' ? 'active' : 'pending',
            document: u.document,
            phone: u.phone,
            specialty: u.specialty,
            reg: u.reg
        });

        // Tenta carregar uma última vez
        profile = await mockDb.login(u.email);
    } catch (e) {
        console.error("[REPAIR] Falha no auto-reparo manual:", e);
    }

    // Retorna o perfil (pode ser null se tudo falhou, o que acionará o redirecionamento no frontend)
    return profile;
  },

  getClinics: async (): Promise<Clinic[]> => {
    const cached = getCached('clinics');
    if (cached) return cached;

    return dedupe('clinics', async () => {
      const { data: profiles, error } = await supabase.from('profiles').select('*').in('role', ['clinic', 'professional']).eq('status', 'active');
      if (error) throw error;

      const ids = profiles.map(p => p.id);
      const { data: images } = await supabase.from('profile_images').select('*').in('profile_id', ids).order('position');

      const clinics = profiles.map(p => {
          const gallery = (images || []).filter(img => img.profile_id === p.id).map(img => ({
              id: img.id, profileId: img.profile_id, imageUrl: img.image_url, position: img.position
          }));
          return {
              id: p.id, name: p.name, specialty: p.specialty || 'Especialista', location: p.city || 'Salvador-BA',
              neighborhood: p.neighborhood || 'Centro', price: p.price || 'A consultar', imageUrl: p.avatar_url,
              rating: p.rating || 5.0, reviewCount: p.review_count || 0, testimonial: p.bio, about: p.about,
              phone: p.phone, availableServices: p.available_services || [], gallery
          };
      });

      setCache('clinics', clinics);
      return clinics;
    });
  },

  getAppointments: async (userId: string, role: UserRole): Promise<Appointment[]> => {
    const key = `apps_${userId}`;
    const cached = getCached(key);
    if (cached) return cached;

    const col = role === 'patient' ? 'patient_id' : 'clinic_id';
