import React, { useState } from 'react';
import { mockDb } from '../lib/mockSupabase';
import { ArrowLeft, Building, User, Check, AlertCircle, ChevronRight, Globe, Phone, FileText, TrendingUp, Zap, Stethoscope, Video, TestTube } from 'lucide-react';

interface RegisterPartnerProps {
  onNavigate: (path: string) => void;
  showToast: (msg: string, type?: 'success' | 'error') => void;
}

const RegisterPartner: React.FC<RegisterPartnerProps> = ({ onNavigate, showToast }) => {
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [errors, setErrors] = useState<Record<string, string>>({});

  const [formData, setFormData] = useState({
    type: 'clinic', // or 'professional'
    name: '',
    email: '',
    password: '',
    confirmPassword: '',
    document: '', // CNPJ or CPF
    reg: '', // CRM or similar
    specialty: '',
    address: '',
    phone: '',
    website: '',
    bio: '',
    availableServices: [] as string[]
  });

  // Helpers for masks
  const formatDocument = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (formData.type === 'clinic') {
      return numbers.replace(/^(\d{2})(\d{3})(\d{3})(\d{4})(\d{2}).*/, '$1.$2.$3/$4-$5').substring(0, 18);
    } else {
      return numbers.replace(/^(\d{3})(\d{3})(\d{3})(\d{2}).*/, '$1.$2.$3-$4').substring(0, 14);
    }
  };

  const formatPhone = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    return numbers.replace(/^(\d{2})(\d{5})(\d{4}).*/, '($1) $2-$3').substring(0, 15);
  };

  const handleChange = (field: string, value: string) => {
    let formattedValue = value;
    if (field === 'document') formattedValue = formatDocument(value);
    if (field === 'phone') formattedValue = formatPhone(value);

    setFormData(prev => ({ ...prev, [field]: formattedValue }));
    if (errors[field]) {
      setErrors(prev => ({ ...prev, [field]: '' }));
    }
  };

  const toggleService = (service: string) => {
    setFormData(prev => {
        const current = prev.availableServices;
        if (current.includes(service)) {
            return { ...prev, availableServices: current.filter(s => s !== service) };
        } else {
            return { ...prev, availableServices: [...current, service] };
        }
    });
  };

  const validateStep = (currentStep: number): boolean => {
    const newErrors: Record<string, string> = {};
    let isValid = true;

    if (currentStep === 1) {
      if (!formData.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
        newErrors.email = 'Email inválido';
        isValid = false;
      }
      if (!formData.password || formData.password.length < 6) {
        newErrors.password = 'A senha deve ter no mínimo 6 caracteres';
        isValid = false;
      }
      if (formData.password !== formData.confirmPassword) {
        newErrors.confirmPassword = 'As senhas não coincidem';
        isValid = false;
      }
    }

    if (currentStep === 2) {
      if (!formData.name) {
        newErrors.name = formData.type === 'clinic' ? 'Razão Social é obrigatória' : 'Nome Completo é obrigatório';
        isValid = false;
      }

      const docClean = formData.document.replace(/\D/g, '');
      if (formData.type === 'clinic') {
        if (docClean.length !== 14) {
          newErrors.document = 'CNPJ inválido (deve ter 14 números)';
          isValid = false;
        }
      } else {
        if (docClean.length !== 11) {
          newErrors.document = 'CPF inválido (deve ter 11 números)';
          isValid = false;
        }
      }

      if (formData.type === 'professional' && !formData.phone) {
        newErrors.phone = 'Telefone é obrigatório';
        isValid = false;
      }
    }

    if (currentStep === 3) {
       if (!formData.reg) {
         newErrors.reg = 'Registro profissional é obrigatório';
         isValid = false;
       }
       if (!formData.specialty) {
         newErrors.specialty = 'Selecione uma especialidade';
         isValid = false;
       }
       if (!formData.address) {
         newErrors.address = 'Endereço é obrigatório';
         isValid = false;
       }
       if (formData.availableServices.length === 0) {
           showToast("Selecione pelo menos um tipo de atendimento.", "error");
           isValid = false;
       }
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleNext = (e: React.FormEvent) => {
    e.preventDefault();
    if (validateStep(step)) {
      setStep(step + 1);
    } else {
      showToast("Por favor, corrija os erros antes de continuar.", "error");
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validateStep(3)) return;

    setLoading(true);

    try {
      await mockDb.registerUser({
        name: formData.name,
        email: formData.email,
        password: formData.password,
        role: formData.type as any,
        document: formData.document,
        phone: formData.phone,
        address: formData.address,
        website: formData.website,
        bio: formData.bio,
        reg: formData.reg,
        specialty: formData.specialty,
        availableServices: formData.availableServices
      });

      // Mesmo que o polling do perfil retorne null, o Auth foi criado. 
      // Parceiros sempre caem na tela de sucesso "Em Análise".
      setLoading(false);
      setSuccess(true);
      showToast("Cadastro enviado com sucesso!");
    } catch (e: any) {
      const msg = e.message || "Erro ao enviar cadastro.";
      showToast(msg, "error");
      setLoading(false);
    }
  };

  if (success) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-2xl shadow-xl p-8 text-center border border-slate-100 animate-fadeIn">
          <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-6 shadow-sm">
            <Check size={40} strokeWidth={3} />
          </div>
          <h2 className="text-3xl font-bold text-slate-800 mb-3">Recebemos seu pedido!</h2>
          <p className="text-slate-600 mb-8 leading-relaxed">
            Seus dados foram enviados para nossa equipe de compliance. Analisaremos seu <span className="font-bold text-slate-800">{formData.document}</span> em até 24 horas.
          </p>
          <div className="bg-blue-50 border border-blue-100 p-5 rounded-xl mb-8 text-left flex gap-4">
            <AlertCircle className="text-blue-500 flex-shrink-0" size={24} />
            <span className="text-slate-600 text-sm">Fique atento ao seu email <strong>{formData.email}</strong>. Avisaremos assim que seu acesso for liberado.</span>
          </div>
          <button 
            onClick={() => onNavigate('/login')}
            className="w-full bg-slate-900 text-white font-bold py-4 rounded-xl hover:bg-slate-800 transition-colors shadow-lg"
          >
            Voltar para Login
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 py-12 px-4 flex items-center justify-center">
      <div className="max-w-lg w-full bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-100">
        <div className="bg-slate-900 p-6 flex items-center gap-4">
          <button onClick={() => onNavigate('/login')} className="text-slate-400 hover:text-white transition-colors p-1 rounded-full hover:bg-white/10">
            <ArrowLeft size={24} />
          </button>
          <div>
            <h2 className="text-xl font-bold text-white tracking-wide">Parceiro Marclyn</h2>
            <div className="flex items-center gap-2 text-xs font-medium text-slate-400 mt-1 uppercase tracking-wider">
               <span className={step >= 1 ? 'text-white' : ''}>Conta</span>
               <ChevronRight size={12} className={step >= 2 ? 'text-teal-400' : ''}/>
               <span className={step >= 2 ? 'text-teal-400' : ''}>Dados</span>
               <ChevronRight size={12} className={step >= 3 ? 'text-teal-400' : ''}/>
               <span className={step >= 3 ? 'text-teal-400' : ''}>Perfil</span>
            </div>
          </div>
        </div>

        <div className="w-full bg-slate-100 h-1.5">
          <div 
            className="bg-teal-500 h-1.5 transition-all duration-500 ease-out" 
            style={{ width: `${(step / 3) * 100}%` }}
          ></div>
        </div>

        <form className="p-8" onSubmit={step === 3 ? handleSubmit : handleNext}>
          {step === 1 && (
            <div className="space-y-6 animate-slideIn">
              <div className="bg-gradient-to-br from-slate-800 to-slate-900 rounded-xl p-5 shadow-lg border border-slate-700 relative overflow-hidden group mb-2">
                <div className="absolute top-0 right-0 w-32 h-32 bg-teal-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
                <div className="flex flex-col sm:flex-row items-start gap-4 relative z-10">
                  <div className="p-3 bg-teal-500/10 border border-teal-500/20 rounded-lg text-teal-400 shadow-sm flex-shrink-0 mt-1">
                    <TrendingUp size={24} />
                  </div>
                  <div>
                    <h4 className="text-white font-bold text-lg mb-2 leading-tight">
                      Você atua na área da saúde?
                    </h4>
                    <p className="text-slate-300 text-sm leading-relaxed mb-3">
