                )}
              </div>
            </div>
          )}

          {step === 3 && (
            <div className="space-y-6 animate-slideIn">
              <h3 className="font-bold text-2xl text-slate-800">
                 {formData.type === 'clinic' ? 'Detalhes Técnicos' : 'Perfil Profissional'}
