                <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                    <button
                        type="button"
                        onClick={() => toggleService('presencial')}
                        className={`p-3 rounded-xl border-2 flex flex-col items-center gap-2 transition-all ${formData.availableServices.includes('presencial') ? 'border-teal-500 bg-teal-50 text-teal-700' : 'border-slate-100 bg-white text-slate-500 hover:border-slate-300'}`}
                    >
                        <Stethoscope size={24} />
                        <span className="text-xs font-bold">Consulta Presencial</span>
                    </button>
                     <button
                        type="button"
                        onClick={() => toggleService('teleconsulta')}
                        className={`p-3 rounded-xl border-2 flex flex-col items-center gap-2 transition-all ${formData.availableServices.includes('teleconsulta') ? 'border-teal-500 bg-teal-50 text-teal-700' : 'border-slate-100 bg-white text-slate-500 hover:border-slate-300'}`}
                    >
                        <Video size={24} />
                        <span className="text-xs font-bold">Teleconsulta</span>
                    </button>
                     <button
                        type="button"
                        onClick={() => toggleService('exame')}
                        className={`p-3 rounded-xl border-2 flex flex-col items-center gap-2 transition-all ${formData.availableServices.includes('exame') ? 'border-teal-500 bg-teal-50 text-teal-700' : 'border-slate-100 bg-white text-slate-500 hover:border-slate-300'}`}
                    >
                        <TestTube size={24} />
                        <span className="text-xs font-bold">Exames</span>
                    </button>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">
                    {formData.type === 'clinic' ? 'Responsável Técnico (CRM)' : 'Número do Conselho (CRM/CRP)'}
                  </label>
                  <input 
                    type="text"
                    className={`w-full p-3 bg-slate-50 border rounded-lg focus:ring-2 focus:ring-teal-500 outline-none ${errors.reg ? 'border-red-300' : 'border-slate-200'}`}
                    value={formData.reg}
                    onChange={e => handleChange('reg', e.target.value)}
                  />
                  {errors.reg && <span className="text-xs text-red-500 mt-1 block">{errors.reg}</span>}
                </div>

                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Especialidade Principal</label>
                  <select 
                    className={`w-full p-3 bg-slate-50 border rounded-lg focus:ring-2 focus:ring-teal-500 outline-none ${errors.specialty ? 'border-red-300' : 'border-slate-200'}`}
                    value={formData.specialty}
                    onChange={e => handleChange('specialty', e.target.value)}
                  >
                    <option value="">Selecione...</option>
                    <option value="cardiologia">Cardiologia</option>
                    <option value="nutricao">Nutrição</option>
                    <option value="fisioterapia">Fisioterapia</option>
                    <option value="clinica_geral">Clínica Geral</option>
                    <option value="odontologia">Odontologia</option>
                    <option value="psicologia">Psicologia</option>
                    <option value="analises_clinicas">Análises Clínicas (Lab)</option>
                  </select>
                  {errors.specialty && <span className="text-xs text-red-500 mt-1 block">{errors.specialty}</span>}
                </div>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Endereço Principal</label>
                <input 
                  type="text" placeholder="Rua, Número, Bairro, Cidade"
                  className={`w-full p-3 bg-slate-50 border rounded-lg focus:ring-2 focus:ring-teal-500 outline-none ${errors.address ? 'border-red-300' : 'border-slate-200'}`}
                  value={formData.address}
                  onChange={e => handleChange('address', e.target.value)}
                />
                 {errors.address && <span className="text-xs text-red-500 mt-1 block">{errors.address}</span>}
              </div>

              {formData.type === 'professional' && (
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1 flex items-center gap-1">
                    <FileText size={12}/> Mini Bio / Resumo
                  </label>
                  <textarea
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none resize-none"
                    rows={3}
                    placeholder="Conte um pouco sobre sua experiência..."
                    value={formData.bio}
                    onChange={e => handleChange('bio', e.target.value)}
                  />
                </div>
              )}
            </div>
          )}

          <div className="mt-10 flex gap-4">
            {step > 1 && (
              <button 
                type="button" 
                onClick={() => setStep(step - 1)}
                className="px-6 py-3 border border-slate-200 rounded-xl font-bold text-slate-600 hover:bg-slate-50 hover:text-slate-900 transition-colors"
              >
                Voltar
              </button>
            )}
            <button 
              type="submit"
              disabled={loading}
              className="flex-1 bg-teal-600 text-white font-bold py-3 rounded-xl hover:bg-teal-700 shadow-lg hover:shadow-xl hover:shadow-teal-500/20 active:scale-95 transition-all flex items-center justify-center gap-2 disabled:opacity-50"
            >
              {loading ? 'Processando...' : (step === 3 ? 'Finalizar Cadastro' : <>Próximo <ChevronRight size={18}/></>)}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default RegisterPartner;

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import Layout from './components/Layout';
import Home from './pages/Home';
import Login from './pages/Login';
import RegisterPatient from './pages/RegisterPatient';
import RegisterPartner from './pages/RegisterPartner';
import PatientDashboard from './pages/PatientDashboard';
import ClinicDashboard from './pages/ClinicDashboard';
import AdminDashboard from './pages/AdminDashboard';
import AdminApprovals from './pages/AdminApprovals';
import AdminSubscriptions from './pages/AdminSubscriptions';
import AdminLogs from './pages/AdminLogs';
import AdminSystemSettings from './pages/AdminSystemSettings';
import ProfilePage from './pages/ProfilePage';
import DocumentsPage from './pages/DocumentsPage';
import SettingsPage from './pages/SettingsPage';
import ConsultationPage from './pages/ConsultationPage';
import SchedulePage from './pages/SchedulePage';
import SearchPage from './pages/SearchPage';
import TeleconsultationRoom from './pages/TeleconsultationRoom';
import ProfessionalPublicProfile from './pages/ProfessionalPublicProfile';
import { mockDb } from './lib/mockSupabase';
import { supabase } from './lib/supabaseClient';
import { User } from './types';
import { CheckCircle, AlertTriangle, X } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [currentPath, setCurrentPath] = useState(() => window.location.hash.replace('#', '').split('?')[0] || '/');

  const isSyncingRef = useRef(false);

  const showToast = useCallback((message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3500);
  }, []);

  const syncProfile = useCallback(async (email: string) => {
    if (isSyncingRef.current) return;
    isSyncingRef.current = true;
    try {
      const profile = await mockDb.login(email);
      setUser(profile);
    } catch (e) {
      console.error("[AuthSync] Fail:", e);
    } finally {
      isSyncingRef.current = false;
      setAuthLoading(false);
    }
  }, []);

  useEffect(() => {
    const handleHash = () => setCurrentPath(window.location.hash.replace('#', '').split('?')[0] || '/');
    window.addEventListener('hashchange', handleHash);

    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user?.email) syncProfile(session.user.email);
      else setAuthLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, session) => {
      if (event === 'SIGNED_IN' && session?.user?.email) syncProfile(session.user.email);
      if (event === 'SIGNED_OUT') { setUser(null); setAuthLoading(false); window.location.hash = '/'; }
    });

    return () => {
      window.removeEventListener('hashchange', handleHash);
      subscription.unsubscribe();
    };
  }, [syncProfile]);

  const navigate = useCallback((path: string) => window.location.hash = path, []);
  const commonProps = useMemo(() => ({ onNavigate: navigate, showToast }), [navigate, showToast]);

  if (authLoading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white">
      <div className="w-16 h-16 border-4 border-teal-500/20 border-t-teal-500 rounded-full animate-spin mb-4"></div>
      <p className="text-teal-400 font-black uppercase text-[10px] tracking-widest animate-pulse">Sincronizando Marclyn Pro...</p>
    </div>
  );

  const renderContent = () => {
    if (currentPath.startsWith('/teleconsulta/')) return user ? <TeleconsultationRoom user={user} {...commonProps} /> : <Login onLogin={setUser} {...commonProps} />;
    if (currentPath.startsWith('/professional/')) return <ProfessionalPublicProfile user={user} {...commonProps} />;

    switch (currentPath) {
      case '/': return <Home user={user} {...commonProps} />;
      case '/search': return <SearchPage user={user} {...commonProps} />;
      case '/login': return <Login onLogin={setUser} {...commonProps} />;
      case '/register-patient': return <RegisterPatient onLogin={setUser} {...commonProps} />;
      case '/register-partner': return <RegisterPartner {...commonProps} />;
      case '/dashboard':
        if (!user) return <Login onLogin={setUser} {...commonProps} />;
        if (user.role === 'admin') return <AdminDashboard user={user} onNavigate={navigate} />;
        if (user.role === 'clinic' || user.role === 'professional') return <ClinicDashboard user={user} onNavigate={navigate} showToast={showToast} />;
        return <PatientDashboard user={user} showToast={showToast} onNavigate={navigate} />;

      // ROTAS ADMINISTRATIVAS CORRIGIDAS
      case '/admin/approvals': 
        return user?.role === 'admin' ? <AdminApprovals onBack={() => navigate('/dashboard')} showToast={showToast} /> : <Home user={user} {...commonProps} />;
      case '/admin/subscriptions':
        return user?.role === 'admin' ? <AdminSubscriptions onNavigate={navigate} showToast={showToast} /> : <Home user={user} {...commonProps} />;
      case '/admin/logs':
        return user?.role === 'admin' ? <AdminLogs onNavigate={navigate} /> : <Home user={user} {...commonProps} />;
      case '/admin/settings':
        return user?.role === 'admin' ? <AdminSystemSettings onNavigate={navigate} showToast={showToast} /> : <Home user={user} {...commonProps} />;

      case '/profile': return user ? <ProfilePage user={user} {...commonProps} /> : <Login onLogin={setUser} {...commonProps} />;
      case '/documents': return user ? <DocumentsPage user={user} onNavigate={navigate} /> : <Login onLogin={setUser} {...commonProps} />;
      case '/consultation': return (user?.role === 'clinic' || user?.role === 'professional') ? <ConsultationPage user={user} {...commonProps} /> : <Home user={user} {...commonProps} />;
      case '/schedule': return (user?.role === 'clinic' || user?.role === 'professional') ? <SchedulePage user={user} {...commonProps} /> : <Home user={user} {...commonProps} />;
      default: return <Home user={user} {...commonProps} />;
    }
  };

  return (
    <Layout user={user} onLogout={() => supabase.auth.signOut()} onNavigate={navigate}>
      {renderContent()}
      {toast && (
        <div className={`fixed top-6 right-6 z-[110] p-4 rounded-xl shadow-2xl flex items-center gap-3 animate-slideIn ${toast.type === 'success' ? 'bg-slate-900 text-white' : 'bg-red-600 text-white'}`}>
          {toast.type === 'success' ? <CheckCircle size={24} className="text-teal-400" /> : <AlertTriangle size={24} />}
          <div className="flex-1"><p className="font-bold text-sm uppercase">{toast.type === 'success' ? 'Sucesso' : 'Erro'}</p><p className="text-xs opacity-90">{toast.message}</p></div>
          <button onClick={() => setToast(null)}><X size={16} /></button>
        </div>
      )}
    </Layout>
  );
};

