import { supabase } from './supabaseClient';
import { Appointment, Clinic, MedicalRecord, RecordType, User, UserRole, UserStatus, AuditLog, TimeSlot, Notification, ProfileImage } from '../types';

// CACHE DE MEMÓRIA
const dbCache = new Map<string, { data: any, timestamp: number }>();
const CACHE_TTL = 5000; 

const getCached = (key: string) => {
    const item = dbCache.get(key);
    if (item && (Date.now() - item.timestamp < CACHE_TTL)) return item.data;
    return null;
};

const setCache = (key: string, data: any) => {
    dbCache.set(key, { data, timestamp: Date.now() });
};

const inflightRequests = new Map<string, Promise<any>>();

async function dedupe<T>(key: string, fn: () => Promise<T>): Promise<T> {
  if (inflightRequests.has(key)) return inflightRequests.get(key);
  const promise = fn().finally(() => inflightRequests.delete(key));
  inflightRequests.set(key, promise);
  return promise;
}

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

function mapProfileToUser(p: any, gallery: any[] = []): User {
  if (!p) return {} as User;
  return {
    id: p.id,
    name: p.name || '',
    email: p.email || '',
    role: p.role as UserRole,
    status: p.status as UserStatus,
    avatarUrl: p.avatar_url,
    favorites: p.favorites || [],
    gallery: gallery.map(img => ({
      id: img.id, profileId: img.profile_id, imageUrl: img.image_url, position: img.position
    })),
    document: p.document,
    specialty: p.specialty,
    reg: p.reg,
    phone: p.phone,
    address: p.address,
    neighborhood: p.neighborhood,
    city: p.city,
    healthPlan: p.health_plan,
    emergencyContact: p.emergency_contact,
    medicalHistory: p.medical_history,
    bio: p.bio,
    about: p.about,
    price: p.price,
    operatingHours: p.operating_hours,
    website: p.website,
    availableServices: p.available_services || [],
    yampiUrl: p.yampi_url
  };
}

export const mockDb = {
  login: async (email?: string): Promise<User | null> => {
    if (!email) return null;
    const cacheKey = `login_${email}`;
    const cached = getCached(cacheKey);
    if (cached) return cached;

    return dedupe(cacheKey, async () => {
      try {
        const { data: p, error } = await supabase.from('profiles').select('*').eq('email', email).maybeSingle();
        if (error) {
            console.error("[DB ERROR] Login:", error);
            throw error;
        }
        if (!p) return null;

        const { data: g } = await supabase.from('profile_images').select('*').eq('profile_id', p.id).order('position');
        const user = mapProfileToUser(p, g || []);
        setCache(cacheKey, user);
        return user;
      } catch (e) {
          dbCache.delete(cacheKey);
          throw e;
      }
    });
  },

  signIn: async (email: string, password: string): Promise<User | null> => {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
    if (data.user) return await mockDb.login(data.user.email!);
    return null;
  },

  registerUser: async (u: any): Promise<User | null> => {
    dbCache.clear();
    const { data: authData, error: authError } = await supabase.auth.signUp({ 
      email: u.email, 
      password: u.password,
      options: {
        data: {
          name: u.name,
          role: u.role,
          document: u.document,
          phone: u.phone,
          specialty: u.specialty,
          reg: u.reg
        }
      }
    });

    if (authError) throw authError;
    const userId = authData.user?.id;
    if (!userId) throw new Error("Erro crítico na criação da conta.");

    let profile = null;
    for (let i = 0; i < 10; i++) {
        await sleep(500);
        profile = await mockDb.login(u.email);
        if (profile) return profile;
    }

    const { error: repairError } = await supabase.from('profiles').insert({
        id: userId,
        email: u.email,
        name: u.name,
        role: u.role,
        status: u.role === 'patient' ? 'active' : 'pending',
        document: u.document,
        phone: u.phone,
        specialty: u.specialty,
        reg: u.reg,
        address: u.address,
        available_services: u.availableServices || []
    });

    if (repairError && repairError.code !== '23505') throw repairError;
    return await mockDb.login(u.email);
  },

  getStats: async () => {
      dbCache.clear();
      const { count: users } = await supabase.from('profiles').select('*', { count: 'exact', head: true });
      const { count: clinics } = await supabase.from('profiles').select('*', { count: 'exact', head: true }).in('role', ['clinic', 'professional']);
      const { count: appointments } = await supabase.from('appointments').select('*', { count: 'exact', head: true });

      const { data: pendings } = await supabase.from('profiles').select('id').eq('status', 'pending');
      const pendingCount = pendings?.length || 0;

      return { 
          users: users || 0, 
          clinics: clinics || 0, 
          appointments: appointments || 0, 
          records: 0, 
          pendingUsers: pendingCount 
      };
  },

  getPendingUsers: async (): Promise<User[]> => {
    const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('status', 'pending')
        .order('created_at', { ascending: false });

    if (error) {
        console.error("[DB ERROR] getPendingUsers:", error);
        throw error;
    }
    return (data || []).map(p => mapProfileToUser(p));
  },

  updateUserStatus: async (userId: string, status: string) => {
    const { error } = await supabase.from('profiles').update({ status }).eq('id', userId);
    if (error) throw error;
    dbCache.clear();
  },

  getClinics: async (): Promise<Clinic[]> => {
    const cached = getCached('clinics');
    if (cached) return cached;

    return dedupe('clinics', async () => {
      const { data: profiles, error } = await supabase.from('profiles').select('*').in('role', ['clinic', 'professional']).eq('status', 'active');
      if (error) throw error;

      const ids = profiles.map(p => p.id);
