import { useState, useEffect } from 'react';
import { mockDb } from '../lib/mockSupabase';
import { ArrowLeft, CreditCard, CheckCircle, AlertCircle, Clock, Search, MoreHorizontal, Edit, Ban, DollarSign, ChevronUp, ChevronDown, Trash2, RefreshCw } from 'lucide-react';

interface AdminSubscriptionsProps {
  onNavigate: (path: string) => void;
  showToast?: (msg: string, type?: 'success' | 'error') => void;
}

interface Subscription {
  id: string;
  clinicId: string;
  clinicName: string;
  plan: 'Básico' | 'Profissional' | 'Enterprise';
  status: 'active' | 'overdue' | 'canceled';
  amount: string;
  nextBilling: string;
}

const AdminSubscriptions: React.FC<AdminSubscriptionsProps> = ({ onNavigate, showToast }) => {
  const [subscriptions, setSubscriptions] = useState<Subscription[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);

  const loadData = async () => {
    setLoading(true);
    try {
        const users = await mockDb.getAllClinicsForAdmin();

        const mappedSubs: Subscription[] = users.map((user) => {
            // MAPEAMENTO REAL:
            // active -> active (Pago)
            // blocked -> overdue (Atrasado)
            // rejected -> canceled (Cancelado)
            let subStatus: Subscription['status'] = 'active';

            if (user.status === 'blocked') {
                subStatus = 'overdue';
            } else if (user.status === 'rejected') {
                subStatus = 'canceled';
            }

            // Determinação de plano baseada no ID para manter consistência visual
            const idNum = user.id.charCodeAt(0) + user.id.charCodeAt(user.id.length - 1);
            const isEnterprise = idNum % 3 === 0;
            const isProfessional = idNum % 2 === 0;

            return {
                id: `sub_${user.id}`,
                clinicId: user.id,
                clinicName: user.name,
                plan: isEnterprise ? 'Enterprise' : isProfessional ? 'Profissional' : 'Básico',
                status: subStatus,
                amount: isEnterprise ? 'R$ 499,00' : isProfessional ? 'R$ 299,00' : 'R$ 149,00',
                nextBilling: '25/12/2023'
            };
        });

        setSubscriptions(mappedSubs);
    } catch (e) {
        if (showToast) showToast("Erro ao carregar assinaturas.", "error");
    } finally {
        setLoading(false);
